const book: BibleBook = {
  id: 'matthew',
  name: 'Mateus',
  englishName: 'Matthew',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'The book of the genealogy of Jesus Christ, the son of David, the son of Abraham.', pt: 'Livro da genealogia de Jesus Cristo, filho de Davi, filho de Abraão.' },
      { v: 2, en: 'Abraham became the father of Isaac. Isaac became the father of Jacob. Jacob became the father of Judah and his brothers.', pt: 'A Abraão nasceu Isaque; a Isaque nasceu Jacó; a Jacó nasceram Judá e seus irmãos;' },
      { v: 3, en: 'Judah became the father of Perez and Zerah by Tamar. Perez became the father of Hezron. Hezron became the father of Ram.', pt: 'a Judá nasceram, de Tamar, Farés e Zará; a Farés nasceu Esrom; a Esrom nasceu Arão;' },
      { v: 4, en: 'Ram became the father of Amminadab. Amminadab became the father of Nahshon. Nahshon became the father of Salmon.', pt: 'a Arão nasceu Aminadabe; a Aminadabe nasceu Nasom; a Nasom nasceu Salmom;' },
      { v: 5, en: 'Salmon became the father of Boaz by Rahab. Boaz became the father of Obed by Ruth. Obed became the father of Jesse.', pt: 'a Salmom nasceu, de Raabe, Booz; a Booz nasceu, de Rute, Obede; a Obede nasceu Jessé;' },
      { v: 6, en: 'Jesse became the father of King David. David became the father of Solomon by her who had been Uriah’s wife.', pt: 'e a Jessé nasceu o rei Davi. A Davi nasceu Salomão da que fora mulher de Urias;' },
      { v: 7, en: 'Solomon became the father of Rehoboam. Rehoboam became the father of Abijah. Abijah became the father of Asa.', pt: 'a Salomão nasceu Roboão; a Roboão nasceu Abias; a Abias nasceu Asafe;' },
      { v: 8, en: 'Asa became the father of Jehoshaphat. Jehoshaphat became the father of Joram. Joram became the father of Uzziah.', pt: 'a Asafe nasceu Josafá; a Josafá nasceu Jorão; a Jorão nasceu Ozias;' },
      { v: 9, en: 'Uzziah became the father of Jotham. Jotham became the father of Ahaz. Ahaz became the father of Hezekiah.', pt: 'a Ozias nasceu Joatão; a Joatão nasceu Acaz; a Acaz nasceu Ezequias;' },
      { v: 10, en: 'Hezekiah became the father of Manasseh. Manasseh became the father of Amon. Amon became the father of Josiah.', pt: 'a Ezequias nasceu Manassés; a Manassés nasceu Amom; a Amom nasceu Josias;' },
      { v: 11, en: 'Josiah became the father of Jechoniah and his brothers, at the time of the exile to Babylon.', pt: 'a Josias nasceram Jeconias e seus irmãos, no tempo da deportação para Babilônia.' },
      { v: 12, en: 'After the exile to Babylon, Jechoniah became the father of Shealtiel. Shealtiel became the father of Zerubbabel.', pt: 'Depois da deportação para Babilônia nasceu a Jeconias, Salatiel; a Salatiel nasceu Zorobabel;' },
      { v: 13, en: 'Zerubbabel became the father of Abiud. Abiud became the father of Eliakim. Eliakim became the father of Azor.', pt: 'a Zorobabel nasceu Abiúde; a Abiúde nasceu Eliaquim; a Eliaquim nasceu Azor;' },
      { v: 14, en: 'Azor became the father of Zadok. Zadok became the father of Achim. Achim became the father of Eliud.', pt: 'a Azor nasceu Sadoque; a Sadoque nasceu Aquim; a Aquim nasceu Eliúde;' },
      { v: 15, en: 'Eliud became the father of Eleazar. Eleazar became the father of Matthan. Matthan became the father of Jacob.', pt: 'a Eliúde nasceu Eleazar; a Eleazar nasceu Matã; a Matã nasceu Jacó;' },
      { v: 16, en: 'Jacob became the father of Joseph, the husband of Mary, from whom was born Jesus, who is called Christ.', pt: 'e a Jacó nasceu José, marido de Maria, da qual nasceu JESUS, que se chama Cristo.' },
      { v: 17, en: 'So all the generations from Abraham to David are fourteen generations; from David to the exile to Babylon fourteen generations; and from the carrying away to Babylon to the Christ, fourteen generations.', pt: 'De sorte que todas as gerações, desde Abraão até Davi, são catorze gerações; e desde Davi até a deportação para Babilônia, catorze gerações; e desde a deportação para Babilônia até o Cristo, catorze gerações.' },
      { v: 18, en: 'Now the birth of Jesus Christ was like this: After his mother, Mary, was engaged to Joseph, before they came together, she was found pregnant by the Holy Spirit.', pt: 'Ora, o nascimento de Jesus Cristo foi assim: Estando Maria, sua mãe, desposada com José, antes de se ajuntarem, ela se achou ter concebido do Espírito Santo.' },
      { v: 19, en: 'Joseph, her husband, being a righteous man, and not willing to make her a public example, intended to put her away secretly.', pt: 'E como José, seu esposo, era justo, e não a queria infamar, intentou deixá-la secretamente.' },
      { v: 20, en: 'But when he thought about these things, behold, an angel of the Lord appeared to him in a dream, saying, “Joseph, son of David, don’t be afraid to take to yourself Mary, your wife, for that which is conceived in her is of the Holy Spirit.', pt: 'E, projetando ele isso, eis que em sonho lhe apareceu um anjo do Senhor, dizendo: José, filho de Davi, não temas receber a Maria, tua mulher, pois o que nela se gerou é do Espírito Santo;' },
      { v: 21, en: 'She shall give birth to a son. You shall call his name Jesus, for it is he who shall save his people from their sins.”', pt: 'ela dará à luz um filho, a quem chamarás JESUS; porque ele salvará o seu povo dos seus pecados.' },
      { v: 22, en: 'Now all this has happened, that it might be fulfilled which was spoken by the Lord through the prophet, saying,', pt: 'Ora, tudo isso aconteceu para que se cumprisse o que fora dito da parte do Senhor pelo profeta:' },
      { v: 23, en: '“Behold, the virgin shall be with child, and shall give birth to a son. They shall call his name Immanuel”; which is, being interpreted, “God with us.”', pt: 'Eis que a virgem conceberá e dará à luz um filho, o qual será chamado EMANUEL, que traduzido é: Deus conosco.' },
      { v: 24, en: 'Joseph arose from his sleep, and did as the angel of the Lord commanded him, and took his wife to himself;', pt: 'E José, tendo despertado do sono, fez como o anjo do Senhor lhe ordenara, e recebeu sua mulher;' },
      { v: 25, en: 'and didn’t know her sexually until she had given birth to her firstborn son. He named him Jesus.', pt: 'e não a conheceu enquanto ela não deu à luz um filho; e pôs-lhe o nome de JESUS.' },
    ],
    2: [
      { v: 1, en: 'Now when Jesus was born in Bethlehem of Judea in the days of King Herod, behold, wise men from the east came to Jerusalem, saying,', pt: 'Tendo, pois, nascido Jesus em Belém da Judéia, no tempo do rei Herodes, eis que vieram do oriente a Jerusalém uns magos que perguntavam:' },
      { v: 2, en: '“Where is he who is born King of the Jews? For we saw his star in the east, and have come to worship him.”', pt: 'Onde está aquele que é nascido rei dos judeus? pois do oriente vimos a sua estrela e viemos adorá-lo.' },
      { v: 3, en: 'When King Herod heard it, he was troubled, and all Jerusalem with him.', pt: 'O rei Herodes, ouvindo isso, perturbou-se, e com ele toda a Jerusalém;' },
      { v: 4, en: 'Gathering together all the chief priests and scribes of the people, he asked them where the Christ would be born.', pt: 'e, reunindo todos os principais sacerdotes e os escribas do povo, perguntava-lhes onde havia de nascer o Cristo.' },
      { v: 5, en: 'They said to him, “In Bethlehem of Judea, for this is written through the prophet,', pt: 'Responderam-lhe eles: Em Belém da Judéia; pois assim está escrito pelo profeta:' },
      { v: 6, en: '‘You Bethlehem, land of Judah, are in no way least among the princes of Judah: for out of you shall come a governor, who shall shepherd my people, Israel.’”', pt: 'E tu, Belém, terra de Judá, de modo nenhum és a menor entre as principais cidades de Judá; porque de ti sairá o Guia que há de apascentar o meu povo de Israel.' },
      { v: 7, en: 'Then Herod secretly called the wise men, and learned from them exactly what time the star appeared.', pt: 'Então Herodes chamou secretamente os magos, e deles inquiriu com precisão acerca do tempo em que a estrela aparecera;' },
      { v: 8, en: 'He sent them to Bethlehem, and said, “Go and search diligently for the young child. When you have found him, bring me word, so that I also may come and worship him.”', pt: 'e enviando-os a Belém, disse-lhes: Ide, e perguntai diligentemente pelo menino; e, quando o achardes, participai-mo, para que também eu vá e o adore.' },
      { v: 9, en: 'They, having heard the king, went their way; and behold, the star, which they saw in the east, went before them, until it came and stood over where the young child was.', pt: 'Tendo eles, pois, ouvido o rei, partiram; e eis que a estrela que tinham visto quando no oriente ia adiante deles, até que, chegando, se deteve sobre o lugar onde estava o menino.' },
      { v: 10, en: 'When they saw the star, they rejoiced with exceedingly great joy.', pt: 'Ao verem eles a estrela, regozijaram-se com grande alegria.' },
      { v: 11, en: 'They came into the house and saw the young child with Mary, his mother, and they fell down and worshiped him. Opening their treasures, they offered to him gifts: gold, frankincense, and myrrh.', pt: 'E entrando na casa, viram o menino com Maria sua mãe e, prostrando-se, o adoraram; e abrindo os seus tesouros, ofertaram-lhe dádivas: ouro incenso e mirra.' },
      { v: 12, en: 'Being warned in a dream that they shouldn’t return to Herod, they went back to their own country another way.', pt: 'Ora, sendo por divina revelação avisados em sonhos para não voltarem a Herodes, regressaram à sua terra por outro caminho.' },
      { v: 13, en: 'Now when they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying, “Arise and take the young child and his mother, and flee into Egypt, and stay there until I tell you, for Herod will seek the young child to destroy him.”', pt: 'E, havendo eles se retirado, eis que um anjo do Senhor apareceu a José em sonho, dizendo: Levanta-te, toma o menino e sua mãe, foge para o Egito, e ali fica até que eu te fale; porque Herodes há de procurar o menino para o matar.' },
      { v: 14, en: 'He arose and took the young child and his mother by night, and departed into Egypt,', pt: 'Levantou-se, pois, tomou de noite o menino e sua mãe, e partiu para o Egito.' },
      { v: 15, en: 'and was there until the death of Herod; that it might be fulfilled which was spoken by the Lord through the prophet, saying, “Out of Egypt I called my son.”', pt: 'e lá ficou até a morte de Herodes, para que se cumprisse o que fora dito da parte do Senhor pelo profeta: Do Egito chamei o meu Filho.' },
      { v: 16, en: 'Then Herod, when he saw that he was mocked by the wise men, was exceedingly angry, and sent out, and killed all the male children who were in Bethlehem and in all the surrounding countryside, from two years old and under, according to the exact time which he had learned from the wise men.', pt: 'Então Herodes, vendo que fora iludido pelos magos, irou-se grandemente e mandou matar todos os meninos de dois anos para baixo que havia em Belém, e em todos os seus arredores, segundo o tempo que com precisão inquirira dos magos.' },
      { v: 17, en: 'Then that which was spoken by Jeremiah the prophet was fulfilled, saying,', pt: 'Cumpriu-se então o que fora dito pelo profeta Jeremias:' },
      { v: 18, en: '“A voice was heard in Ramah, lamentation, weeping and great mourning, Rachel weeping for her children; she wouldn’t be comforted, because they are no more.”', pt: 'Em Ramá se ouviu uma voz, lamentação e grande pranto: Raquel chorando os seus filhos, e não querendo ser consolada, porque eles já não existem.' },
      { v: 19, en: 'But when Herod was dead, behold, an angel of the Lord appeared in a dream to Joseph in Egypt, saying,', pt: 'Mas tendo morrido Herodes, eis que um anjo do Senhor apareceu em sonho a José no Egito,' },
      { v: 20, en: '“Arise and take the young child and his mother, and go into the land of Israel, for those who sought the young child’s life are dead.”', pt: 'dizendo: Levanta-te, toma o menino e sua mãe e vai para a terra de Israel; porque já morreram os que procuravam a morte do menino.' },
      { v: 21, en: 'He arose and took the young child and his mother, and came into the land of Israel.', pt: 'Então ele se levantou, tomou o menino e sua mãe e foi para a terra de Israel.' },
      { v: 22, en: 'But when he heard that Archelaus was reigning over Judea in the place of his father, Herod, he was afraid to go there. Being warned in a dream, he withdrew into the region of Galilee,', pt: 'Ouvindo, porém, que Arquelau reinava na Judéia em lugar de seu pai Herodes, temeu ir para lá; mas avisado em sonho por divina revelação, retirou-se para as regiões da Galiléia,' },
      { v: 23, en: 'and came and lived in a city called Nazareth; that it might be fulfilled which was spoken through the prophets: “He will be called a Nazarene.”', pt: 'e foi habitar numa cidade chamada Nazaré; para que se cumprisse o que fora dito pelos profetas: Ele será chamado nazareno.' },
    ],
    3: [
      { v: 1, en: 'In those days, John the Baptizer came, preaching in the wilderness of Judea, saying,', pt: 'Naqueles dias apareceu João, o Batista, pregando no deserto da Judéia,' },
      { v: 2, en: '“Repent, for the Kingdom of Heaven is at hand!”', pt: 'dizendo: Arrependei-vos, porque é chegado o reino dos céus.' },
      { v: 3, en: 'For this is he who was spoken of by Isaiah the prophet, saying, “The voice of one crying in the wilderness, make ready the way of the Lord. Make his paths straight.”', pt: 'Porque este é o anunciado pelo profeta Isaías, que diz: Voz do que clama no deserto; Preparai o caminho do Senhor, endireitai as suas veredas.' },
      { v: 4, en: 'Now John himself wore clothing made of camel’s hair, with a leather belt around his waist. His food was locusts and wild honey.', pt: 'Ora, João usava uma veste de pelos de camelo, e um cinto de couro em torno de seus lombos; e alimentava-se de gafanhotos e mel silvestre.' },
      { v: 5, en: 'Then people from Jerusalem, all of Judea, and all the region around the Jordan went out to him.', pt: 'Então iam ter com ele os de Jerusalém, de toda a Judéia, e de toda a circunvizinhança do Jordão,' },
      { v: 6, en: 'They were baptized by him in the Jordan, confessing their sins.', pt: 'e eram por ele batizados no rio Jordão, confessando os seus pecados.' },
      { v: 7, en: 'But when he saw many of the Pharisees and Sadducees coming for his baptism, he said to them, “You offspring of vipers, who warned you to flee from the wrath to come?', pt: 'Mas, vendo ele muitos dos fariseus e dos saduceus que vinham ao seu batismo, disse-lhes: Raça de víboras, quem vos ensinou a fugir da ira vindoura?' },
      { v: 8, en: 'Therefore produce fruit worthy of repentance!', pt: 'Produzi, pois, frutos dignos de arrependimento,' },
      { v: 9, en: 'Don’t think to yourselves, ‘We have Abraham for our father,’ for I tell you that God is able to raise up children to Abraham from these stones.', pt: 'e não queirais dizer dentro de vós mesmos: Temos por pai a Abraão; porque eu vos digo que mesmo destas pedras Deus pode suscitar filhos a Abraão.' },
      { v: 10, en: '“Even now the ax lies at the root of the trees. Therefore every tree that doesn’t produce good fruit is cut down, and cast into the fire.', pt: 'E já está posto o machado á raiz das árvores; toda árvore, pois que não produz bom fruto, é cortada e lançada no fogo.' },
      { v: 11, en: 'I indeed baptize you in water for repentance, but he who comes after me is mightier than I, whose shoes I am not worthy to carry. He will baptize you in the Holy Spirit.', pt: 'Eu, na verdade, vos batizo em água, na base do arrependimento; mas aquele que vem após mim é mais poderoso do que eu, que nem sou digno de levar-lhe as alparcas; ele vos batizará no Espírito Santo, e em fogo.' },
      { v: 12, en: 'His winnowing fork is in his hand, and he will thoroughly cleanse his threshing floor. He will gather his wheat into the barn, but the chaff he will burn up with unquenchable fire.”', pt: 'A sua pá ele tem na mão, e limpará bem a sua eira; recolherá o seu trigo ao celeiro, mas queimará a palha em fogo inextinguível.' },
      { v: 13, en: 'Then Jesus came from Galilee to the Jordan to John, to be baptized by him.', pt: 'Então veio Jesus da Galiléia ter com João, junto do Jordão, para ser batizado por ele.' },
      { v: 14, en: 'But John would have hindered him, saying, “I need to be baptized by you, and you come to me?”', pt: 'Mas João o impedia, dizendo: Eu é que preciso ser batizado por ti, e tu vens a mim?' },
      { v: 15, en: 'But Jesus, answering, said to him, “Allow it now, for this is the fitting way for us to fulfill all righteousness.” Then he allowed him.', pt: 'Jesus, porém, lhe respondeu: Consente agora; porque assim nos convém cumprir toda a justiça. Então ele consentiu.' },
      { v: 16, en: 'Jesus, when he was baptized, went up directly from the water: and behold, the heavens were opened to him. He saw the Spirit of God descending as a dove, and coming on him.', pt: 'Batizado que foi Jesus, saiu logo da água; e eis que se lhe abriram os céus, e viu o Espírito Santo de Deus descendo como uma pomba e vindo sobre ele;' },
      { v: 17, en: 'Behold, a voice out of the heavens said, “This is my beloved Son, with whom I am well pleased.”', pt: 'e eis que uma voz dos céus dizia: Este é o meu Filho amado, em quem me comprazo.' },
    ],
    4: [
      { v: 1, en: 'Then Jesus was led up by the Spirit into the wilderness to be tempted by the devil.', pt: 'Então foi conduzido Jesus pelo Espírito ao deserto, para ser tentado pelo Diabo.' },
      { v: 2, en: 'When he had fasted forty days and forty nights, he was hungry afterward.', pt: 'E, tendo jejuado quarenta dias e quarenta noites, depois teve fome.' },
      { v: 3, en: 'The tempter came and said to him, “If you are the Son of God, command that these stones become bread.”', pt: 'Chegando, então, o tentador, disse-lhe: Se tu és Filho de Deus manda que estas pedras se tornem em pães.' },
      { v: 4, en: 'But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of the mouth of God.’”', pt: 'Mas Jesus lhe respondeu: Está escrito: Nem só de pão viverá o homem, mas de toda palavra que sai da boca de Deus.' },
      { v: 5, en: 'Then the devil took him into the holy city. He set him on the pinnacle of the temple,', pt: 'Então o Diabo o levou à cidade santa, colocou-o sobre o pináculo do templo,' },
      { v: 6, en: 'and said to him, “If you are the Son of God, throw yourself down, for it is written, ‘He will put his angels in charge of you.’ and, ‘On their hands they will bear you up, so that you don’t dash your foot against a stone.’”', pt: 'e disse-lhe: Se tu és Filho de Deus, lança-te daqui abaixo; porque está escrito: Aos seus anjos dará ordens a teu respeito; e: eles te susterão nas mãos, para que nunca tropeces em alguma pedra.' },
      { v: 7, en: 'Jesus said to him, “Again, it is written, ‘You shall not test the Lord, your God.’”', pt: 'Replicou-lhe Jesus: Também está escrito: Não tentarás o Senhor teu Deus.' },
      { v: 8, en: 'Again, the devil took him to an exceedingly high mountain, and showed him all the kingdoms of the world, and their glory.', pt: 'Novamente o Diabo o levou a um monte muito alto; e mostrou-lhe todos os reinos do mundo, e a glória deles;' },
      { v: 9, en: 'He said to him, “I will give you all of these things, if you will fall down and worship me.”', pt: 'e disse-lhe: Tudo isto te darei, se, prostrado, me adorares.' },
      { v: 10, en: 'Then Jesus said to him, “Get behind me, Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”', pt: 'Então ordenou-lhe Jesus: Vai-te, Satanás; porque está escrito: Ao Senhor teu Deus adorarás, e só a ele servirás.' },
      { v: 11, en: 'Then the devil left him, and behold, angels came and served him.', pt: 'Então o Diabo o deixou; e eis que vieram os anjos e o serviram.' },
      { v: 12, en: 'Now when Jesus heard that John was delivered up, he withdrew into Galilee.', pt: 'Ora, ouvindo Jesus que João fora entregue, retirou-se para a Galiléia;' },
      { v: 13, en: 'Leaving Nazareth, he came and lived in Capernaum, which is by the sea, in the region of Zebulun and Naphtali,', pt: 'e, deixando Nazaré, foi habitar em Cafarnaum, cidade marítima, nos confins de Zabulom e Naftali;' },
      { v: 14, en: 'that it might be fulfilled which was spoken through Isaiah the prophet, saying,', pt: 'para que se cumprisse o que fora dito pelo profeta Isaías:' },
      { v: 15, en: '“The land of Zebulun and the land of Naphtali, toward the sea, beyond the Jordan, Galilee of the Gentiles,', pt: 'A terra de Zabulom e a terra de Naftali, o caminho do mar, além do Jordão, a Galiléia dos gentios,' },
      { v: 16, en: 'the people who sat in darkness saw a great light, to those who sat in the region and shadow of death, to them light has dawned.”', pt: 'o povo que estava sentado em trevas viu uma grande luz; sim, aos que estavam sentados na região da sombra da morte, a estes a luz raiou.' },
      { v: 17, en: 'From that time, Jesus began to preach, and to say, “Repent! For the Kingdom of Heaven is at hand.”', pt: 'Desde então começou Jesus a pregar, e a dizer: Arrependei- vos, porque é chegado o reino dos céus.' },
      { v: 18, en: 'Walking by the sea of Galilee, he saw two brothers: Simon, who is called Peter, and Andrew, his brother, casting a net into the sea; for they were fishermen.', pt: 'E Jesus, andando ao longo do mar da Galiléia, viu dois irmãos - Simão, chamado Pedro, e seu irmão André, os quais lançavam a rede ao mar, porque eram pescadores.' },
      { v: 19, en: 'He said to them, “Come after me, and I will make you fishers for men.”', pt: 'Disse-lhes: Vinde após mim, e eu vos farei pescadores de homens.' },
      { v: 20, en: 'They immediately left their nets and followed him.', pt: 'Eles, pois, deixando imediatamente as redes, o seguiram.' },
      { v: 21, en: 'Going on from there, he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets. He called them.', pt: 'E, passando mais adiante, viu outros dois irmãos - Tiago, filho de Zebedeu, e seu irmão João, no barco com seu pai Zebedeu, consertando as redes; e os chamou.' },
      { v: 22, en: 'They immediately left the boat and their father, and followed him.', pt: 'Estes, deixando imediatamente o barco e seu pai, seguiram- no.' },
      { v: 23, en: 'Jesus went about in all Galilee, teaching in their synagogues, preaching the Good News of the Kingdom, and healing every disease and every sickness among the people.', pt: 'E percorria Jesus toda a Galiléia, ensinando nas sinagogas, pregando o evangelho do reino, e curando todas as doenças e enfermidades entre o povo.' },
      { v: 24, en: 'The report about him went out into all Syria. They brought to him all who were sick, afflicted with various diseases and torments, possessed with demons, epileptics, and paralytics; and he healed them.', pt: 'Assim a sua fama correu por toda a Síria; e trouxeram-lhe todos os que padeciam, acometidos de várias doenças e tormentos, os endemoninhados, os lunáticos, e os paralíticos; e ele os curou.' },
      { v: 25, en: 'Great multitudes from Galilee, Decapolis, Jerusalem, Judea and from beyond the Jordan followed him.', pt: 'De sorte que o seguiam grandes multidões da Galiléia, de Decápolis, de Jerusalém, da Judéia, e dalém do Jordão.' },
    ],
    5: [
      { v: 1, en: 'Seeing the multitudes, he went up onto the mountain. When he had sat down, his disciples came to him.', pt: 'Jesus, pois, vendo as multidões, subiu ao monte; e, tendo se assentado, aproximaram-se os seus discípulos,' },
      { v: 2, en: 'He opened his mouth and taught them, saying,', pt: 'e ele se pôs a ensiná-los, dizendo:' },
      { v: 3, en: '“Blessed are the poor in spirit, for theirs is the Kingdom of Heaven.', pt: 'Bem-aventurados os humildes de espírito, porque deles é o reino dos céus.' },
      { v: 4, en: 'Blessed are those who mourn, for they shall be comforted.', pt: 'Bem-aventurados os que choram, porque eles serão consolados.' },
      { v: 5, en: 'Blessed are the gentle, for they shall inherit the earth.', pt: 'Bem-aventurados os mansos, porque eles herdarão a terra.' },
      { v: 6, en: 'Blessed are those who hunger and thirst after righteousness, for they shall be filled.', pt: 'Bem-aventurados os que têm fome e sede de justiça porque eles serão fartos.' },
      { v: 7, en: 'Blessed are the merciful, for they shall obtain mercy.', pt: 'Bem-aventurados os misericordiosos, porque eles alcançarão misericórdia.' },
      { v: 8, en: 'Blessed are the pure in heart, for they shall see God.', pt: 'Bem-aventurados os limpos de coração, porque eles verão a Deus.' },
      { v: 9, en: 'Blessed are the peacemakers, for they shall be called children of God.', pt: 'Bem-aventurados os pacificadores, porque eles serão chamados filhos de Deus.' },
      { v: 10, en: 'Blessed are those who have been persecuted for righteousness’ sake, for theirs is the Kingdom of Heaven.', pt: 'Bem-aventurados os que são perseguidos por causa da justiça, porque deles é o reino dos céus.' },
      { v: 11, en: '“Blessed are you when people reproach you, persecute you, and say all kinds of evil against you falsely, for my sake.', pt: 'Bem-aventurados sois vós, quando vos injuriarem e perseguiram e, mentindo, disserem todo mal contra vós por minha causa.' },
      { v: 12, en: 'Rejoice, and be exceedingly glad, for great is your reward in heaven. For that is how they persecuted the prophets who were before you.', pt: 'Alegrai-vos e exultai, porque é grande o vosso galardão nos céus; porque assim perseguiram aos profetas que foram antes de vós.' },
      { v: 13, en: '“You are the salt of the earth, but if the salt has lost its flavor, with what will it be salted? It is then good for nothing, but to be cast out and trodden under the feet of men.', pt: 'Vós sois o sal da terra; mas se o sal se tornar insípido, com que se há de restaurar-lhe o sabor? para nada mais presta, senão para ser lançado fora, e ser pisado pelos homens.' },
      { v: 14, en: 'You are the light of the world. A city located on a hill can’t be hidden.', pt: 'Vós sois a luz do mundo. Não se pode esconder uma cidade situada sobre um monte;' },
      { v: 15, en: 'Neither do you light a lamp, and put it under a measuring basket, but on a stand; and it shines to all who are in the house.', pt: 'nem os que acendem uma candeia a colocam debaixo do alqueire, mas no velador, e assim ilumina a todos que estão na casa.' },
      { v: 16, en: 'Even so, let your light shine before men; that they may see your good works, and glorify your Father who is in heaven.', pt: 'Assim resplandeça a vossa luz diante dos homens, para que vejam as vossas boas obras, e glorifiquem a vosso Pai, que está nos céus.' },
      { v: 17, en: '“Don’t think that I came to destroy the law or the prophets. I didn’t come to destroy, but to fulfill.', pt: 'Não penseis que vim destruir a lei ou os profetas; não vim destruir, mas cumprir.' },
      { v: 18, en: 'For most certainly, I tell you, until heaven and earth pass away, not even one smallest letter or one tiny pen stroke shall in any way pass away from the law, until all things are accomplished.', pt: 'Porque em verdade vos digo que, até que o céu e a terra passem, de modo nenhum passará da lei um só i ou um só til, até que tudo seja cumprido.' },
      { v: 19, en: 'Whoever, therefore, shall break one of these least commandments, and teach others to do so, shall be called least in the Kingdom of Heaven; but whoever shall do and teach them shall be called great in the Kingdom of Heaven.', pt: 'Qualquer, pois, que violar um destes mandamentos, por menor que seja, e assim ensinar aos homens, será chamado o menor no reino dos céus; aquele, porém, que os cumprir e ensinar será chamado grande no reino dos céus.' },
      { v: 20, en: 'For I tell you that unless your righteousness exceeds that of the scribes and Pharisees, there is no way you will enter into the Kingdom of Heaven.', pt: 'Pois eu vos digo que, se a vossa justiça não exceder a dos escribas e fariseus, de modo nenhum entrareis no reino dos céus.' },
      { v: 21, en: '“You have heard that it was said to the ancient ones, ‘You shall not murder;’ and ‘Whoever murders will be in danger of the judgment.’', pt: 'Ouvistes que foi dito aos antigos: Não matarás; e, Quem matar será réu de juízo.' },
      { v: 22, en: 'But I tell you, that everyone who is angry with his brother without a cause will be in danger of the judgment; and whoever says to his brother, ‘Raca!’ will be in danger of the council; and whoever says, ‘You fool!’ will be in danger of the fire of Gehenna.', pt: 'Eu, porém, vos digo que todo aquele que se encolerizar contra seu irmão, será réu de juízo; e quem disser a seu irmão: Raca, será réu diante do sinédrio; e quem lhe disser: Tolo, será réu do fogo do inferno.' },
      { v: 23, en: '“If therefore you are offering your gift at the altar, and there remember that your brother has anything against you,', pt: 'Portanto, se estiveres apresentando a tua oferta no altar, e aí te lembrares de que teu irmão tem alguma coisa contra ti,' },
      { v: 24, en: 'leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift.', pt: 'deixa ali diante do altar a tua oferta, e vai conciliar-te primeiro com teu irmão, e depois vem apresentar a tua oferta.' },
      { v: 25, en: 'Agree with your adversary quickly, while you are with him on the way; lest perhaps the prosecutor deliver you to the judge, and the judge deliver you to the officer, and you be cast into prison.', pt: 'Concilia-te depressa com o teu adversário, enquanto estás no caminho com ele; para que não aconteça que o adversário te entregue ao guarda, e sejas lançado na prisão.' },
      { v: 26, en: 'Most certainly I tell you, you shall by no means get out of there, until you have paid the last penny.', pt: 'Em verdade te digo que de maneira nenhuma sairás dali enquanto não pagares o último ceitil.' },
      { v: 27, en: '“You have heard that it was said, ‘You shall not commit adultery;’', pt: 'Ouvistes que foi dito: Não adulterarás.' },
      { v: 28, en: 'but I tell you that everyone who gazes at a woman to lust after her has committed adultery with her already in his heart.', pt: 'Eu, porém, vos digo que todo aquele que olhar para uma mulher para a cobiçar, já em seu coração cometeu adultério com ela.' },
      { v: 29, en: 'If your right eye causes you to stumble, pluck it out and throw it away from you. For it is more profitable for you that one of your members should perish, than for your whole body to be cast into Gehenna.', pt: 'Se o teu olho direito te faz tropeçar, arranca-o e lança-o de ti; pois te é melhor que se perca um dos teus membros do que seja todo o teu corpo lançado no inferno.' },
      { v: 30, en: 'If your right hand causes you to stumble, cut it off, and throw it away from you. For it is more profitable for you that one of your members should perish, than for your whole body to be cast into Gehenna.', pt: 'E, se a tua mão direita te faz tropeçar, corta-a e lança-a de ti; pois te é melhor que se perca um dos teus membros do que vá todo o teu corpo para o inferno.' },
      { v: 31, en: '“It was also said, ‘Whoever shall put away his wife, let him give her a writing of divorce,’', pt: 'Também foi dito: Quem repudiar sua mulher, dê-lhe carta de divórcio.' },
      { v: 32, en: 'but I tell you that whoever puts away his wife, except for the cause of sexual immorality, makes her an adulteress; and whoever marries her when she is put away commits adultery.', pt: 'Eu, porém, vos digo que todo aquele que repudia sua mulher, a não ser por causa de infidelidade, a faz adúltera; e quem casar com a repudiada, comete adultério.' },
      { v: 33, en: '“Again you have heard that it was said to them of old time, ‘You shall not make false vows, but shall perform to the Lord your vows,’', pt: 'Outrossim, ouvistes que foi dito aos antigos: Não jurarás falso, mas cumprirás para com o Senhor os teus juramentos.' },
      { v: 34, en: 'but I tell you, don’t swear at all: neither by heaven, for it is the throne of God;', pt: 'Eu, porém, vos digo que de maneira nenhuma jureis; nem pelo céu, porque é o trono de Deus;' },
      { v: 35, en: 'nor by the earth, for it is the footstool of his feet; nor by Jerusalem, for it is the city of the great King.', pt: 'nem pela terra, porque é o escabelo de seus pés; nem por Jerusalém, porque é a cidade do grande Rei;' },
      { v: 36, en: 'Neither shall you swear by your head, for you can’t make one hair white or black.', pt: 'nem jures pela tua cabeça, porque não podes tornar um só cabelo branco ou preto.' },
      { v: 37, en: 'But let your ‘Yes’ be ‘Yes’ and your ‘No’ be ‘No.’ Whatever is more than these is of the evil one.', pt: 'Seja, porém, o vosso falar: Sim, sim; não, não; pois o que passa daí, vem do Maligno.' },
      { v: 38, en: '“You have heard that it was said, ‘An eye for an eye, and a tooth for a tooth.’', pt: 'Ouvistes que foi dito: Olho por olho, e dente por dente.' },
      { v: 39, en: 'But I tell you, don’t resist him who is evil; but whoever strikes you on your right cheek, turn to him the other also.', pt: 'Eu, porém, vos digo que não resistais ao homem mau; mas a qualquer que te bater na face direita, oferece-lhe também a outra;' },
      { v: 40, en: 'If anyone sues you to take away your coat, let him have your cloak also.', pt: 'e ao que quiser pleitear contigo, e tirar-te a túnica, larga-lhe também a capa;' },
      { v: 41, en: 'Whoever compels you to go one mile, go with him two.', pt: 'e, se qualquer te obrigar a caminhar mil passos, vai com ele dois mil.' },
      { v: 42, en: 'Give to him who asks you, and don’t turn away him who desires to borrow from you.', pt: 'Dá a quem te pedir, e não voltes as costas ao que quiser que lhe emprestes.' },
      { v: 43, en: '“You have heard that it was said, ‘You shall love your neighbor and hate your enemy.’', pt: 'Ouvistes que foi dito: Amarás ao teu próximo, e odiarás ao teu inimigo.' },
      { v: 44, en: 'But I tell you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who mistreat you and persecute you,', pt: 'Eu, porém, vos digo: Amai aos vossos inimigos, e orai pelos que vos perseguem;' },
      { v: 45, en: 'that you may be children of your Father who is in heaven. For he makes his sun to rise on the evil and the good, and sends rain on the just and the unjust.', pt: 'para que vos torneis filhos do vosso Pai que está nos céus; porque ele faz nascer o seu sol sobre maus e bons, e faz chover sobre justos e injustos.' },
      { v: 46, en: 'For if you love those who love you, what reward do you have? Don’t even the tax collectors do the same?', pt: 'Pois, se amardes aos que vos amam, que recompensa tereis? não fazem os publicanos também o mesmo?' },
      { v: 47, en: 'If you only greet your friends, what more do you do than others? Don’t even the tax collectors do the same?', pt: 'E, se saudardes somente os vossos irmãos, que fazeis demais? não fazem os gentios também o mesmo?' },
      { v: 48, en: 'Therefore you shall be perfect, just as your Father in heaven is perfect.', pt: 'Sede vós, pois, perfeitos, como é perfeito o vosso Pai celestial.' },
    ],
    6: [
      { v: 1, en: '“Be careful that you don’t do your charitable giving before men, to be seen by them, or else you have no reward from your Father who is in heaven.', pt: 'Guardai-vos de fazer as vossas boas obras diante dos homens, para serdes vistos por eles; de outra sorte não tereis recompensa junto de vosso Pai, que está nos céus.' },
      { v: 2, en: 'Therefore when you do merciful deeds, don’t sound a trumpet before yourself, as the hypocrites do in the synagogues and in the streets, that they may get glory from men. Most certainly I tell you, they have received their reward.', pt: 'Quando, pois, deres esmola, não faças tocar trombeta diante de ti, como fazem os hipócritas nas sinagogas e nas ruas, para serem glorificados pelos homens. Em verdade vos digo que já receberam a sua recompensa.' },
      { v: 3, en: 'But when you do merciful deeds, don’t let your left hand know what your right hand does,', pt: 'Mas, quando tu deres esmola, não saiba a tua mão esquerda o que faz a direita;' },
      { v: 4, en: 'so that your merciful deeds may be in secret, then your Father who sees in secret will reward you openly.', pt: 'para que a tua esmola fique em secreto; e teu Pai, que vê em secreto, te recompensará.' },
      { v: 5, en: '“When you pray, you shall not be as the hypocrites, for they love to stand and pray in the synagogues and in the corners of the streets, that they may be seen by men. Most certainly, I tell you, they have received their reward.', pt: 'E, quando orardes, não sejais como os hipócritas; pois gostam de orar em pé nas sinagogas, e às esquinas das ruas, para serem vistos pelos homens. Em verdade vos digo que já receberam a sua recompensa.' },
      { v: 6, en: 'But you, when you pray, enter into your inner room, and having shut your door, pray to your Father who is in secret, and your Father who sees in secret will reward you openly.', pt: 'Mas tu, quando orares, entra no teu quarto e, fechando a porta, ora a teu Pai que está em secreto; e teu Pai, que vê em secreto, te recompensará.' },
      { v: 7, en: 'In praying, don’t use vain repetitions, as the Gentiles do; for they think that they will be heard for their much speaking.', pt: 'E, orando, não useis de vãs repetições, como os gentios; porque pensam que pelo seu muito falar serão ouvidos.' },
      { v: 8, en: 'Therefore don’t be like them, for your Father knows what things you need, before you ask him.', pt: 'Não vos assemelheis, pois, a eles; porque vosso Pai sabe o que vos é necessário, antes de vós lho pedirdes.' },
      { v: 9, en: 'Pray like this: ‘Our Father in heaven, may your name be kept holy.', pt: 'Portanto, orai vós deste modo: Pai nosso que estás nos céus, santificado seja o teu nome;' },
      { v: 10, en: 'Let your Kingdom come. Let your will be done, as in heaven, so on earth.', pt: 'venha o teu reino, seja feita a tua vontade, assim na terra como no céu;' },
      { v: 11, en: 'Give us today our daily bread.', pt: 'o pão nosso de cada dia nos dá hoje;' },
      { v: 12, en: 'Forgive us our debts, as we also forgive our debtors.', pt: 'e perdoa-nos as nossas dívidas, assim como nós também temos perdoado aos nossos devedores;' },
      { v: 13, en: 'Bring us not into temptation, but deliver us from the evil one. For yours is the Kingdom, the power, and the glory forever. Amen.’', pt: 'e não nos deixes entrar em tentação; mas livra-nos do mal. [Porque teu é o reino e o poder, e a glória, para sempre, Amém.]' },
      { v: 14, en: '“For if you forgive men their trespasses, your heavenly Father will also forgive you.', pt: 'Porque, se perdoardes aos homens as suas ofensas, também vosso Pai celestial vos perdoará a vós;' },
      { v: 15, en: 'But if you don’t forgive men their trespasses, neither will your Father forgive your trespasses.', pt: 'se, porém, não perdoardes aos homens, tampouco vosso Pai perdoará vossas ofensas.' },
      { v: 16, en: '“Moreover when you fast, don’t be like the hypocrites, with sad faces. For they disfigure their faces, that they may be seen by men to be fasting. Most certainly I tell you, they have received their reward.', pt: 'Quando jejuardes, não vos mostreis contristrados como os hipócritas; porque eles desfiguram os seus rostos, para que os homens vejam que estão jejuando. Em verdade vos digo que já receberam a sua recompensa.' },
      { v: 17, en: 'But you, when you fast, anoint your head, and wash your face;', pt: 'Tu, porém, quando jejuares, unge a tua cabeça, e lava o teu rosto,' },
      { v: 18, en: 'so that you are not seen by men to be fasting, but by your Father who is in secret, and your Father, who sees in secret, will reward you.', pt: 'para não mostrar aos homens que estás jejuando, mas a teu Pai, que está em secreto; e teu Pai, que vê em secreto, te recompensará.' },
      { v: 19, en: '“Don’t lay up treasures for yourselves on the earth, where moth and rust consume, and where thieves break through and steal;', pt: 'Não ajunteis para vós tesouros na terra; onde a traça e a ferrugem os consomem, e onde os ladrões minam e roubam;' },
      { v: 20, en: 'but lay up for yourselves treasures in heaven, where neither moth nor rust consume, and where thieves don’t break through and steal;', pt: 'mas ajuntai para vós tesouros no céu, onde nem a traça nem a ferrugem os consumem, e onde os ladrões não minam nem roubam.' },
      { v: 21, en: 'for where your treasure is, there your heart will be also.', pt: 'Porque onde estiver o teu tesouro, aí estará também o teu coração.' },
      { v: 22, en: '“The lamp of the body is the eye. If therefore your eye is sound, your whole body will be full of light.', pt: 'A candeia do corpo são os olhos; de sorte que, se os teus olhos forem bons, todo teu corpo terá luz;' },
      { v: 23, en: 'But if your eye is evil, your whole body will be full of darkness. If therefore the light that is in you is darkness, how great is the darkness!', pt: 'se, porém, os teus olhos forem maus, o teu corpo será tenebroso. Se, portanto, a luz que em ti há são trevas, quão grandes são tais trevas!' },
      { v: 24, en: '“No one can serve two masters, for either he will hate the one and love the other; or else he will be devoted to one and despise the other. You can’t serve both God and Mammon.', pt: 'Ninguém pode servir a dois senhores; porque ou há de odiar a um e amar o outro, ou há de dedicar-se a um e desprezar o outro. Não podeis servir a Deus e às riquezas.' },
      { v: 25, en: 'Therefore I tell you, don’t be anxious for your life: what you will eat, or what you will drink; nor yet for your body, what you will wear. Isn’t life more than food, and the body more than clothing?', pt: 'Por isso vos digo: Não estejais ansiosos quanto à vossa vida, pelo que haveis de comer, ou pelo que haveis de beber; nem, quanto ao vosso corpo, pelo que haveis de vestir. Não é a vida mais do que o alimento, e o corpo mais do que o vestuário?' },
      { v: 26, en: 'See the birds of the sky, that they don’t sow, neither do they reap, nor gather into barns. Your heavenly Father feeds them. Aren’t you of much more value than they?', pt: 'Olhai para as aves do céu, que não semeiam, nem ceifam, nem ajuntam em celeiros; e vosso Pai celestial as alimenta. Não valeis vós muito mais do que elas?' },
      { v: 27, en: '“Which of you, by being anxious, can add one moment to his lifespan?', pt: 'Ora, qual de vós, por mais ansioso que esteja, pode acrescentar um côvado à sua estatura?' },
      { v: 28, en: 'Why are you anxious about clothing? Consider the lilies of the field, how they grow. They don’t toil, neither do they spin,', pt: 'E pelo que haveis de vestir, por que andais ansiosos? Olhai para os lírios do campo, como crescem; não trabalham nem fiam;' },
      { v: 29, en: 'yet I tell you that even Solomon in all his glory was not dressed like one of these.', pt: 'contudo vos digo que nem mesmo Salomão em toda a sua glória se vestiu como um deles.' },
      { v: 30, en: 'But if God so clothes the grass of the field, which today exists, and tomorrow is thrown into the oven, won’t he much more clothe you, you of little faith?', pt: 'Pois, se Deus assim veste a erva do campo, que hoje existe e amanhã é lançada no forno, quanto mais a vós, homens de pouca fé?' },
      { v: 31, en: '“Therefore don’t be anxious, saying, ‘What will we eat?’, ‘What will we drink?’ or, ‘With what will we be clothed?’', pt: 'Portanto, não vos inquieteis, dizendo: Que havemos de comer? ou: Que havemos de beber? ou: Com que nos havemos de vestir?' },
      { v: 32, en: 'For the Gentiles seek after all these things; for your heavenly Father knows that you need all these things.', pt: '(Pois a todas estas coisas os gentios procuram.) Porque vosso Pai celestial sabe que precisais de tudo isso.' },
      { v: 33, en: 'But seek first God’s Kingdom, and his righteousness; and all these things will be given to you as well.', pt: 'Mas buscai primeiro o seu reino e a sua justiça, e todas estas coisas vos serão acrescentadas.' },
      { v: 34, en: 'Therefore don’t be anxious for tomorrow, for tomorrow will be anxious for itself. Each day’s own evil is sufficient.', pt: 'Não vos inquieteis, pois, pelo dia de amanhã; porque o dia de amanhã cuidará de si mesmo. Basta a cada dia o seu mal.' },
    ],
    7: [
      { v: 1, en: '“Don’t judge, so that you won’t be judged.', pt: 'Não julgueis, para que não sejais julgados.' },
      { v: 2, en: 'For with whatever judgment you judge, you will be judged; and with whatever measure you measure, it will be measured to you.', pt: 'Porque com o juízo com que julgais, sereis julgados; e com a medida com que medis vos medirão a vós.' },
      { v: 3, en: 'Why do you see the speck that is in your brother’s eye, but don’t consider the beam that is in your own eye?', pt: 'E por que vês o argueiro no olho do teu irmão, e não reparas na trave que está no teu olho?' },
      { v: 4, en: 'Or how will you tell your brother, ‘Let me remove the speck from your eye;’ and behold, the beam is in your own eye?', pt: 'Ou como dirás a teu irmão: Deixa-me tirar o argueiro do teu olho, quando tens a trave no teu?' },
      { v: 5, en: 'You hypocrite! First remove the beam out of your own eye, and then you can see clearly to remove the speck out of your brother’s eye.', pt: 'Hipócrita! tira primeiro a trave do teu olho; e então verás bem para tirar o argueiro do olho do teu irmão.' },
      { v: 6, en: '“Don’t give that which is holy to the dogs, neither throw your pearls before the pigs, lest perhaps they trample them under their feet, and turn and tear you to pieces.', pt: 'Não deis aos cães o que é santo, nem lanceis aos porcos as vossas pérolas, para não acontecer que as calquem aos pés e, voltando-se, vos despedacem.' },
      { v: 7, en: '“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you.', pt: 'Pedí, e dar-se-vos-á; buscai, e achareis; batei e abrir-se-vos-á.' },
      { v: 8, en: 'For everyone who asks receives. He who seeks finds. To him who knocks it will be opened.', pt: 'Pois todo o que pede, recebe; e quem busca, acha; e ao que bate, abrir-se-lhe-á.' },
      { v: 9, en: 'Or who is there among you, who, if his son asks him for bread, will give him a stone?', pt: 'Ou qual dentre vós é o homem que, se seu filho lhe pedir pão, lhe dará uma pedra?' },
      { v: 10, en: 'Or if he asks for a fish, who will give him a serpent?', pt: 'Ou, se lhe pedir peixe, lhe dará uma serpente?' },
      { v: 11, en: 'If you then, being evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to those who ask him!', pt: 'Se vós, pois, sendo maus, sabeis dar boas dádivas a vossos filhos, quanto mais vosso Pai, que está nos céus, dará boas coisas aos que lhas pedirem?' },
      { v: 12, en: 'Therefore whatever you desire for men to do to you, you shall also do to them; for this is the law and the prophets.', pt: 'Portanto, tudo o que vós quereis que os homens vos façam, fazei-lho também vós a eles; porque esta é a lei e os profetas.' },
      { v: 13, en: '“Enter in by the narrow gate; for wide is the gate and broad is the way that leads to destruction, and many are those who enter in by it.', pt: 'Entrai pela porta estreita; porque larga é a porta, e espaçoso o caminho que conduz à perdição, e muitos são os que entram por ela;' },
      { v: 14, en: 'How narrow is the gate, and restricted is the way that leads to life! Few are those who find it.', pt: 'e porque estreita é a porta, e apertado o caminho que conduz à vida, e poucos são os que a encontram.' },
      { v: 15, en: '“Beware of false prophets, who come to you in sheep’s clothing, but inwardly are ravening wolves.', pt: 'Guardai-vos dos falsos profetas, que vêm a vós disfarçados em ovelhas, mas interiormente são lobos devoradores.' },
      { v: 16, en: 'By their fruits you will know them. Do you gather grapes from thorns, or figs from thistles?', pt: 'Pelos seus frutos os conhecereis. Colhem-se, porventura, uvas dos espinheiros, ou figos dos abrolhos?' },
      { v: 17, en: 'Even so, every good tree produces good fruit; but the corrupt tree produces evil fruit.', pt: 'Assim, toda árvore boa produz bons frutos; porém a árvore má produz frutos maus.' },
      { v: 18, en: 'A good tree can’t produce evil fruit, neither can a corrupt tree produce good fruit.', pt: 'Uma árvore boa não pode dar maus frutos; nem uma árvore má dar frutos bons.' },
      { v: 19, en: 'Every tree that doesn’t grow good fruit is cut down, and thrown into the fire.', pt: 'Toda árvore que não produz bom fruto é cortada e lançada no fogo.' },
      { v: 20, en: 'Therefore by their fruits you will know them.', pt: 'Portanto, pelos seus frutos os conhecereis.' },
      { v: 21, en: 'Not everyone who says to me, ‘Lord, Lord,’ will enter into the Kingdom of Heaven; but he who does the will of my Father who is in heaven.', pt: 'Nem todo o que me diz: Senhor, Senhor! entrará no reino dos céus, mas aquele que faz a vontade de meu Pai, que está nos céus.' },
      { v: 22, en: 'Many will tell me in that day, ‘Lord, Lord, didn’t we prophesy in your name, in your name cast out demons, and in your name do many mighty works?’', pt: 'Muitos me dirão naquele dia: Senhor, Senhor, não profetizamos nós em teu nome? e em teu nome não expulsamos demônios? e em teu nome não fizemos muitos milagres?' },
      { v: 23, en: 'Then I will tell them, ‘I never knew you. Depart from me, you who work iniquity.’', pt: 'Então lhes direi claramemnte: Nunca vos conheci; apartai-vos de mim, vós que praticais a iniquidade.' },
      { v: 24, en: '“Everyone therefore who hears these words of mine, and does them, I will liken him to a wise man, who built his house on a rock.', pt: 'Todo aquele, pois, que ouve estas minhas palavras e as põe em prática, será comparado a um homem prudente, que edificou a casa sobre a rocha.' },
      { v: 25, en: 'The rain came down, the floods came, and the winds blew, and beat on that house; and it didn’t fall, for it was founded on the rock.', pt: 'E desceu a chuva, correram as torrentes, sopraram os ventos, e bateram com ímpeto contra aquela casa; contudo não caiu, porque estava fundada sobre a rocha.' },
      { v: 26, en: 'Everyone who hears these words of mine, and doesn’t do them will be like a foolish man, who built his house on the sand.', pt: 'Mas todo aquele que ouve estas minhas palavras, e não as põe em prática, será comparado a um homem insensato, que edificou a sua casa sobre a areia.' },
      { v: 27, en: 'The rain came down, the floods came, and the winds blew, and beat on that house; and it fell—and great was its fall.”', pt: 'E desceu a chuva, correram as torrentes, sopraram os ventos, e bateram com ímpeto contra aquela casa, e ela caiu; e grande foi a sua queda.' },
      { v: 28, en: 'When Jesus had finished saying these things, the multitudes were astonished at his teaching,', pt: 'Ao concluir Jesus este discurso, as multidões se maravilhavam da sua doutrina;' },
      { v: 29, en: 'for he taught them with authority, and not like the scribes.', pt: 'porque as ensinava como tendo autoridade, e não como os escribas.' },
    ],
    8: [
      { v: 1, en: 'When he came down from the mountain, great multitudes followed him.', pt: 'Quando Jesus desceu do monte, grandes multidões o seguiam.' },
      { v: 2, en: 'Behold, a leper came to him and worshiped him, saying, “Lord, if you want to, you can make me clean.”', pt: 'E eis que veio um leproso e o adorava, dizendo: Senhor, se quiseres, podes tornar-me limpo.' },
      { v: 3, en: 'Jesus stretched out his hand, and touched him, saying, “I want to. Be made clean.” Immediately his leprosy was cleansed.', pt: 'Jesus, pois, estendendo a mão, tocou-o, dizendo: Quero; sê limpo. No mesmo instante ficou purificado da sua lepra.' },
      { v: 4, en: 'Jesus said to him, “See that you tell nobody, but go, show yourself to the priest, and offer the gift that Moses commanded, as a testimony to them.”', pt: 'Disse-lhe então Jesus: Olha, não contes isto a ninguém; mas vai, mostra-te ao sacerdote, e apresenta a oferta que Moisés determinou, para lhes servir de testemunho.' },
      { v: 5, en: 'When he came into Capernaum, a centurion came to him, asking him,', pt: 'Tendo Jesus entrado em Cafarnaum, chegou-se a ele um centurião que lhe rogava, dizendo:' },
      { v: 6, en: 'and saying, “Lord, my servant lies in the house paralyzed, grievously tormented.”', pt: 'Senhor, o meu criado jaz em casa paralítico, e horrivelmente atormentado.' },
      { v: 7, en: 'Jesus said to him, “I will come and heal him.”', pt: 'Respondeu-lhe Jesus: Eu irei, e o curarei.' },
      { v: 8, en: 'The centurion answered, “Lord, I’m not worthy for you to come under my roof. Just say the word, and my servant will be healed.', pt: 'O centurião, porém, replicou-lhe: Senhor, não sou digno de que entres debaixo do meu telhado; mas somente dize uma palavra, e o meu criado há de sarar.' },
      { v: 9, en: 'For I am also a man under authority, having under myself soldiers. I tell this one, ‘Go,’ and he goes; and tell another, ‘Come,’ and he comes; and tell my servant, ‘Do this,’ and he does it.”', pt: 'Pois também eu sou homem sujeito à autoridade, e tenho soldados às minhas ordens; e digo a este: Vai, e ele vai; e a outro: Vem, e ele vem; e ao meu servo: Faze isto, e ele o faz.' },
      { v: 10, en: 'When Jesus heard it, he marveled, and said to those who followed, “Most certainly I tell you, I haven’t found so great a faith, not even in Israel.', pt: 'Jesus, ouvindo isso, admirou-se, e disse aos que o seguiam: Em verdade vos digo que a ninguém encontrei em Israel com tamanha fé.' },
      { v: 11, en: 'I tell you that many will come from the east and the west, and will sit down with Abraham, Isaac, and Jacob in the Kingdom of Heaven,', pt: 'Também vos digo que muitos virão do oriente e do ocidente, e reclinar-se-ão à mesa de Abraão, Isaque e Jacó, no reino dos céus;' },
      { v: 12, en: 'but the children of the Kingdom will be thrown out into the outer darkness. There will be weeping and gnashing of teeth.”', pt: 'mas os filhos do reino serão lançados nas trevas exteriores; ali haverá choro e ranger de dentes.' },
      { v: 13, en: 'Jesus said to the centurion, “Go your way. Let it be done for you as you have believed.” His servant was healed in that hour.', pt: 'Então disse Jesus ao centurião: Vai-te, e te seja feito assim como creste. E naquela mesma hora o seu criado sarou.' },
      { v: 14, en: 'When Jesus came into Peter’s house, he saw his wife’s mother lying sick with a fever.', pt: 'Ora, tendo Jesus entrado na casa de Pedro, viu a sogra deste de cama; e com febre.' },
      { v: 15, en: 'He touched her hand, and the fever left her. She got up and served him.', pt: 'E tocou-lhe a mão, e a febre a deixou; então ela se levantou, e o servia.' },
      { v: 16, en: 'When evening came, they brought to him many possessed with demons. He cast out the spirits with a word, and healed all who were sick;', pt: 'Caída a tarde, trouxeram-lhe muitos endemoninhados; e ele com a sua palavra expulsou os espíritos, e curou todos os enfermos;' },
      { v: 17, en: 'that it might be fulfilled which was spoken through Isaiah the prophet, saying, “He took our infirmities, and bore our diseases.”', pt: 'para que se cumprisse o que fora dito pelo profeta Isaías: Ele tomou sobre si as nossas enfermidades, e levou as nossas doenças.' },
      { v: 18, en: 'Now when Jesus saw great multitudes around him, he gave the order to depart to the other side.', pt: 'Vendo Jesus uma multidão ao redor de si, deu ordem de partir para o outro lado do mar.' },
      { v: 19, en: 'A scribe came, and said to him, “Teacher, I will follow you wherever you go.”', pt: 'E, aproximando-se um escriba, disse-lhe: Mestre, seguir-te- ei para onde quer que fores.' },
      { v: 20, en: 'Jesus said to him, “The foxes have holes, and the birds of the sky have nests, but the Son of Man has nowhere to lay his head.”', pt: 'Respondeu-lhe Jesus: As raposas têm covis, e as aves do céu têm ninhos; mas o Filho do homem não tem onde reclinar a cabeça.' },
      { v: 21, en: 'Another of his disciples said to him, “Lord, allow me first to go and bury my father.”', pt: 'E outro de seus discípulos lhe disse: Senhor, permite-me ir primeiro sepultar meu pai.' },
      { v: 22, en: 'But Jesus said to him, “Follow me, and leave the dead to bury their own dead.”', pt: 'Jesus, porém, respondeu-lhe: Segue-me, e deixa os mortos sepultar os seus próprios mortos.' },
      { v: 23, en: 'When he got into a boat, his disciples followed him.', pt: 'E, entrando ele no barco, seus discípulos o seguiram.' },
      { v: 24, en: 'Behold, a violent storm came up on the sea, so much that the boat was covered with the waves, but he was asleep.', pt: 'E eis que se levantou no mar tão grande tempestade que o barco era coberto pelas ondas; ele, porém, estava dormindo.' },
      { v: 25, en: 'They came to him, and woke him up, saying, “Save us, Lord! We are dying!”', pt: 'Os discípulos, pois, aproximando-se, o despertaram, dizendo: Salva-nos, Senhor, que estamos perecendo.' },
      { v: 26, en: 'He said to them, “Why are you fearful, O you of little faith?” Then he got up, rebuked the wind and the sea, and there was a great calm.', pt: 'Ele lhes respondeu: Por que temeis, homens de pouca fé? Então, levantando-se repreendeu os ventos e o mar, e seguiu-se grande bonança.' },
      { v: 27, en: 'The men marveled, saying, “What kind of man is this, that even the wind and the sea obey him?”', pt: 'E aqueles homens se maravilharam, dizendo: Que homem é este, que até os ventos e o mar lhe obedecem?' },
      { v: 28, en: 'When he came to the other side, into the country of the Gergesenes, two people possessed by demons met him there, coming out of the tombs, exceedingly fierce, so that nobody could pass that way.', pt: 'Tendo ele chegado ao outro lado, à terra dos gadarenos, saíram-lhe ao encontro dois endemoninhados, vindos dos sepulcros; tão ferozes eram que ninguém podia passar por aquele caminho.' },
      { v: 29, en: 'Behold, they cried out, saying, “What do we have to do with you, Jesus, Son of God? Have you come here to torment us before the time?”', pt: 'E eis que gritaram, dizendo: Que temos nós contigo, Filho de Deus? Vieste aqui atormentar-nos antes do tempo?' },
      { v: 30, en: 'Now there was a herd of many pigs feeding far away from them.', pt: 'Ora, a alguma distância deles, andava pastando uma grande manada de porcos.' },
      { v: 31, en: 'The demons begged him, saying, “If you cast us out, permit us to go away into the herd of pigs.”', pt: 'E os demônios rogavam-lhe, dizendo: Se nos expulsas, manda- nos entrar naquela manada de porcos.' },
      { v: 32, en: 'He said to them, “Go!” They came out, and went into the herd of pigs: and behold, the whole herd of pigs rushed down the cliff into the sea, and died in the water.', pt: 'Disse-lhes Jesus: Ide. Então saíram, e entraram nos porcos; e eis que toda a manada se precipitou pelo despenhadeiro no mar, perecendo nas águas.' },
      { v: 33, en: 'Those who fed them fled, and went away into the city, and told everything, including what happened to those who were possessed with demons.', pt: 'Os pastores fugiram e, chegando à cidade, divulgaram todas estas coisas, e o que acontecera aos endemoninhados.' },
      { v: 34, en: 'Behold, all the city came out to meet Jesus. When they saw him, they begged that he would depart from their borders.', pt: 'E eis que toda a cidade saiu ao encontro de Jesus; e vendo- o, rogaram-lhe que se retirasse dos seus termos.' },
    ],
    9: [
      { v: 1, en: 'He entered into a boat, and crossed over, and came into his own city.', pt: 'E entrando Jesus num barco, passou para o outro lado, e chegou à sua própria cidade.' },
      { v: 2, en: 'Behold, they brought to him a man who was paralyzed, lying on a bed. Jesus, seeing their faith, said to the paralytic, “Son, cheer up! Your sins are forgiven you.”', pt: 'E eis que lhe trouxeram um paralítico deitado num leito. Jesus, pois, vendo-lhes a fé, disse ao paralítico: Tem ânimo, filho; perdoados são os teus pecados.' },
      { v: 3, en: 'Behold, some of the scribes said to themselves, “This man blasphemes.”', pt: 'E alguns dos escribas disseram consigo: Este homem blasfema.' },
      { v: 4, en: 'Jesus, knowing their thoughts, said, “Why do you think evil in your hearts?', pt: 'Mas Jesus, conhecendo-lhes os pensamentos, disse: Por que pensais o mal em vossos corações?' },
      { v: 5, en: 'For which is easier, to say, ‘Your sins are forgiven;’ or to say, ‘Get up, and walk?’', pt: 'Pois qual é mais fácil? dizer: Perdoados são os teus pecados, ou dizer: Levanta-te e anda?' },
      { v: 6, en: 'But that you may know that the Son of Man has authority on earth to forgive sins-” (then he said to the paralytic), “Get up, and take up your mat, and go to your house.”', pt: 'Ora, para que saibais que o Filho do homem tem sobre a terra autoridade para perdoar pecados (disse então ao paralítico): Levanta- te, toma o teu leito, e vai para tua casa.' },
      { v: 7, en: 'He arose and departed to his house.', pt: 'E este, levantando-se, foi para sua casa.' },
      { v: 8, en: 'But when the multitudes saw it, they marveled and glorified God, who had given such authority to men.', pt: 'E as multidões, vendo isso, temeram, e glorificaram a Deus, que dera tal autoridade aos homens.' },
      { v: 9, en: 'As Jesus passed by from there, he saw a man called Matthew sitting at the tax collection office. He said to him, “Follow me.” He got up and followed him.', pt: 'Partindo Jesus dali, viu sentado na coletoria um homem chamado Mateus, e disse-lhe: Segue-me. E ele, levantando-se, o seguiu.' },
      { v: 10, en: 'As he sat in the house, behold, many tax collectors and sinners came and sat down with Jesus and his disciples.', pt: 'Ora, estando ele à mesa em casa, eis que chegaram muitos publicanos e pecadores, e se reclinaram à mesa juntamente com Jesus e seus discípulos.' },
      { v: 11, en: 'When the Pharisees saw it, they said to his disciples, “Why does your teacher eat with tax collectors and sinners?”', pt: 'E os fariseus, vendo isso, perguntavam aos discípulos: Por que come o vosso Mestre com publicanos e pecadores?' },
      { v: 12, en: 'When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick do.', pt: 'Jesus, porém, ouvindo isso, respondeu: Não necessitam de médico os sãos, mas sim os enfermos.' },
      { v: 13, en: 'But you go and learn what this means: ‘I desire mercy, and not sacrifice,’ for I came not to call the righteous, but sinners to repentance.”', pt: 'Ide, pois, e aprendei o que significa: Misericórdia quero, e não sacrifícios. Porque eu não vim chamar justos, mas pecadores.' },
      { v: 14, en: 'Then John’s disciples came to him, saying, “Why do we and the Pharisees fast often, but your disciples don’t fast?”', pt: 'Então vieram ter com ele os discípulos de João, perguntando: Por que é que nós e os fariseus jejuamos, mas os teus discípulos não jejuam?' },
      { v: 15, en: 'Jesus said to them, “Can the friends of the bridegroom mourn, as long as the bridegroom is with them? But the days will come when the bridegroom will be taken away from them, and then they will fast.', pt: 'Respondeu-lhes Jesus: Podem porventura ficar tristes os convidados às núpcias, enquanto o noivo está com eles? Dias virão, porém, em que lhes será tirado o noivo, e então hão de jejuar.' },
      { v: 16, en: 'No one puts a piece of unshrunk cloth on an old garment; for the patch would tear away from the garment, and a worse hole is made.', pt: 'Ninguém põe remendo de pano novo em vestido velho; porque semelhante remendo tira parte do vestido, e faz-se maior a rotura.' },
      { v: 17, en: 'Neither do people put new wine into old wine skins, or else the skins would burst, and the wine be spilled, and the skins ruined. No, they put new wine into fresh wine skins, and both are preserved.”', pt: 'Nem se deita vinho novo em odres velhos; do contrário se rebentam, derrama-se o vinho, e os odres se perdem; mas deita-se vinho novo em odres novos, e assim ambos se conservam.' },
      { v: 18, en: 'While he told these things to them, behold, a ruler came and worshiped him, saying, “My daughter has just died, but come and lay your hand on her, and she will live.”', pt: 'Enquanto ainda lhes dizia essas coisas, eis que chegou um chefe da sinagoga e o adorou, dizendo: Minha filha acaba de falecer; mas vem, impõe-lhe a tua mão, e ela viverá.' },
      { v: 19, en: 'Jesus got up and followed him, as did his disciples.', pt: 'Levantou-se, pois, Jesus, e o foi seguindo, ele e os seus discípulos.' },
      { v: 20, en: 'Behold, a woman who had an issue of blood for twelve years came behind him, and touched the fringe of his garment;', pt: 'E eis que certa mulher, que havia doze anos padecia de uma hemorragia, chegou por detrás dele e tocou-lhe a orla do manto;' },
      { v: 21, en: 'for she said within herself, “If I just touch his garment, I will be made well.”', pt: 'porque dizia consigo: Se eu tão-somente tocar-lhe o manto, ficarei sã.' },
      { v: 22, en: 'But Jesus, turning around and seeing her, said, “Daughter, cheer up! Your faith has made you well.” And the woman was made well from that hour.', pt: 'Mas Jesus, voltando-se e vendo-a, disse: Tem ânimo, filha, a tua fé te salvou. E desde aquela hora a mulher ficou sã.' },
      { v: 23, en: 'When Jesus came into the ruler’s house, and saw the flute players, and the crowd in noisy disorder,', pt: 'Quando Jesus chegou à casa daquele chefe, e viu os tocadores de flauta e a multidão em alvoroço,' },
      { v: 24, en: 'he said to them, “Make room, because the girl isn’t dead, but sleeping.” They were ridiculing him.', pt: 'disse; Retirai-vos; porque a menina não está morta, mas dorme. E riam-se dele.' },
      { v: 25, en: 'But when the crowd was put out, he entered in, took her by the hand, and the girl arose.', pt: 'Tendo-se feito sair o povo, entrou Jesus, tomou a menina pela mão, e ela se levantou.' },
      { v: 26, en: 'The report of this went out into all that land.', pt: 'E espalhou-se a notícia disso por toda aquela terra.' },
      { v: 27, en: 'As Jesus passed by from there, two blind men followed him, calling out and saying, “Have mercy on us, son of David!”', pt: 'Partindo Jesus dali, seguiram-no dois cegos, que clamavam, dizendo: Tem compaixão de nós, Filho de Davi.' },
      { v: 28, en: 'When he had come into the house, the blind men came to him. Jesus said to them, “Do you believe that I am able to do this?” They told him, “Yes, Lord.”', pt: 'E, tendo ele entrado em casa, os cegos se aproximaram dele; e Jesus perguntou-lhes: Credes que eu posso fazer isto? Responderam- lhe eles: Sim, Senhor.' },
      { v: 29, en: 'Then he touched their eyes, saying, “According to your faith be it done to you.”', pt: 'Então lhes tocou os olhos, dizendo: Seja-vos feito segundo a vossa fé.' },
      { v: 30, en: 'Their eyes were opened. Jesus strictly commanded them, saying, “See that no one knows about this.”', pt: 'E os olhos se lhes abriram. Jesus ordenou-lhes terminantemente, dizendo: Vede que ninguém o saiba.' },
      { v: 31, en: 'But they went out and spread abroad his fame in all that land.', pt: 'Eles, porém, saíram, e divulgaram a sua fama por toda aquela terra.' },
      { v: 32, en: 'As they went out, behold, a mute man who was demon possessed was brought to him.', pt: 'Enquanto esses se retiravam, eis que lhe trouxeram um homem mudo e endemoninhado.' },
      { v: 33, en: 'When the demon was cast out, the mute man spoke. The multitudes marveled, saying, “Nothing like this has ever been seen in Israel!”', pt: 'E, expulso o demônio, falou o mudo e as multidões se admiraram, dizendo: Nunca tal se viu em Israel.' },
      { v: 34, en: 'But the Pharisees said, “By the prince of the demons, he casts out demons.”', pt: 'Os fariseus, porém, diziam: É pelo príncipe dos demônios que ele expulsa os demônios.' },
      { v: 35, en: 'Jesus went about all the cities and the villages, teaching in their synagogues, and preaching the Good News of the Kingdom, and healing every disease and every sickness among the people.', pt: 'E percorria Jesus todas as cidades e aldeias, ensinando nas sinagogas, pregando o evangelho do reino, e curando toda sorte de doenças e enfermidades.' },
      { v: 36, en: 'But when he saw the multitudes, he was moved with compassion for them, because they were harassed and scattered, like sheep without a shepherd.', pt: 'Vendo ele as multidões, compadeceu-se delas, porque andavam desgarradas e errantes, como ovelhas que não têm pastor.' },
      { v: 37, en: 'Then he said to his disciples, “The harvest indeed is plentiful, but the laborers are few.', pt: 'Então disse a seus discípulos: Na verdade, a seara é grande, mas os trabalhadores são poucos.' },
      { v: 38, en: 'Pray therefore that the Lord of the harvest will send out laborers into his harvest.”', pt: 'Rogai, pois, ao Senhor da seara que mande trabalhadores para a sua seara.' },
    ],
    10: [
      { v: 1, en: 'He called to himself his twelve disciples, and gave them authority over unclean spirits, to cast them out, and to heal every disease and every sickness.', pt: 'E, chamando a si os seus doze discípulos, deu-lhes autoridade sobre os espíritos imundos, para expulsarem, e para curarem toda sorte de doenças e enfermidades.' },
      { v: 2, en: 'Now the names of the twelve apostles are these. The first, Simon, who is called Peter; Andrew, his brother; James the son of Zebedee; John, his brother;', pt: 'Ora, os nomes dos doze apóstolos são estes: primeiro, Simão, chamado Pedro, e André, seu irmão; Tiago, filho de Zebedeu, e João, seu irmão;' },
      { v: 3, en: 'Philip; Bartholomew; Thomas; Matthew the tax collector; James the son of Alphaeus; Lebbaeus, who was also called Thaddaeus;', pt: 'Felipe e Bartolomeu; Tomé e Mateus, o publicano; Tiago, filho de Alfeu, e Tadeu;' },
      { v: 4, en: 'Simon the Canaanite; and Judas Iscariot, who also betrayed him.', pt: 'Simão Cananeu, e Judas Iscariotes, aquele que o traiu.' },
      { v: 5, en: 'Jesus sent these twelve out, and commanded them, saying, “Don’t go among the Gentiles, and don’t enter into any city of the Samaritans.', pt: 'A estes doze enviou Jesus, e ordenou-lhes, dizendo: Não ireis aos gentios, nem entrareis em cidade de samaritanos;' },
      { v: 6, en: 'Rather, go to the lost sheep of the house of Israel.', pt: 'mas ide antes às ovelhas perdidas da casa de Israel;' },
      { v: 7, en: 'As you go, preach, saying, ‘The Kingdom of Heaven is at hand!’', pt: 'e indo, pregai, dizendo: É chegado o reino dos céus.' },
      { v: 8, en: 'Heal the sick, cleanse the lepers, and cast out demons. Freely you received, so freely give.', pt: 'Curai os enfermos, ressuscitai os mortos, limpai os leprosos, expulsai os demônios; de graça recebestes, de graça dai.' },
      { v: 9, en: 'Don’t take any gold, silver, or brass in your money belts.', pt: 'Não vos provereis de ouro, nem de prata, nem de cobre, em vossos cintos;' },
      { v: 10, en: 'Take no bag for your journey, neither two coats, nor shoes, nor staff: for the laborer is worthy of his food.', pt: 'nem de alforje para o caminho, nem de duas túnicas, nem de alparcas, nem de bordão; porque digno é o trabalhador do seu alimento.' },
      { v: 11, en: 'Into whatever city or village you enter, find out who in it is worthy; and stay there until you go on.', pt: 'Em qualquer cidade ou aldeia em que entrardes, procurai saber quem nela é digno, e hospedai-vos aí até que vos retireis.' },
      { v: 12, en: 'As you enter into the household, greet it.', pt: 'E, ao entrardes na casa, saudai-a;' },
      { v: 13, en: 'If the household is worthy, let your peace come on it, but if it isn’t worthy, let your peace return to you.', pt: 'se a casa for digna, desça sobre ela a vossa paz; mas, se não for digna, torne para vós a vossa paz.' },
      { v: 14, en: 'Whoever doesn’t receive you, nor hear your words, as you go out of that house or that city, shake the dust off your feet.', pt: 'E, se ninguém vos receber, nem ouvir as vossas palavras, saindo daquela casa ou daquela cidade, sacudi o pó dos vossos pés.' },
      { v: 15, en: 'Most certainly I tell you, it will be more tolerable for the land of Sodom and Gomorrah in the day of judgment than for that city.', pt: 'Em verdade vos digo que, no dia do juízo, haverá menos rigor para a terra de Sodoma e Gomorra do que para aquela cidade.' },
      { v: 16, en: '“Behold, I send you out as sheep among wolves. Therefore be wise as serpents, and harmless as doves.', pt: 'Eis que vos envio como ovelhas ao meio de lobos; portanto, sede prudentes como as serpentes e simples como as pombas.' },
      { v: 17, en: 'But beware of men: for they will deliver you up to councils, and in their synagogues they will scourge you.', pt: 'Acautelai-vos dos homens; porque eles vos entregarão aos sinédrios, e vos açoitarão nas suas sinagogas;' },
      { v: 18, en: 'Yes, and you will be brought before governors and kings for my sake, for a testimony to them and to the nations.', pt: 'e por minha causa sereis levados à presença dos governadores e dos reis, para lhes servir de testemunho, a eles e aos gentios.' },
      { v: 19, en: 'But when they deliver you up, don’t be anxious how or what you will say, for it will be given you in that hour what you will say.', pt: 'Mas, quando vos entregarem, não cuideis de como, ou o que haveis de falar; porque naquela hora vos será dado o que haveis de dizer.' },
      { v: 20, en: 'For it is not you who speak, but the Spirit of your Father who speaks in you.', pt: 'Porque não sois vós que falais, mas o Espírito de vosso Pai é que fala em vós.' },
      { v: 21, en: '“Brother will deliver up brother to death, and the father his child. Children will rise up against parents, and cause them to be put to death.', pt: 'Um irmão entregará à morte a seu irmão, e um pai a seu filho; e filhos se levantarão contra os pais e os matarão.' },
      { v: 22, en: 'You will be hated by all men for my name’s sake, but he who endures to the end will be saved.', pt: 'E sereis odiados de todos por causa do meu nome, mas aquele que perseverar até o fim, esse será salvo.' },
      { v: 23, en: 'But when they persecute you in this city, flee into the next, for most certainly I tell you, you will not have gone through the cities of Israel, until the Son of Man has come.', pt: 'Quando, porém, vos perseguirem numa cidade, fugi para outra; porque em verdade vos digo que não acabareis de percorrer as cidades de Israel antes que venha o Filho do homem.' },
      { v: 24, en: '“A disciple is not above his teacher, nor a servant above his lord.', pt: 'Não é o discípulo mais do que o seu mestre, nem o servo mais do que o seu senhor.' },
      { v: 25, en: 'It is enough for the disciple that he be like his teacher, and the servant like his lord. If they have called the master of the house Beelzebul, how much more those of his household!', pt: 'Basta ao discípulo ser como seu mestre, e ao servo como seu senhor. Se chamaram Belzebu ao dono da casa, quanto mais aos seus domésticos?' },
      { v: 26, en: 'Therefore don’t be afraid of them, for there is nothing covered that will not be revealed; and hidden that will not be known.', pt: 'Portanto, não os temais; porque nada há encoberto que não haja de ser descoberto, nem oculto que não haja de ser conhecido.' },
      { v: 27, en: 'What I tell you in the darkness, speak in the light; and what you hear whispered in the ear, proclaim on the housetops.', pt: 'O que vos digo às escuras, dizei-o às claras; e o que escutais ao ouvido, dos eirados pregai-o.' },
      { v: 28, en: 'Don’t be afraid of those who kill the body, but are not able to kill the soul. Rather, fear him who is able to destroy both soul and body in Gehenna.', pt: 'E não temais os que matam o corpo, e não podem matar a alma; temei antes aquele que pode fazer perecer no inferno tanto a alma como o corpo.' },
      { v: 29, en: '“Aren’t two sparrows sold for an assarion coin? Not one of them falls on the ground apart from your Father’s will,', pt: 'Não se vendem dois passarinhos por um asse? e nenhum deles cairá em terra sem a vontade de vosso Pai.' },
      { v: 30, en: 'but the very hairs of your head are all numbered.', pt: 'E até mesmo os cabelos da vossa cabeça estão todos contados.' },
      { v: 31, en: 'Therefore don’t be afraid. You are of more value than many sparrows.', pt: 'Não temais, pois; mais valeis vós do que muitos passarinhos.' },
      { v: 32, en: 'Everyone therefore who confesses me before men, him I will also confess before my Father who is in heaven.', pt: 'Portanto, todo aquele que me confessar diante dos homens, também eu o confessarei diante de meu Pai, que está nos céus.' },
      { v: 33, en: 'But whoever denies me before men, him I will also deny before my Father who is in heaven.', pt: 'Mas qualquer que me negar diante dos homens, também eu o negarei diante de meu Pai, que está nos céus.' },
      { v: 34, en: '“Don’t think that I came to send peace on the earth. I didn’t come to send peace, but a sword.', pt: 'Não penseis que vim trazer paz à terra; não vim trazer paz, mas espada.' },
      { v: 35, en: 'For I came to set a man at odds against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law.', pt: 'Porque eu vim pôr em dissensão o homem contra seu pai, a filha contra sua mãe, e a nora contra sua sogra;' },
      { v: 36, en: 'A man’s foes will be those of his own household.', pt: 'e assim os inimigos do homem serão os da sua própria casa.' },
      { v: 37, en: 'He who loves father or mother more than me is not worthy of me; and he who loves son or daughter more than me isn’t worthy of me.', pt: 'Quem ama o pai ou a mãe mais do que a mim não é digno de mim; e quem ama o filho ou a filha mais do que a mim não é digno de mim.' },
      { v: 38, en: 'He who doesn’t take his cross and follow after me, isn’t worthy of me.', pt: 'E quem não toma a sua cruz, e não segue após mim, não é digno de mim.' },
      { v: 39, en: 'He who seeks his life will lose it; and he who loses his life for my sake will find it.', pt: 'Quem achar a sua vida perdê-la-á, e quem perder a sua vida por amor de mim achá-la-á.' },
      { v: 40, en: 'He who receives you receives me, and he who receives me receives him who sent me.', pt: 'Quem vos recebe, a mim me recebe; e quem me recebe a mim, recebe aquele que me enviou.' },
      { v: 41, en: 'He who receives a prophet in the name of a prophet will receive a prophet’s reward. He who receives a righteous man in the name of a righteous man will receive a righteous man’s reward.', pt: 'Quem recebe um profeta na qualidade de profeta, receberá a recompensa de profeta; e quem recebe um justo na qualidade de justo, receberá a recompensa de justo.' },
      { v: 42, en: 'Whoever gives one of these little ones just a cup of cold water to drink in the name of a disciple, most certainly I tell you he will in no way lose his reward.”', pt: 'E aquele que der até mesmo um copo de água fresca a um destes pequeninos, na qualidade de discípulo, em verdade vos digo que de modo algum perderá a sua recompensa.' },
    ],
    11: [
      { v: 1, en: 'When Jesus had finished directing his twelve disciples, he departed from there to teach and preach in their cities.', pt: 'Tendo acabado Jesus de dar instruções aos seus doze discípulos, partiu dali a ensinar e a pregar nas cidades da região.' },
      { v: 2, en: 'Now when John heard in the prison the works of Christ, he sent two of his disciples', pt: 'Ora, quando João no cárcere ouviu falar das obras do Cristo, mandou pelos seus discípulos perguntar-lhe:' },
      { v: 3, en: 'and said to him, “Are you he who comes, or should we look for another?”', pt: 'És tu aquele que havia de vir, ou havemos de esperar outro?' },
      { v: 4, en: 'Jesus answered them, “Go and tell John the things which you hear and see:', pt: 'Respondeu-lhes Jesus: Ide contar a João as coisas que ouvis e vedes:' },
      { v: 5, en: 'the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised up, and the poor have good news preached to them.', pt: 'os cegos vêem, e os coxos andam; os leprosos são purificados, e os surdos ouvem; os mortos são ressuscitados, e aos pobres é anunciado o evangelho.' },
      { v: 6, en: 'Blessed is he who finds no occasion for stumbling in me.”', pt: 'E bem-aventurado é aquele que não se escandalizar de mim.' },
      { v: 7, en: 'As these went their way, Jesus began to say to the multitudes concerning John, “What did you go out into the wilderness to see? A reed shaken by the wind?', pt: 'Ao partirem eles, começou Jesus a dizer às multidões a respeito de João: que saístes a ver no deserto? um caniço agitado pelo vento?' },
      { v: 8, en: 'But what did you go out to see? A man in soft clothing? Behold, those who wear soft clothing are in kings’ houses.', pt: 'Mas que saístes a ver? um homem trajado de vestes luxuosas? Eis que aqueles que trajam vestes luxuosas estão nas casas dos reis.' },
      { v: 9, en: 'But why did you go out? To see a prophet? Yes, I tell you, and much more than a prophet.', pt: 'Mas por que saístes? para ver um profeta? Sim, vos digo, e muito mais do que profeta.' },
      { v: 10, en: 'For this is he, of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’', pt: 'Este é aquele de quem está escrito: Eis aí envio eu ante a tua face o meu mensageiro, que há de preparar adiante de ti o teu caminho.' },
      { v: 11, en: 'Most certainly I tell you, among those who are born of women there has not arisen anyone greater than John the Baptizer; yet he who is least in the Kingdom of Heaven is greater than he.', pt: 'Em verdade vos digo que, entre os nascidos de mulher, não surgiu outro maior do que João, o Batista; mas aquele que é o menor no reino dos céus é maior do que ele.' },
      { v: 12, en: 'From the days of John the Baptizer until now, the Kingdom of Heaven suffers violence, and the violent take it by force.', pt: 'E desde os dias de João, o Batista, até agora, o reino dos céus é tomado a força, e os violentos o tomam de assalto.' },
      { v: 13, en: 'For all the prophets and the law prophesied until John.', pt: 'Pois todos os profetas e a lei profetizaram até João.' },
      { v: 14, en: 'If you are willing to receive it, this is Elijah, who is to come.', pt: 'E, se quereis dar crédito, é este o Elias que havia de vir.' },
      { v: 15, en: 'He who has ears to hear, let him hear.', pt: 'Quem tem ouvidos, ouça.' },
      { v: 16, en: '“But to what shall I compare this generation? It is like children sitting in the marketplaces, who call to their companions', pt: 'Mas, a quem compararei esta geração? É semelhante aos meninos que, sentados nas praças, clamam aos seus companheiros:' },
      { v: 17, en: 'and say, ‘We played the flute for you, and you didn’t dance. We mourned for you, and you didn’t lament.’', pt: 'Tocamo-vos flauta, e não dançastes; cantamos lamentações, e não pranteastes.' },
      { v: 18, en: 'For John came neither eating nor drinking, and they say, ‘He has a demon.’', pt: 'Porquanto veio João, não comendo nem bebendo, e dizem: Tem demônio.' },
      { v: 19, en: 'The Son of Man came eating and drinking, and they say, ‘Behold, a gluttonous man and a drunkard, a friend of tax collectors and sinners!’ But wisdom is justified by her children.”', pt: 'Veio o Filho do homem, comendo e bebendo, e dizem: Eis aí um comilão e bebedor de vinho, amigo de publicanos e pecadores. Entretanto a sabedoria é justificada pelas suas obras.' },
      { v: 20, en: 'Then he began to denounce the cities in which most of his mighty works had been done, because they didn’t repent.', pt: 'Então começou ele a lançar em rosto às cidades onde se operara a maior parte dos seus milagres, o não se haverem arrependido, dizendo:' },
      { v: 21, en: '“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago in sackcloth and ashes.', pt: 'Ai de ti, Corazin! ai de ti, Betsaida! porque, se em Tiro e em Sidom, se tivessem operado os milagres que em vós se operaram, há muito elas se teriam arrependido em cilício e em cinza.' },
      { v: 22, en: 'But I tell you, it will be more tolerable for Tyre and Sidon on the day of judgment than for you.', pt: 'Contudo, eu vos digo que para Tiro e Sidom haverá menos rigor, no dia do juízo, do que para vós.' },
      { v: 23, en: 'You, Capernaum, who are exalted to heaven, you will go down to Hades. For if the mighty works had been done in Sodom which were done in you, it would have remained until today.', pt: 'E tu, Cafarnaum, porventura serás elevada até o céu? até o hades descerás; porque, se em Sodoma se tivessem operado os milagres que em ti se operaram, teria ela permanecido até hoje.' },
      { v: 24, en: 'But I tell you that it will be more tolerable for the land of Sodom, on the day of judgment, than for you.”', pt: 'Contudo, eu vos digo que no dia do juízo haverá menos rigor para a terra de Sodoma do que para ti.' },
      { v: 25, en: 'At that time, Jesus answered, “I thank you, Father, Lord of heaven and earth, that you hid these things from the wise and understanding, and revealed them to infants.', pt: 'Naquele tempo falou Jesus, dizendo: Graças te dou, ó Pai, Senhor do céu e da terra, porque ocultaste estas coisas aos sábios e entendidos, e as revelaste aos pequeninos.' },
      { v: 26, en: 'Yes, Father, for so it was well-pleasing in your sight.', pt: 'Sim, ó Pai, porque assim foi do teu agrado.' },
      { v: 27, en: 'All things have been delivered to me by my Father. No one knows the Son, except the Father; neither does anyone know the Father, except the Son, and he to whom the Son desires to reveal him.', pt: 'Todas as coisas me foram entregues por meu Pai; e ninguém conhece plenamente o Filho, senão o Pai; e ninguém conhece plenamente o Pai, senão o Filho, e aquele a quem o Filho o quiser revelar.' },
      { v: 28, en: '“Come to me, all you who labor and are heavily burdened, and I will give you rest.', pt: 'Vinde a mim, todos os que estai cansados e oprimidos, e eu vos aliviarei.' },
      { v: 29, en: 'Take my yoke upon you, and learn from me, for I am gentle and humble in heart; and you will find rest for your souls.', pt: 'Tomai sobre vós o meu jugo, e aprendei de mim, que sou manso e humilde de coração; e achareis descanso para as vossas almas.' },
      { v: 30, en: 'For my yoke is easy, and my burden is light.”', pt: 'Porque o meu jugo é suave, e o meu fardo e leve.' },
    ],
    12: [
      { v: 1, en: 'At that time, Jesus went on the Sabbath day through the grain fields. His disciples were hungry and began to pluck heads of grain and to eat.', pt: 'Naquele tempo passou Jesus pelas searas num dia de sábado; e os seus discípulos, sentindo fome, começaram a colher espigas, e a comer.' },
      { v: 2, en: 'But the Pharisees, when they saw it, said to him, “Behold, your disciples do what is not lawful to do on the Sabbath.”', pt: 'Os fariseus, vendo isso, disseram-lhe: Eis que os teus discípulos estão fazendo o que não é lícito fazer no sábado.' },
      { v: 3, en: 'But he said to them, “Haven’t you read what David did, when he was hungry, and those who were with him;', pt: 'Ele, porém, lhes disse: Acaso não lestes o que fez Davi, quando teve fome, ele e seus companheiros?' },
      { v: 4, en: 'how he entered into God’s house, and ate the show bread, which was not lawful for him to eat, neither for those who were with him, but only for the priests?', pt: 'Como entrou na casa de Deus, e como eles comeram os pães da proposição, que não lhe era lícito comer, nem a seus companheiros, mas somente aos sacerdotes?' },
      { v: 5, en: 'Or have you not read in the law, that on the Sabbath day, the priests in the temple profane the Sabbath, and are guiltless?', pt: 'Ou não lestes na lei que, aos sábados, os sacerdotes no templo violam o sábado, e ficam sem culpa?' },
      { v: 6, en: 'But I tell you that one greater than the temple is here.', pt: 'Digo-vos, porém, que aqui está o que é maior do que o templo.' },
      { v: 7, en: 'But if you had known what this means, ‘I desire mercy, and not sacrifice,’ you wouldn’t have condemned the guiltless.', pt: 'Mas, se vós soubésseis o que significa: Misericórdia quero, e não sacrifícios, não condenaríeis os inocentes.' },
      { v: 8, en: 'For the Son of Man is Lord of the Sabbath.”', pt: 'Porque o Filho do homem até do sábado é o Senhor.' },
      { v: 9, en: 'He departed there, and went into their synagogue.', pt: 'Partindo dali, entrou Jesus na sinagoga deles.' },
      { v: 10, en: 'And behold there was a man with a withered hand. They asked him, “Is it lawful to heal on the Sabbath day?” that they might accuse him.', pt: 'E eis que estava ali um homem que tinha uma das mãos atrofiadas; e eles, para poderem acusar a Jesus, o interrogaram, dizendo: É lícito curar nos sábados?' },
      { v: 11, en: 'He said to them, “What man is there among you, who has one sheep, and if this one falls into a pit on the Sabbath day, won’t he grab on to it, and lift it out?', pt: 'E ele lhes disse: Qual dentre vós será o homem que, tendo uma só ovelha, se num sábado ela cair numa cova, não há de lançar mão dela, e tirá-la?' },
      { v: 12, en: 'Of how much more value then is a man than a sheep! Therefore it is lawful to do good on the Sabbath day.”', pt: 'Ora, quanto mais vale um homem do que uma ovelha! Portanto, é lícito fazer bem nos sábados.' },
      { v: 13, en: 'Then he told the man, “Stretch out your hand.” He stretched it out; and it was restored whole, just like the other.', pt: 'Então disse àquele homem: estende a tua mão. E ele a estendeu, e lhe foi restituída sã como a outra.' },
      { v: 14, en: 'But the Pharisees went out, and conspired against him, how they might destroy him.', pt: 'Os fariseus, porém, saindo dali, tomaram conselho contra ele, para o matarem.' },
      { v: 15, en: 'Jesus, perceiving that, withdrew from there. Great multitudes followed him; and he healed them all,', pt: 'Jesus, percebendo isso, retirou-se dali. Acompanharam-no muitos; e ele curou a todos,' },
      { v: 16, en: 'and commanded them that they should not make him known:', pt: 'e advertiu-lhes que não o dessem a conhecer;' },
      { v: 17, en: 'that it might be fulfilled which was spoken through Isaiah the prophet, saying,', pt: 'para que se cumprisse o que foi dito pelo profeta Isaías:' },
      { v: 18, en: '“Behold, my servant whom I have chosen; my beloved in whom my soul is well pleased: I will put my Spirit on him. He will proclaim justice to the nations.', pt: 'Eis aqui o meu servo que escolhi, o meu amado em quem a minha alma se compraz; porei sobre ele o meu espírito, e ele anunciará aos gentios o juízo.' },
      { v: 19, en: 'He will not strive, nor shout; neither will anyone hear his voice in the streets.', pt: 'Não contenderá, nem clamará, nem se ouvirá pelas ruas a sua voz.' },
      { v: 20, en: 'He won’t break a bruised reed. He won’t quench a smoking flax, until he leads justice to victory.', pt: 'Não esmagará a cana quebrada, e não apagará o morrão que fumega, até que faça triunfar o juízo;' },
      { v: 21, en: 'In his name, the nations will hope.”', pt: 'e no seu nome os gentios esperarão.' },
      { v: 22, en: 'Then one possessed by a demon, blind and mute, was brought to him and he healed him, so that the blind and mute man both spoke and saw.', pt: 'Trouxeram-lhe então um endemoninhado cego e mudo; e ele o curou, de modo que o mudo falava e via.' },
      { v: 23, en: 'All the multitudes were amazed, and said, “Can this be the son of David?”', pt: 'E toda a multidão, maravilhada, dizia: É este, porventura, o Filho de Davi?' },
      { v: 24, en: 'But when the Pharisees heard it, they said, “This man does not cast out demons, except by Beelzebul, the prince of the demons.”', pt: 'Mas os fariseus, ouvindo isto, disseram: Este não expulsa os demônios senão por Belzebu, príncipe dos demônios.' },
      { v: 25, en: 'Knowing their thoughts, Jesus said to them, “Every kingdom divided against itself is brought to desolation, and every city or house divided against itself will not stand.', pt: 'Jesus, porém, conhecendo-lhes os pensamentos, disse-lhes: Todo reino dividido contra si mesmo é devastado; e toda cidade, ou casa, dividida contra si mesma não subsistirá.' },
      { v: 26, en: 'If Satan casts out Satan, he is divided against himself. How then will his kingdom stand?', pt: 'Ora, se Satanás expulsa a Satanás, está dividido contra si mesmo; como subsistirá, pois, o seus reino?' },
      { v: 27, en: 'If I by Beelzebul cast out demons, by whom do your children cast them out? Therefore they will be your judges.', pt: 'E, se eu expulso os demônios por Belzebu, por quem os expulsam os vossos filhos? Por isso, eles mesmos serão os vossos juízes.' },
      { v: 28, en: 'But if I by the Spirit of God cast out demons, then God’s Kingdom has come upon you.', pt: 'Mas, se é pelo Espírito de Deus que eu expulso os demônios, logo é chegado a vós o reino de Deus.' },
      { v: 29, en: 'Or how can one enter into the house of the strong man, and plunder his goods, unless he first bind the strong man? Then he will plunder his house.', pt: 'Ou, como pode alguém entrar na casa do valente, e roubar-lhe os bens, se primeiro não amarrar o valente? e então lhe saquear a casa.' },
      { v: 30, en: '“He who is not with me is against me, and he who doesn’t gather with me, scatters.', pt: 'Quem não é comigo é contra mim; e quem comigo não ajunta, espalha.' },
      { v: 31, en: 'Therefore I tell you, every sin and blasphemy will be forgiven men, but the blasphemy against the Spirit will not be forgiven men.', pt: 'Portanto vos digo: Todo pecado e blasfêmia se perdoará aos homens; mas a blasfêmia contra o Espírito não será perdoada.' },
      { v: 32, en: 'Whoever speaks a word against the Son of Man, it will be forgiven him; but whoever speaks against the Holy Spirit, it will not be forgiven him, neither in this age, nor in that which is to come.', pt: 'Se alguém disser alguma palavra contra o Filho do homem, isso lhe será perdoado; mas se alguém falar contra o Espírito Santo, não lhe será perdoado, nem neste mundo, nem no vindouro.' },
      { v: 33, en: '“Either make the tree good, and its fruit good, or make the tree corrupt, and its fruit corrupt; for the tree is known by its fruit.', pt: 'Ou fazei a árvore boa, e o seu fruto bom; ou fazei a árvore má, e o seu fruto mau; porque pelo fruto se conhece a árvore.' },
      { v: 34, en: 'You offspring of vipers, how can you, being evil, speak good things? For out of the abundance of the heart, the mouth speaks.', pt: 'Raça de víboras! como podeis vós falar coisas boas, sendo maus? pois do que há em abundância no coração, disso fala a boca.' },
      { v: 35, en: 'The good man out of his good treasure brings out good things, and the evil man out of his evil treasure brings out evil things.', pt: 'O homem bom, do seu bom tesouro tira coisas boas, e o homem mau do mau tesouro tira coisas más.' },
      { v: 36, en: 'I tell you that every idle word that men speak, they will give account of it in the day of judgment.', pt: 'Digo-vos, pois, que de toda palavra fútil que os homens disserem, hão de dar conta no dia do juízo.' },
      { v: 37, en: 'For by your words you will be justified, and by your words you will be condemned.”', pt: 'Porque pelas tuas palavras serás justificado, e pelas tuas palavras serás condenado.' },
      { v: 38, en: 'Then certain of the scribes and Pharisees answered, “Teacher, we want to see a sign from you.”', pt: 'Então alguns dos escribas e dos fariseus, tomando a palavra, disseram: Mestre, queremos ver da tua parte algum sinal.' },
      { v: 39, en: 'But he answered them, “An evil and adulterous generation seeks after a sign, but no sign will be given to it but the sign of Jonah the prophet.', pt: 'Mas ele lhes respondeu: Uma geração má e adúltera pede um sinal; e nenhum sinal se lhe dará, senão o do profeta Jonas;' },
      { v: 40, en: 'For as Jonah was three days and three nights in the belly of the whale, so will the Son of Man be three days and three nights in the heart of the earth.', pt: 'pois, como Jonas esteve três dias e três noites no ventre do grande peixe, assim estará o Filho do homem três dias e três noites no seio da terra.' },
      { v: 41, en: 'The men of Nineveh will stand up in the judgment with this generation, and will condemn it, for they repented at the preaching of Jonah; and behold, someone greater than Jonah is here.', pt: 'Os ninivitas se levantarão no juízo com esta geração, e a condenarão; porque se arrependeram com a pregação de Jonas. E eis aqui quem é maior do que Jonas.' },
      { v: 42, en: 'The queen of the south will rise up in the judgment with this generation, and will condemn it, for she came from the ends of the earth to hear the wisdom of Solomon; and behold, someone greater than Solomon is here.', pt: 'A rainha do sul se levantará no juízo com esta geração, e a condenará; porque veio dos confins da terra para ouvir a sabedoria de Salomão. E eis aqui quem é maior do que Salomão.' },
      { v: 43, en: 'When an unclean spirit has gone out of a man, he passes through waterless places, seeking rest, and doesn’t find it.', pt: 'Ora, havendo o espírito imundo saido do homem, anda por lugares áridos, buscando repouso, e não o encontra.' },
      { v: 44, en: 'Then he says, ‘I will return into my house from which I came out,’ and when he has come back, he finds it empty, swept, and put in order.', pt: 'Então diz: Voltarei para minha casa, donde saí. E, chegando, acha-a desocupada, varrida e adornada.' },
      { v: 45, en: 'Then he goes, and takes with himself seven other spirits more evil than he is, and they enter in and dwell there. The last state of that man becomes worse than the first. Even so will it be also to this evil generation.”', pt: 'Então vai e leva consigo outros sete espíritos piores do que ele e, entretanto, habitam ali; e o último estado desse homem vem a ser pior do que o primeiro. Assim há de acontecer também a esta geração perversa.' },
      { v: 46, en: 'While he was yet speaking to the multitudes, behold, his mother and his brothers stood outside, seeking to speak to him.', pt: 'Enquanto ele ainda falava às multidões, estavam do lado de fora sua mãe e seus irmãos, procurando falar-lhe.' },
      { v: 47, en: 'One said to him, “Behold, your mother and your brothers stand outside, seeking to speak to you.”', pt: 'Disse-lhe alguém: Eis que estão ali fora tua mãe e teus irmãos, e procuram falar contigo.' },
      { v: 48, en: 'But he answered him who spoke to him, “Who is my mother? Who are my brothers?”', pt: 'Ele, porém, respondeu ao que lhe falava: Quem é minha mãe? e quem são meus irmãos?' },
      { v: 49, en: 'He stretched out his hand towards his disciples, and said, “Behold, my mother and my brothers!', pt: 'E, estendendo a mão para os seus discípulos disse: Eis aqui minha mãe e meus irmãos.' },
      { v: 50, en: 'For whoever does the will of my Father who is in heaven, he is my brother, and sister, and mother.”', pt: 'Pois qualquer que fizer a vontade de meu Pai que está nos céus, esse é meu irmão, irmã e mãe.' },
    ],
    13: [
      { v: 1, en: 'On that day Jesus went out of the house, and sat by the seaside.', pt: 'No mesmo dia, tendo Jesus saído de casa, sentou-se à beira do mar;' },
      { v: 2, en: 'Great multitudes gathered to him, so that he entered into a boat, and sat, and all the multitude stood on the beach.', pt: 'e reuniram-se a ele grandes multidões, de modo que entrou num barco, e se sentou; e todo o povo estava em pé na praia.' },
      { v: 3, en: 'He spoke to them many things in parables, saying, “Behold, a farmer went out to sow.', pt: 'E falou-lhes muitas coisas por parábolas, dizendo: Eis que o semeador saiu a semear.' },
      { v: 4, en: 'As he sowed, some seeds fell by the roadside, and the birds came and devoured them.', pt: 'e quando semeava, uma parte da semente caiu à beira do caminho, e vieram as aves e comeram.' },
      { v: 5, en: 'Others fell on rocky ground, where they didn’t have much soil, and immediately they sprang up, because they had no depth of earth.', pt: 'E outra parte caiu em lugares pedregosos, onde não havia muita terra: e logo nasceu, porque não tinha terra profunda;' },
      { v: 6, en: 'When the sun had risen, they were scorched. Because they had no root, they withered away.', pt: 'mas, saindo o sol, queimou-se e, por não ter raiz, secou-se.' },
      { v: 7, en: 'Others fell among thorns. The thorns grew up and choked them.', pt: 'E outra caiu entre espinhos; e os espinhos cresceram e a sufocaram.' },
      { v: 8, en: 'Others fell on good soil, and yielded fruit: some one hundred times as much, some sixty, and some thirty.', pt: 'Mas outra caiu em boa terra, e dava fruto, um a cem, outro a sessenta e outro a trinta por um.' },
      { v: 9, en: 'He who has ears to hear, let him hear.”', pt: 'Quem tem ouvidos, ouça.' },
      { v: 10, en: 'The disciples came, and said to him, “Why do you speak to them in parables?”', pt: 'E chegando-se a ele os discípulos, perguntaram-lhe: Por que lhes falas por parábolas?' },
      { v: 11, en: 'He answered them, “To you it is given to know the mysteries of the Kingdom of Heaven, but it is not given to them.', pt: 'Respondeu-lhes Jesus: Porque a vós é dado conhecer os mistérios do reino dos céus, mas a eles não lhes é dado;' },
      { v: 12, en: 'For whoever has, to him will be given, and he will have abundance, but whoever doesn’t have, from him will be taken away even that which he has.', pt: 'pois ao que tem, dar-se-lhe-á, e terá em abundância; mas ao que não tem, até aquilo que tem lhe será tirado.' },
      { v: 13, en: 'Therefore I speak to them in parables, because seeing they don’t see, and hearing, they don’t hear, neither do they understand.', pt: 'Por isso lhes falo por parábolas; porque eles, vendo, não vêem; e ouvindo, não ouvem nem entendem.' },
      { v: 14, en: 'In them the prophecy of Isaiah is fulfilled, which says, ‘By hearing you will hear, and will in no way understand; Seeing you will see, and will in no way perceive:', pt: 'E neles se cumpre a profecia de Isaías, que diz: Ouvindo, ouvireis, e de maneira alguma entendereis; e, vendo, vereis, e de maneira alguma percebereis.' },
      { v: 15, en: 'for this people’s heart has grown callous, their ears are dull of hearing, they have closed their eyes; or else perhaps they might perceive with their eyes, hear with their ears, understand with their heart, and would turn again; and I would heal them.’', pt: 'Porque o coração deste povo se endureceu, e com os ouvidos ouviram tardamente, e fecharam os olhos, para que não vejam com os olhos, nem ouçam com os ouvidos, nem entendam com o coração, nem se convertam, e eu os cure.' },
      { v: 16, en: '“But blessed are your eyes, for they see; and your ears, for they hear.', pt: 'Mas bem-aventurados os vossos olhos, porque vêem, e os vossos ouvidos, porque ouvem.' },
      { v: 17, en: 'For most certainly I tell you that many prophets and righteous men desired to see the things which you see, and didn’t see them; and to hear the things which you hear, and didn’t hear them.', pt: 'Pois, em verdade vos digo que muitos profetas e justos desejaram ver o que vedes, e não o viram; e ouvir o que ouvis, e não o ouviram.' },
      { v: 18, en: '“Hear, then, the parable of the farmer.', pt: 'Ouvi, pois, vós a parábola do semeador.' },
      { v: 19, en: 'When anyone hears the word of the Kingdom, and doesn’t understand it, the evil one comes, and snatches away that which has been sown in his heart. This is what was sown by the roadside.', pt: 'A todo o que ouve a palavra do reino e não a entende, vem o Maligno e arrebata o que lhe foi semeado no coração; este é o que foi semeado à beira do caminho.' },
      { v: 20, en: 'What was sown on the rocky places, this is he who hears the word, and immediately with joy receives it;', pt: 'E o que foi semeado nos lugares pedregosos, este é o que ouve a palavra, e logo a recebe com alegria;' },
      { v: 21, en: 'yet he has no root in himself, but endures for a while. When oppression or persecution arises because of the word, immediately he stumbles.', pt: 'mas não tem raiz em si mesmo, antes é de pouca duração; e sobrevindo a angústia e a perseguição por causa da palavra, logo se escandaliza.' },
      { v: 22, en: 'What was sown among the thorns, this is he who hears the word, but the cares of this age and the deceitfulness of riches choke the word, and he becomes unfruitful.', pt: 'E o que foi semeado entre os espinhos, este é o que ouve a palavra; mas os cuidados deste mundo e a sedução das riquezas sufocam a palavra, e ela fica infrutífera.' },
      { v: 23, en: 'What was sown on the good ground, this is he who hears the word, and understands it, who most certainly bears fruit, and produces, some one hundred times as much, some sixty, and some thirty.”', pt: 'Mas o que foi semeado em boa terra, este é o que ouve a palavra, e a entende; e dá fruto, e um produz cem, outro sessenta, e outro trinta.' },
      { v: 24, en: 'He set another parable before them, saying, “The Kingdom of Heaven is like a man who sowed good seed in his field,', pt: 'Propôs-lhes outra parábola, dizendo: O reino dos céus é semelhante ao homem que semeou boa semente no seu campo;' },
      { v: 25, en: 'but while people slept, his enemy came and sowed darnel weeds also among the wheat, and went away.', pt: 'mas, enquanto os homens dormiam, veio o inimigo dele, semeou joio no meio do trigo, e retirou-se.' },
      { v: 26, en: 'But when the blade sprang up and produced fruit, then the darnel weeds appeared also.', pt: 'Quando, porém, a erva cresceu e começou a espigar, então apareceu também o joio.' },
      { v: 27, en: 'The servants of the householder came and said to him, ‘Sir, didn’t you sow good seed in your field? Where did these darnel weeds come from?’', pt: 'Chegaram, pois, os servos do proprietário, e disseram-lhe: Senhor, não semeaste no teu campo boa semente? Donde, pois, vem o joio?' },
      { v: 28, en: '“He said to them, ‘An enemy has done this.’ “The servants asked him, ‘Do you want us to go and gather them up?’', pt: 'Respondeu-lhes: Algum inimigo é quem fez isso. E os servos lhe disseram: Queres, pois, que vamos arrancá-lo?' },
      { v: 29, en: '“But he said, ‘No, lest perhaps while you gather up the darnel weeds, you root up the wheat with them.', pt: 'Ele, porém, disse: Não; para que, ao colher o joio, não arranqueis com ele também o trigo.' },
      { v: 30, en: 'Let both grow together until the harvest, and in the harvest time I will tell the reapers, “First, gather up the darnel weeds, and bind them in bundles to burn them; but gather the wheat into my barn.”’”', pt: 'Deixai crescer ambos juntos até a ceifa; e, por ocasião da ceifa, direi aos ceifeiros: Ajuntai primeiro o joio, e atai-o em molhos para o queimar; o trigo, porém, recolhei-o no meu celeiro.' },
      { v: 31, en: 'He set another parable before them, saying, “The Kingdom of Heaven is like a grain of mustard seed, which a man took, and sowed in his field;', pt: 'Propôs-lhes outra parábola, dizendo: O reino dos céus é semelhante a um grão de mostarda que um homem tomou, e semeou no seu campo;' },
      { v: 32, en: 'which indeed is smaller than all seeds. But when it is grown, it is greater than the herbs, and becomes a tree, so that the birds of the air come and lodge in its branches.”', pt: 'o qual é realmente a menor de todas as sementes; mas, depois de ter crescido, é a maior das hortaliças, e faz-se árvore, de sorte que vêm as aves do céu, e se aninham nos seus ramos.' },
      { v: 33, en: 'He spoke another parable to them. “The Kingdom of Heaven is like yeast, which a woman took, and hid in three measures of meal, until it was all leavened.”', pt: 'Outra parábola lhes disse: O reino dos céus é semelhante ao fermento que uma mulher tomou e misturou com três medidas de farinha, até ficar tudo levedado.' },
      { v: 34, en: 'Jesus spoke all these things in parables to the multitudes; and without a parable, he didn’t speak to them,', pt: 'Todas estas coisas falou Jesus às multidões por parábolas, e sem parábolas nada lhes falava;' },
      { v: 35, en: 'that it might be fulfilled which was spoken through the prophet, saying, “I will open my mouth in parables; I will utter things hidden from the foundation of the world.”', pt: 'para que se cumprisse o que foi dito pelo profeta: Abrirei em parábolas a minha boca; publicarei coisas ocultas desde a fundação do mundo.' },
      { v: 36, en: 'Then Jesus sent the multitudes away, and went into the house. His disciples came to him, saying, “Explain to us the parable of the darnel weeds of the field.”', pt: 'Então Jesus, deixando as multidões, entrou em casa. E chegaram-se a ele os seus discípulos, dizendo: Explica-nos a parábola do joio do campo.' },
      { v: 37, en: 'He answered them, “He who sows the good seed is the Son of Man,', pt: 'E ele, respondendo, disse: O que semeia a boa semente é o Filho do homem;' },
      { v: 38, en: 'the field is the world; and the good seed, these are the children of the Kingdom; and the darnel weeds are the children of the evil one.', pt: 'o campo é o mundo; a boa semente são os filhos do reino; o o joio são os filhos do maligno;' },
      { v: 39, en: 'The enemy who sowed them is the devil. The harvest is the end of the age, and the reapers are angels.', pt: 'o inimigo que o semeou é o Diabo; a ceifa é o fim do mundo, e os celeiros são os anjos.' },
      { v: 40, en: 'As therefore the darnel weeds are gathered up and burned with fire; so will it be at the end of this age.', pt: 'Pois assim como o joio é colhido e queimado no fogo, assim será no fim do mundo.' },
      { v: 41, en: 'The Son of Man will send out his angels, and they will gather out of his Kingdom all things that cause stumbling, and those who do iniquity,', pt: 'Mandará o Filho do homem os seus anjos, e eles ajuntarão do seu reino todos os que servem de tropeço, e os que praticam a iniquidade,' },
      { v: 42, en: 'and will cast them into the furnace of fire. There will be weeping and the gnashing of teeth.', pt: 'e lançá-los-ão na fornalha de fogo; ali haverá choro e ranger de dentes.' },
      { v: 43, en: 'Then the righteous will shine like the sun in the Kingdom of their Father. He who has ears to hear, let him hear.', pt: 'Então os justos resplandecerão como o sol, no reino de seu Pai. Quem tem ouvidos, ouça.' },
      { v: 44, en: '“Again, the Kingdom of Heaven is like treasure hidden in the field, which a man found, and hid. In his joy, he goes and sells all that he has, and buys that field.', pt: 'O reino dos céus é semelhante a um tesouro escondido no campo, que um homem, ao descobrí-lo, esconde; então, movido de gozo, vai, vende tudo quanto tem, e compra aquele campo.' },
      { v: 45, en: '“Again, the Kingdom of Heaven is like a man who is a merchant seeking fine pearls,', pt: 'Outrossim, o reino dos céus é semelhante a um negociante que buscava boas pérolas;' },
      { v: 46, en: 'who having found one pearl of great price, he went and sold all that he had, and bought it.', pt: 'e encontrando uma pérola de grande valor, foi, vendeu tudo quanto tinha, e a comprou.' },
      { v: 47, en: '“Again, the Kingdom of Heaven is like a dragnet, that was cast into the sea, and gathered some fish of every kind,', pt: 'Igualmente, o reino dos céus é semelhante a uma rede lançada ao mar, e que apanhou toda espécie de peixes.' },
      { v: 48, en: 'which, when it was filled, they drew up on the beach. They sat down, and gathered the good into containers, but the bad they threw away.', pt: 'E, quando cheia, puxaram-na para a praia; e, sentando-se, puseram os bons em cestos; os ruins, porém, lançaram fora.' },
      { v: 49, en: 'So will it be in the end of the world. The angels will come and separate the wicked from among the righteous,', pt: 'Assim será no fim do mundo: sairão os anjos, e separarão os maus dentre os justos,' },
      { v: 50, en: 'and will cast them into the furnace of fire. There will be the weeping and the gnashing of teeth.”', pt: 'e lançá-los-ão na fornalha de fogo; ali haverá choro e ranger de dentes.' },
      { v: 51, en: 'Jesus said to them, “Have you understood all these things?” They answered him, “Yes, Lord.”', pt: 'Entendestes todas estas coisas? Disseram-lhe eles: Entendemos.' },
      { v: 52, en: 'He said to them, “Therefore every scribe who has been made a disciple in the Kingdom of Heaven is like a man who is a householder, who brings out of his treasure new and old things.”', pt: 'E disse-lhes: Por isso, todo escriba que se fez discípulo do reino dos céus é semelhante a um homem, proprietário, que tira do seu tesouro coisas novas e velhas.' },
      { v: 53, en: 'When Jesus had finished these parables, he departed from there.', pt: 'E Jesus, tendo concluido estas parábolas, se retirou dali.' },
      { v: 54, en: 'Coming into his own country, he taught them in their synagogue, so that they were astonished, and said, “Where did this man get this wisdom, and these mighty works?', pt: 'E, chegando à sua terra, ensinava o povo na sinagoga, de modo que este se maravilhava e dizia: Donde lhe vem esta sabedoria, e estes poderes milagrosos?' },
      { v: 55, en: 'Isn’t this the carpenter’s son? Isn’t his mother called Mary, and his brothers, James, Joses, Simon, and Judas?', pt: 'Não é este o filho do carpinteiro? e não se chama sua mãe Maria, e seus irmãos Tiago, José, Simão, e Judas?' },
      { v: 56, en: 'Aren’t all of his sisters with us? Where then did this man get all of these things?”', pt: 'E não estão entre nós todas as suas irmãs? Donde lhe vem, pois, tudo isto?' },
      { v: 57, en: 'They were offended by him. But Jesus said to them, “A prophet is not without honor, except in his own country, and in his own house.”', pt: 'E escandalizavam-se dele. Jesus, porém, lhes disse: Um profeta não fica sem honra senão na sua terra e na sua própria casa.' },
      { v: 58, en: 'He didn’t do many mighty works there because of their unbelief.', pt: 'E não fez ali muitos milagres, por causa da incredulidade deles.' },
    ],
    14: [
      { v: 1, en: 'At that time, Herod the tetrarch heard the report concerning Jesus,', pt: 'Naquele tempo Herodes, o tetrarca, ouviu a fama de Jesus,' },
      { v: 2, en: 'and said to his servants, “This is John the Baptizer. He is risen from the dead. That is why these powers work in him.”', pt: 'e disse aos seus cortesãos: Este é João, o Batista; ele ressuscitou dentre os mortos, e por isso estes poderes milagrosos operam nele.' },
      { v: 3, en: 'For Herod had laid hold of John, and bound him, and put him in prison for the sake of Herodias, his brother Philip’s wife.', pt: 'Pois Herodes havia prendido a João, e, maniatando-o, o guardara no cárcere, por causa de Herodias, mulher de seu irmão Felipe;' },
      { v: 4, en: 'For John said to him, “It is not lawful for you to have her.”', pt: 'porque João lhe dizia: Não te é lícito possuí-la.' },
      { v: 5, en: 'When he would have put him to death, he feared the multitude, because they counted him as a prophet.', pt: 'E queria matá-lo, mas temia o povo; porque o tinham como profeta.' },
      { v: 6, en: 'But when Herod’s birthday came, the daughter of Herodias danced among them and pleased Herod.', pt: 'Festejando-se, porém, o dia natalício de Herodes, a filha de Herodias dançou no meio dos convivas, e agradou a Herodes,' },
      { v: 7, en: 'Whereupon he promised with an oath to give her whatever she should ask.', pt: 'pelo que este prometeu com juramento dar-lhe tudo o que pedisse.' },
      { v: 8, en: 'She, being prompted by her mother, said, “Give me here on a platter the head of John the Baptizer.”', pt: 'E instigada por sua mãe, disse ela: Dá-me aqui num prato a cabeça de João, o Batista.' },
      { v: 9, en: 'The king was grieved, but for the sake of his oaths, and of those who sat at the table with him, he commanded it to be given,', pt: 'Entristeceu-se, então, o rei; mas, por causa do juramento, e dos que estavam à mesa com ele, ordenou que se lhe desse,' },
      { v: 10, en: 'and he sent and beheaded John in the prison.', pt: 'e mandou degolar a João no cárcere;' },
      { v: 11, en: 'His head was brought on a platter, and given to the young lady: and she brought it to her mother.', pt: 'e a cabeça foi trazida num prato, e dada à jovem, e ela a levou para a sua mãe.' },
      { v: 12, en: 'His disciples came, and took the body, and buried it; and they went and told Jesus.', pt: 'Então vieram os seus discípulos, levaram o corpo e o sepultaram; e foram anunciá-lo a Jesus.' },
      { v: 13, en: 'Now when Jesus heard this, he withdrew from there in a boat, to a deserted place apart. When the multitudes heard it, they followed him on foot from the cities.', pt: 'Jesus, ouvindo isto, retirou-se dali num barco, para um, lugar deserto, à parte; e quando as multidões o souberam, seguiram-no a pé desde as cidades.' },
      { v: 14, en: 'Jesus went out, and he saw a great multitude. He had compassion on them, and healed their sick.', pt: 'E ele, ao desembarcar, viu uma grande multidão; e, compadecendo-se dela, curou os seus enfermos.' },
      { v: 15, en: 'When evening had come, his disciples came to him, saying, “This place is deserted, and the hour is already late. Send the multitudes away, that they may go into the villages, and buy themselves food.”', pt: 'Chegada a tarde, aproximaram-se dele os discípulos, dizendo: O lugar é deserto, e a hora é já passada; despede as multidões, para que vão às aldeias, e comprem o que comer.' },
      { v: 16, en: 'But Jesus said to them, “They don’t need to go away. You give them something to eat.”', pt: 'Jesus, porém, lhes disse: Não precisam ir embora; dai-lhes vós de comer.' },
      { v: 17, en: 'They told him, “We only have here five loaves and two fish.”', pt: 'Então eles lhe disseram: Não temos aqui senão cinco pães e dois peixes.' },
      { v: 18, en: 'He said, “Bring them here to me.”', pt: 'E ele disse: trazei-mos aqui.' },
      { v: 19, en: 'He commanded the multitudes to sit down on the grass; and he took the five loaves and the two fish, and looking up to heaven, he blessed, broke and gave the loaves to the disciples, and the disciples gave to the multitudes.', pt: 'Tendo mandado às multidões que se reclinassem sobre a relva, tomou os cinco pães e os dois peixes e, erguendo os olhos ao céu, os abençoou; e partindo os pães, deu-os aos discípulos, e os discípulos às multidões.' },
      { v: 20, en: 'They all ate, and were filled. They took up twelve baskets full of that which remained left over from the broken pieces.', pt: 'Todos comeram e se fartaram; e dos pedaços que sobejaram levantaram doze cestos cheios.' },
      { v: 21, en: 'Those who ate were about five thousand men, besides women and children.', pt: 'Ora, os que comeram foram cerca de cinco mil homens, além de mulheres e crianças.' },
      { v: 22, en: 'Immediately Jesus made the disciples get into the boat, and to go ahead of him to the other side, while he sent the multitudes away.', pt: 'Logo em seguida obrigou os seus discípulos a entrar no barco, e passar adiante dele para o outro lado, enquanto ele despedia as multidões.' },
      { v: 23, en: 'After he had sent the multitudes away, he went up into the mountain by himself to pray. When evening had come, he was there alone.', pt: 'Tendo-as despedido, subiu ao monte para orar à parte. Ao anoitecer, estava ali sozinho.' },
      { v: 24, en: 'But the boat was now in the middle of the sea, distressed by the waves, for the wind was contrary.', pt: 'Entrementes, o barco já estava a muitos estádios da terra, açoitado pelas ondas; porque o vento era contrário.' },
      { v: 25, en: 'In the fourth watch of the night, Jesus came to them, walking on the sea.', pt: 'Â quarta vigília da noite, foi Jesus ter com eles, andando sobre o mar.' },
      { v: 26, en: 'When the disciples saw him walking on the sea, they were troubled, saying, “It’s a ghost!” and they cried out for fear.', pt: 'Os discípulos, porém, ao vê-lo andando sobre o mar, assustaram-se e disseram: É um fantasma. E gritaram de medo.' },
      { v: 27, en: 'But immediately Jesus spoke to them, saying, “Cheer up! It is I! Don’t be afraid.”', pt: 'Jesus, porém, imediatamente lhes falou, dizendo: Tende ânimo; sou eu; não temais.' },
      { v: 28, en: 'Peter answered him and said, “Lord, if it is you, command me to come to you on the waters.”', pt: 'Respondeu-lhe Pedro: Senhor! se és tu, manda-me ir ter contigo sobre as águas.' },
      { v: 29, en: 'He said, “Come!” Peter stepped down from the boat, and walked on the waters to come to Jesus.', pt: 'Disse-lhe ele: Vem. Pedro, descendo do barco, e andando sobre as águas, foi ao encontro de Jesus.' },
      { v: 30, en: 'But when he saw that the wind was strong, he was afraid, and beginning to sink, he cried out, saying, “Lord, save me!”', pt: 'Mas, sentindo o vento, teve medo; e, começando a submergir, clamou: Senhor, salva-me.' },
      { v: 31, en: 'Immediately Jesus stretched out his hand, took hold of him, and said to him, “You of little faith, why did you doubt?”', pt: 'Imediatamente estendeu Jesus a mão, segurou-o, e disse-lhe: Homem de pouca fé, por que duvidaste?' },
      { v: 32, en: 'When they got up into the boat, the wind ceased.', pt: 'E logo que subiram para o barco, o vento cessou.' },
      { v: 33, en: 'Those who were in the boat came and worshiped him, saying, “You are truly the Son of God!”', pt: 'Então os que estavam no barco adoraram-no, dizendo: Verdadeiramente tu és Filho de Deus.' },
      { v: 34, en: 'When they had crossed over, they came to the land of Gennesaret.', pt: 'Ora, terminada a travessia, chegaram à terra em Genezaré.' },
      { v: 35, en: 'When the people of that place recognized him, they sent into all that surrounding region, and brought to him all who were sick;', pt: 'Quando os homens daquele lugar o reconheceram, mandaram por toda aquela circunvizinhança, e trouxeram-lhe todos os enfermos;' },
      { v: 36, en: 'and they begged him that they might just touch the fringe of his garment. As many as touched it were made whole.', pt: 'e rogaram-lhe que apenas os deixasse tocar a orla do seu manto; e todos os que a tocaram ficaram curados.' },
    ],
    15: [
      { v: 1, en: 'Then Pharisees and scribes came to Jesus from Jerusalem, saying,', pt: 'Então chegaram a Jesus uns fariseus e escribas vindos de Jerusalém, e lhe perguntaram:' },
      { v: 2, en: '“Why do your disciples disobey the tradition of the elders? For they don’t wash their hands when they eat bread.”', pt: 'Por que transgridem os teus discípulos a tradição dos anciãos? pois não lavam as mãos, quando comem.' },
      { v: 3, en: 'He answered them, “Why do you also disobey the commandment of God because of your tradition?', pt: 'Ele, porém, respondendo, disse-lhes: E vós, por que transgredis o mandamento de Deus por causa da vossa tradição?' },
      { v: 4, en: 'For God commanded, ‘Honor your father and your mother,’ and, ‘He who speaks evil of father or mother, let him be put to death.’', pt: 'Pois Deus ordenou: Honra a teu pai e a tua mãe; e, Quem maldisser a seu pai ou a sua mãe, certamente morrerá.' },
      { v: 5, en: 'But you say, ‘Whoever may tell his father or his mother, “Whatever help you might otherwise have gotten from me is a gift devoted to God,”', pt: 'Mas vós dizeis: Qualquer que disser a seu pai ou a sua mãe: O que poderias aproveitar de mim é oferta ao Senhor; esse de modo algum terá de honrar a seu pai.' },
      { v: 6, en: 'he shall not honor his father or mother.’ You have made the commandment of God void because of your tradition.', pt: 'E assim por causa da vossa tradição invalidastes a palavra de Deus.' },
      { v: 7, en: 'You hypocrites! Well did Isaiah prophesy of you, saying,', pt: 'Hipócritas! bem profetizou Isaias a vosso respeito, dizendo:' },
      { v: 8, en: '‘These people draw near to me with their mouth, and honor me with their lips; but their heart is far from me.', pt: 'Este povo honra-me com os lábios; o seu coração, porém, está longe de mim.' },
      { v: 9, en: 'And in vain do they worship me, teaching as doctrine rules made by men.’”', pt: 'Mas em vão me adoram, ensinando doutrinas que são preceitos de homem.' },
      { v: 10, en: 'He summoned the multitude, and said to them, “Hear, and understand.', pt: 'E, clamando a si a multidão, disse-lhes: Ouvi, e entendei:' },
      { v: 11, en: 'That which enters into the mouth doesn’t defile the man; but that which proceeds out of the mouth, this defiles the man.”', pt: 'Não é o que entra pela boca que contamina o homem; mas o que sai da boca, isso é o que o contamina.' },
      { v: 12, en: 'Then the disciples came, and said to him, “Do you know that the Pharisees were offended, when they heard this saying?”', pt: 'Então os discípulos, aproximando-se dele, perguntaram-lhe: Sabes que os fariseus, ouvindo essas palavras, se escandalizaram?' },
      { v: 13, en: 'But he answered, “Every plant which my heavenly Father didn’t plant will be uprooted.', pt: 'Respondeu-lhes ele: Toda planta que meu Pai celestial não plantou será arrancada.' },
      { v: 14, en: 'Leave them alone. They are blind guides of the blind. If the blind guide the blind, both will fall into a pit.”', pt: 'Deixai-os; são guias cegos; ora, se um cego guiar outro cego, ambos cairão no barranco.' },
      { v: 15, en: 'Peter answered him, “Explain the parable to us.”', pt: 'E Pedro, tomando a palavra, disse-lhe: Explica-nos essa parábola.' },
      { v: 16, en: 'So Jesus said, “Do you also still not understand?', pt: 'Respondeu Jesus: Estai vós também ainda sem entender?' },
      { v: 17, en: 'Don’t you understand that whatever goes into the mouth passes into the belly, and then out of the body?', pt: 'Não compreendeis que tudo o que entra pela boca desce pelo ventre, e é lançado fora?' },
      { v: 18, en: 'But the things which proceed out of the mouth come out of the heart, and they defile the man.', pt: 'Mas o que sai da boca procede do coração; e é isso o que contamina o homem.' },
      { v: 19, en: 'For out of the heart come evil thoughts, murders, adulteries, sexual sins, thefts, false testimony, and blasphemies.', pt: 'Porque do coração procedem os maus pensamentos, homicídios, adultérios, prostituição, furtos, falsos testemunhos e blasfêmias.' },
      { v: 20, en: 'These are the things which defile the man; but to eat with unwashed hands doesn’t defile the man.”', pt: 'São estas as coisas que contaminam o homem; mas o comer sem lavar as mãos, isso não o contamina.' },
      { v: 21, en: 'Jesus went out from there, and withdrew into the region of Tyre and Sidon.', pt: 'Ora, partindo Jesus dali, retirou-se para as regiões de Tiro e Sidom.' },
      { v: 22, en: 'Behold, a Canaanite woman came out from those borders, and cried, saying, “Have mercy on me, Lord, you son of David! My daughter is severely possessed by a demon!”', pt: 'E eis que uma mulher cananéia, provinda daquelas cercania, clamava, dizendo: Senhor, Filho de Davi, tem compaixão de mim, que minha filha está horrivelmente endemoninhada.' },
      { v: 23, en: 'But he answered her not a word. His disciples came and begged him, saying, “Send her away; for she cries after us.”', pt: 'Contudo ele não lhe respondeu palavra. Chegando-se, pois, a ele os seus discípulos, rogavam-lhe, dizendo: Despede-a, porque vem clamando atrás de nós.' },
      { v: 24, en: 'But he answered, “I wasn’t sent to anyone but the lost sheep of the house of Israel.”', pt: 'Respondeu-lhes ele: Não fui enviado senão às ovelhas perdidas da casa de Israel.' },
      { v: 25, en: 'But she came and worshiped him, saying, “Lord, help me.”', pt: 'Então veio ela e, adorando-o, disse: Senhor, socorre-me.' },
      { v: 26, en: 'But he answered, “It is not appropriate to take the children’s bread and throw it to the dogs.”', pt: 'Ele, porém, respondeu: Não é bom tomar o pão dos filhos e lançá-lo aos cachorrinhos.' },
      { v: 27, en: 'But she said, “Yes, Lord, but even the dogs eat the crumbs which fall from their masters’ table.”', pt: 'Ao que ela disse: Sim, Senhor, mas até os cachorrinhos comem das migalhas que caem da mesa dos seus donos.' },
      { v: 28, en: 'Then Jesus answered her, “Woman, great is your faith! Be it done to you even as you desire.” And her daughter was healed from that hour.', pt: 'Então respondeu Jesus, e disse-lhe: ç mulher, grande é a tua fé! seja-te feito como queres. E desde aquela hora sua filha ficou sã.' },
      { v: 29, en: 'Jesus departed from there, and came near to the sea of Galilee; and he went up into the mountain, and sat there.', pt: 'Partindo Jesus dali, chegou ao pé do mar da Galiléia; e, subindo ao monte, sentou-se ali.' },
      { v: 30, en: 'Great multitudes came to him, having with them the lame, blind, mute, maimed, and many others, and they put them down at his feet. He healed them,', pt: 'E vieram a ele grandes multidões, trazendo consigo coxos, aleijados, cegos, mudos, e outros muitos, e lhos puseram aos pés; e ele os curou;' },
      { v: 31, en: 'so that the multitude wondered when they saw the mute speaking, the injured healed, the lame walking, and the blind seeing—and they glorified the God of Israel.', pt: 'de modo que a multidão se admirou, vendo mudos a falar, aleijados a ficar sãos, coxos a andar, cegos a ver; e glorificaram ao Deus de Israel.' },
      { v: 32, en: 'Jesus summoned his disciples and said, “I have compassion on the multitude, because they continue with me now three days and have nothing to eat. I don’t want to send them away fasting, or they might faint on the way.”', pt: 'Jesus chamou os seus discípulos, e disse: Tenho compaixão da multidão, porque já faz três dias que eles estão comigo, e não têm o que comer; e não quero despedi-los em jejum, para que não desfaleçam no caminho.' },
      { v: 33, en: 'The disciples said to him, “Where should we get so many loaves in a deserted place as to satisfy so great a multitude?”', pt: 'Disseram-lhe os discípulos: Donde nos viriam num deserto tantos pães, para fartar tamanha multidão?' },
      { v: 34, en: 'Jesus said to them, “How many loaves do you have?” They said, “Seven, and a few small fish.”', pt: 'Perguntou-lhes Jesus: Quantos pães tendes? E responderam: Sete, e alguns peixinhos.' },
      { v: 35, en: 'He commanded the multitude to sit down on the ground;', pt: 'E tendo ele ordenado ao povo que se sentasse no chão,' },
      { v: 36, en: 'and he took the seven loaves and the fish. He gave thanks and broke them, and gave to the disciples, and the disciples to the multitudes.', pt: 'tomou os sete pães e os peixes, e havendo dado graças, partiu-os, e os entregava aos discípulos, e os discípulos á multidão.' },
      { v: 37, en: 'They all ate, and were filled. They took up seven baskets full of the broken pieces that were left over.', pt: 'Assim todos comeram, e se fartaram; e do que sobejou dos pedaços levantaram sete alcofas cheias.' },
      { v: 38, en: 'Those who ate were four thousand men, besides women and children.', pt: 'Ora, os que tinham comido eram quatro mil homens além de mulheres e crianças.' },
      { v: 39, en: 'Then he sent away the multitudes, got into the boat, and came into the borders of Magdala.', pt: 'E havendo Jesus despedido a multidão, entrou no barco, e foi para os confins de Magadã.' },
    ],
    16: [
      { v: 1, en: 'The Pharisees and Sadducees came, and testing him, asked him to show them a sign from heaven.', pt: 'Então chegaram a ele os fariseus e os saduceus e, para o experimentarem, pediram-lhe que lhes mostrasse algum sinal do céu.' },
      { v: 2, en: 'But he answered them, “When it is evening, you say, ‘It will be fair weather, for the sky is red.’', pt: 'Mas ele respondeu, e disse-lhes: Ao cair da tarde, dizeis: Haverá bom tempo, porque o céu está rubro.' },
      { v: 3, en: 'In the morning, ‘It will be foul weather today, for the sky is red and threatening.’ Hypocrites! You know how to discern the appearance of the sky, but you can’t discern the signs of the times!', pt: 'E pela manhã: Hoje haverá tempestade, porque o céu está de um vermelho sombrio. Ora, sabeis discernir o aspecto do céu, e não podeis discernir os sinais dos tempos?' },
      { v: 4, en: 'An evil and adulterous generation seeks after a sign, and there will be no sign given to it, except the sign of the prophet Jonah.” He left them, and departed.', pt: 'Uma geração má e adúltera pede um sinal, e nenhum sinal lhe será dado, senão o de Jonas. E, deixando-os, retirou-se.' },
      { v: 5, en: 'The disciples came to the other side and had forgotten to take bread.', pt: 'Quando os discípulos passaram para o outro lado, esqueceram- se de levar pão.' },
      { v: 6, en: 'Jesus said to them, “Take heed and beware of the yeast of the Pharisees and Sadducees.”', pt: 'E Jesus lhes disse: Olhai, e acautelai-vos do fermento dos fariseus e dos saduceus.' },
      { v: 7, en: 'They reasoned among themselves, saying, “We brought no bread.”', pt: 'Pelo que eles arrazoavam entre si, dizendo: É porque não trouxemos pão.' },
      { v: 8, en: 'Jesus, perceiving it, said, “Why do you reason among yourselves, you of little faith, ‘because you have brought no bread?’', pt: 'E Jesus, percebendo isso, disse: Por que arrazoais entre vós por não terdes pão, homens de pouca fé?' },
      { v: 9, en: 'Don’t you yet perceive, neither remember the five loaves for the five thousand, and how many baskets you took up?', pt: 'Não compreendeis ainda, nem vos lembrais dos cinco pães para os cinco mil, e de quantos cestos levantastes?' },
      { v: 10, en: 'Nor the seven loaves for the four thousand, and how many baskets you took up?', pt: 'Nem dos sete pães para os quatro mil, e de quantas alcofas levantastes?' },
      { v: 11, en: 'How is it that you don’t perceive that I didn’t speak to you concerning bread? But beware of the yeast of the Pharisees and Sadducees.”', pt: 'Como não compreendeis que não nos falei a respeito de pães? Mas guardai-vos do fermento dos fariseus e dos saduceus.' },
      { v: 12, en: 'Then they understood that he didn’t tell them to beware of the yeast of bread, but of the teaching of the Pharisees and Sadducees.', pt: 'Então entenderam que não dissera que se guardassem, do fermento dos pães, mas da doutrina dos fariseus e dos saduceus.' },
      { v: 13, en: 'Now when Jesus came into the parts of Caesarea Philippi, he asked his disciples, saying, “Who do men say that I, the Son of Man, am?”', pt: 'Tendo Jesus chegado às regiões de Cesaréia de Felipe, interrogou os seus discípulos, dizendo: Quem dizem os homens ser o Filho do homem?' },
      { v: 14, en: 'They said, “Some say John the Baptizer, some, Elijah, and others, Jeremiah, or one of the prophets.”', pt: 'Responderam eles: Uns dizem que é João, o Batista; outros, Elias; outros, Jeremias, ou algum dos profetas.' },
      { v: 15, en: 'He said to them, “But who do you say that I am?”', pt: 'Mas vós, perguntou-lhes Jesus, quem dizeis que eu sou?' },
      { v: 16, en: 'Simon Peter answered, “You are the Christ, the Son of the living God.”', pt: 'Respondeu-lhe Simão Pedro: Tu és o Cristo, o Filho do Deus vivo.' },
      { v: 17, en: 'Jesus answered him, “Blessed are you, Simon Bar Jonah, for flesh and blood has not revealed this to you, but my Father who is in heaven.', pt: 'Disse-lhe Jesus: Bem-aventurado és tu, Simão Barjonas, porque não foi carne e sangue que to revelou, mas meu Pai, que está nos céus.' },
      { v: 18, en: 'I also tell you that you are Peter, and on this rock I will build my assembly, and the gates of Hades will not prevail against it.', pt: 'Pois também eu te digo que tu és Pedro, e sobre esta pedra edificarei a minha igreja, e as portas do hades não prevalecerão contra ela;' },
      { v: 19, en: 'I will give to you the keys of the Kingdom of Heaven, and whatever you bind on earth will have been bound in heaven; and whatever you release on earth will have been released in heaven.”', pt: 'dar-te-ei as chaves do reino dos céus; o que ligares, pois, na terra será ligado nos céus, e o que desligares na terra será desligado nos céus.' },
      { v: 20, en: 'Then he commanded the disciples that they should tell no one that he was Jesus the Christ.', pt: 'Então ordenou aos discípulos que a ninguém dissessem que ele era o Cristo.' },
      { v: 21, en: 'From that time, Jesus began to show his disciples that he must go to Jerusalem and suffer many things from the elders, chief priests, and scribes, and be killed, and the third day be raised up.', pt: 'Desde então começou Jesus Cristo a mostrar aos seus discípulos que era necessário que ele fosse a Jerusalém, que padecesse muitas coisas dos anciãos, dos principais sacerdotes, e dos escribas, que fosse morto, e que ao terceiro dia ressuscitasse.' },
      { v: 22, en: 'Peter took him aside, and began to rebuke him, saying, “Far be it from you, Lord! This will never be done to you.”', pt: 'E Pedro, tomando-o à parte, começou a repreendê-lo, dizendo: Tenha Deus compaixão de ti, Senhor; isso de modo nenhum te acontecerá.' },
      { v: 23, en: 'But he turned, and said to Peter, “Get behind me, Satan! You are a stumbling block to me, for you are not setting your mind on the things of God, but on the things of men.”', pt: 'Ele, porém, voltando-se, disse a Pedro: Para trás de mim, Satanás, que me serves de escândalo; porque não estás pensando nas coisas que são de Deus, mas sim nas que são dos homens.' },
      { v: 24, en: 'Then Jesus said to his disciples, “If anyone desires to come after me, let him deny himself, and take up his cross, and follow me.', pt: 'Então disse Jesus aos seus discípulos: Se alguém quer vir após mim, negue-se a si mesmo, tome a sua cruz, e siga-me;' },
      { v: 25, en: 'For whoever desires to save his life will lose it, and whoever will lose his life for my sake will find it.', pt: 'pois, quem quiser salvar a sua vida perdê-la-á; mas quem perder a sua vida por amor de mim, achá-la-á.' },
      { v: 26, en: 'For what will it profit a man, if he gains the whole world, and forfeits his life? Or what will a man give in exchange for his life?', pt: 'Pois que aproveita ao homem se ganhar o mundo inteiro e perder a sua vida? ou que dará o homem em troca da sua vida?' },
      { v: 27, en: 'For the Son of Man will come in the glory of his Father with his angels, and then he will render to everyone according to his deeds.', pt: 'Porque o Filho do homem há de vir na glória de seu Pai, com os seus anjos; e então retribuirá a cada um segundo as suas obras.' },
      { v: 28, en: 'Most certainly I tell you, there are some standing here who will in no way taste of death, until they see the Son of Man coming in his Kingdom.”', pt: 'Em verdade vos digo, alguns dos que aqui estão de modo nenhum provarão a morte até que vejam vir o Filho do homem no seu reino.' },
    ],
    17: [
      { v: 1, en: 'After six days, Jesus took with him Peter, James, and John his brother, and brought them up into a high mountain by themselves.', pt: 'Seis dias depois, tomou Jesus consigo a Pedro, a Tiago e a João, irmão deste, e os conduziu à parte a um alto monte;' },
      { v: 2, en: 'He was transfigured before them. His face shone like the sun, and his garments became as white as the light.', pt: 'e foi transfigurado diante deles; o seu rosto resplandeceu como o sol, e as suas vestes tornaram-se brancas como a luz.' },
      { v: 3, en: 'Behold, Moses and Elijah appeared to them talking with him.', pt: 'E eis que lhes apareceram Moisés e Elias, falando com ele.' },
      { v: 4, en: 'Peter answered, and said to Jesus, “Lord, it is good for us to be here. If you want, let’s make three tents here: one for you, one for Moses, and one for Elijah.”', pt: 'Pedro, tomando a palavra, disse a Jesus: Senhor, bom é estarmos aqui; se queres, farei aqui três cabanas, uma para ti, outra para Moisés, e outra para Elias.' },
      { v: 5, en: 'While he was still speaking, behold, a bright cloud overshadowed them. Behold, a voice came out of the cloud, saying, “This is my beloved Son, in whom I am well pleased. Listen to him.”', pt: 'Estando ele ainda a falar, eis que uma nuvem luminosa os cobriu; e dela saiu uma voz que dizia: Este é o meu Filho amado, em quem me comprazo; a ele ouvi.' },
      { v: 6, en: 'When the disciples heard it, they fell on their faces, and were very afraid.', pt: 'Os discípulos, ouvindo isso, cairam com o rosto em terra, e ficaram grandemente atemorizados.' },
      { v: 7, en: 'Jesus came and touched them and said, “Get up, and don’t be afraid.”', pt: 'Chegou-se, pois, Jesus e, tocando-os, disse: Levantai-vos e não temais.' },
      { v: 8, en: 'Lifting up their eyes, they saw no one, except Jesus alone.', pt: 'E, erguendo eles os olhos, não viram a ninguém senão a Jesus somente.' },
      { v: 9, en: 'As they were coming down from the mountain, Jesus commanded them, saying, “Don’t tell anyone what you saw, until the Son of Man has risen from the dead.”', pt: 'Enquanto desciam do monte, Jesus lhes ordenou: A ninguém conteis a visão, até que o Filho do homem seja levantado dentre os mortos.' },
      { v: 10, en: 'His disciples asked him, saying, “Then why do the scribes say that Elijah must come first?”', pt: 'Perguntaram-lhe os discípulos: Por que dizem então os escribas que é necessário que Elias venha primeiro?' },
      { v: 11, en: 'Jesus answered them, “Elijah indeed comes first, and will restore all things,', pt: 'Respondeu ele: Na verdade Elias havia de vir e restaurar todas as coisas;' },
      { v: 12, en: 'but I tell you that Elijah has come already, and they didn’t recognize him, but did to him whatever they wanted to. Even so the Son of Man will also suffer by them.”', pt: 'digo-vos, porém, que Elias já veio, e não o reconheceram; mas fizeram-lhe tudo o que quiseram. Assim também o Filho do homem há de padecer às mãos deles.' },
      { v: 13, en: 'Then the disciples understood that he spoke to them of John the Baptizer.', pt: 'Então entenderam os discípulos que lhes falava a respeito de João, o Batista.' },
      { v: 14, en: 'When they came to the multitude, a man came to him, kneeling down to him, and saying,', pt: 'Quando chegaram à multidão, aproximou-se de Jesus um homem que, ajoelhando-se diante dele, disse:' },
      { v: 15, en: '“Lord, have mercy on my son, for he is epileptic, and suffers grievously; for he often falls into the fire, and often into the water.', pt: 'Senhor, tem compaixão de meu filho, porque é epiléptico e sofre muito; pois muitas vezes cai no fogo, e muitas vezes na água.' },
      { v: 16, en: 'So I brought him to your disciples, and they could not cure him.”', pt: 'Eu o trouxe aos teus discípulos, e não o puderam curar.' },
      { v: 17, en: 'Jesus answered, “Faithless and perverse generation! How long will I be with you? How long will I bear with you? Bring him here to me.”', pt: 'E Jesus, respondendo, disse: Ó geração incrédula e perversa! até quando estarei convosco? até quando vos sofrerei? Trazei-mo aqui.' },
      { v: 18, en: 'Jesus rebuked him, the demon went out of him, and the boy was cured from that hour.', pt: 'Então Jesus repreendeu ao demônio, o qual saiu de menino, que desde aquela hora ficou curado.' },
      { v: 19, en: 'Then the disciples came to Jesus privately, and said, “Why weren’t we able to cast it out?”', pt: 'Depois os discípulos, aproximando-se de Jesus em particular, perguntaram-lhe: Por que não pudemos nós expulsá-lo?' },
      { v: 20, en: 'He said to them, “Because of your unbelief. For most certainly I tell you, if you have faith as a grain of mustard seed, you will tell this mountain, ‘Move from here to there,’ and it will move; and nothing will be impossible for you.', pt: 'Disse-lhes ele: Por causa da vossa pouca fé; pois em verdade vos digo que, se tiverdes fé como um grão de mostarda direis a este monte: Passa daqui para acolá, e ele há de passar; e nada vos será impossível.' },
      { v: 21, en: 'But this kind doesn’t go out except by prayer and fasting.”', pt: '[mas esta casta de demônios não se expulsa senão à força de oração e de jejum.]' },
      { v: 22, en: 'While they were staying in Galilee, Jesus said to them, “The Son of Man is about to be delivered up into the hands of men,', pt: 'Ora, achando-se eles na Galiléia, disse-lhes Jesus: O Filho do homem está para ser entregue nas mãos dos homens;' },
      { v: 23, en: 'and they will kill him, and the third day he will be raised up.” They were exceedingly sorry.', pt: 'e matá-lo-ão, e ao terceiro dia ressurgirá. E eles se entristeceram grandemente.' },
      { v: 24, en: 'When they had come to Capernaum, those who collected the didrachma coins came to Peter, and said, “Doesn’t your teacher pay the didrachma?”', pt: 'Tendo eles chegado a Cafarnaum, aproximaram-se de Pedro os que cobravam as didracmas, e lhe perguntaram: O vosso mestre não paga as didracmas?' },
      { v: 25, en: 'He said, “Yes.” When he came into the house, Jesus anticipated him, saying, “What do you think, Simon? From whom do the kings of the earth receive toll or tribute? From their children, or from strangers?”', pt: 'Disse ele: Sim. Ao entrar Pedro em casa, Jesus se lhe antecipou, perguntando: Que te parece, Simão? De quem cobram os reis da terra imposto ou tributo? dos seus filhos, ou dos alheios?' },
      { v: 26, en: 'Peter said to him, “From strangers.” Jesus said to him, “Therefore the children are exempt.', pt: 'Quando ele respondeu: Dos alheios, disse-lhe Jesus: Logo, são isentos os filhos.' },
      { v: 27, en: 'But, lest we cause them to stumble, go to the sea, cast a hook, and take up the first fish that comes up. When you have opened its mouth, you will find a stater coin. Take that, and give it to them for me and you.”', pt: 'Mas, para que não os escandalizemos, vai ao mar, lança o anzol, tira o primeiro peixe que subir e, abrindo-lhe a boca, encontrarás um estáter; toma-o, e dá-lho por mim e por ti.' },
    ],
    18: [
      { v: 1, en: 'In that hour the disciples came to Jesus, saying, “Who then is greatest in the Kingdom of Heaven?”', pt: 'Naquela hora chegaram-se a Jesus os discípulos e perguntaram: Quem é o maior no reino dos céus?' },
      { v: 2, en: 'Jesus called a little child to himself, and set him in the middle of them,', pt: 'Jesus, chamando uma criança, colocou-a no meio deles,' },
      { v: 3, en: 'and said, “Most certainly I tell you, unless you turn, and become as little children, you will in no way enter into the Kingdom of Heaven.', pt: 'e disse: Em verdade vos digo que se não vos converterdes e não vos fizerdes como crianças, de modo algum entrareis no reino dos céus.' },
      { v: 4, en: 'Whoever therefore humbles himself as this little child, the same is the greatest in the Kingdom of Heaven.', pt: 'Portanto, quem se tornar humilde como esta criança, esse é o maior no reino dos céus.' },
      { v: 5, en: 'Whoever receives one such little child in my name receives me,', pt: 'E qualquer que receber em meu nome uma criança tal como esta, a mim me recebe.' },
      { v: 6, en: 'but whoever causes one of these little ones who believe in me to stumble, it would be better for him that a huge millstone should be hung around his neck, and that he should be sunk in the depths of the sea.', pt: 'Mas qualquer que fizer tropeçar um destes pequeninos que creem em mim, melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho, e se submergisse na profundeza do mar.' },
      { v: 7, en: '“Woe to the world because of occasions of stumbling! For it must be that the occasions come, but woe to that person through whom the occasion comes!', pt: 'Ai do mundo, por causa dos tropeços! pois é inevitável que venham; mas ai do homem por quem o tropeço vier!' },
      { v: 8, en: 'If your hand or your foot causes you to stumble, cut it off, and cast it from you. It is better for you to enter into life maimed or crippled, rather than having two hands or two feet to be cast into the eternal fire.', pt: 'Se, pois, a tua mão ou o teu pé te fizer tropeçar, corta-o, lança-o de ti; melhor te é entrar na vida aleijado, ou coxo, do que, tendo duas mãos ou dois pés, ser lançado no fogo eterno.' },
      { v: 9, en: 'If your eye causes you to stumble, pluck it out, and cast it from you. It is better for you to enter into life with one eye, rather than having two eyes to be cast into the Gehenna of fire.', pt: 'E, se teu olho te fizer tropeçar, arranca-o, e lança-o de ti; melhor te é entrar na vida com um só olho, do que tendo dois olhos, ser lançado no inferno de fogo.' },
      { v: 10, en: 'See that you don’t despise one of these little ones, for I tell you that in heaven their angels always see the face of my Father who is in heaven.', pt: 'Vede, não desprezeis a nenhum destes pequeninos; pois eu vos digo que os seus anjos nos céus sempre vêm a face de meu Pai, que está nos céus.' },
      { v: 11, en: 'For the Son of Man came to save that which was lost.', pt: '[Porque o Filho do homem veio salvar o que se havia perdido.]' },
      { v: 12, en: '“What do you think? If a man has one hundred sheep, and one of them goes astray, doesn’t he leave the ninety-nine, go to the mountains, and seek that which has gone astray?', pt: 'Que vos parece? Se alguém tiver cem ovelhas, e uma delas se extraviar, não deixará as noventa e nove nos montes para ir buscar a que se extraviou?' },
      { v: 13, en: 'If he finds it, most certainly I tell you, he rejoices over it more than over the ninety-nine which have not gone astray.', pt: 'E, se acontecer achá-la, em verdade vos digo que maior prazer tem por esta do que pelas noventa e nove que não se extraviaram.' },
      { v: 14, en: 'Even so it is not the will of your Father who is in heaven that one of these little ones should perish.', pt: 'Assim também não é da vontade de vosso Pai que está nos céus, que venha a perecer um só destes pequeninos.' },
      { v: 15, en: '“If your brother sins against you, go, show him his fault between you and him alone. If he listens to you, you have gained back your brother.', pt: 'Ora, se teu irmão pecar, vai, e repreende-o entre ti e ele só; se te ouvir, terás ganho teu irmão;' },
      { v: 16, en: 'But if he doesn’t listen, take one or two more with you, that at the mouth of two or three witnesses every word may be established.', pt: 'mas se não te ouvir, leva ainda contigo um ou dois, para que pela boca de duas ou três testemunhas toda palavra seja confirmada.' },
      { v: 17, en: 'If he refuses to listen to them, tell it to the assembly. If he refuses to hear the assembly also, let him be to you as a Gentile or a tax collector.', pt: 'Se recusar ouvi-los, dize-o à igreja; e, se também recusar ouvir a igreja, considera-o como gentio e publicano.' },
      { v: 18, en: 'Most certainly I tell you, whatever things you bind on earth will have been bound in heaven, and whatever things you release on earth will have been released in heaven.', pt: 'Em verdade vos digo: Tudo quanto ligardes na terra será ligado no céu; e tudo quanto desligardes na terra será desligado no céu.' },
      { v: 19, en: 'Again, assuredly I tell you, that if two of you will agree on earth concerning anything that they will ask, it will be done for them by my Father who is in heaven.', pt: 'Ainda vos digo mais: Se dois de vós na terra concordarem acerca de qualquer coisa que pedirem, isso lhes será feito por meu Pai, que está nos céus.' },
      { v: 20, en: 'For where two or three are gathered together in my name, there I am in the middle of them.”', pt: 'Pois onde se acham dois ou três reunidos em meu nome, aí estou eu no meio deles.' },
      { v: 21, en: 'Then Peter came and said to him, “Lord, how often shall my brother sin against me, and I forgive him? Until seven times?”', pt: 'Então Pedro, aproximando-se dele, lhe perguntou: Senhor, até quantas vezes pecará meu irmão contra mim, e eu hei de perdoar? Até sete?' },
      { v: 22, en: 'Jesus said to him, “I don’t tell you until seven times, but, until seventy times seven.', pt: 'Respondeu-lhe Jesus: Não te digo que até sete; mas até setenta vezes sete.' },
      { v: 23, en: 'Therefore the Kingdom of Heaven is like a certain king, who wanted to reconcile accounts with his servants.', pt: 'Por isso o reino dos céus é comparado a um rei que quis tomar contas a seus servos;' },
      { v: 24, en: 'When he had begun to reconcile, one was brought to him who owed him ten thousand talents.', pt: 'e, tendo começado a tomá-las, foi-lhe apresentado um que lhe devia dez mil talentos;' },
      { v: 25, en: 'But because he couldn’t pay, his lord commanded him to be sold, with his wife, his children, and all that he had, and payment to be made.', pt: 'mas não tendo ele com que pagar, ordenou seu senhor que fossem vendidos, ele, sua mulher, seus filhos, e tudo o que tinha, e que se pagasse a dívida.' },
      { v: 26, en: 'The servant therefore fell down and knelt before him, saying, ‘Lord, have patience with me, and I will repay you all!’', pt: 'Então aquele servo, prostrando-se, o reverenciava, dizendo: Senhor, tem paciência comigo, que tudo te pagarei.' },
      { v: 27, en: 'The lord of that servant, being moved with compassion, released him, and forgave him the debt.', pt: 'O senhor daquele servo, pois, movido de compaixão, soltou-o, e perdoou-lhe a dívida.' },
      { v: 28, en: '“But that servant went out, and found one of his fellow servants, who owed him one hundred denarii, and he grabbed him, and took him by the throat, saying, ‘Pay me what you owe!’', pt: 'Saindo, porém, aquele servo, encontrou um dos seus conservos, que lhe devia cem denários; e, segurando-o, o sufocava, dizendo: Paga o que me deves.' },
      { v: 29, en: '“So his fellow servant fell down at his feet and begged him, saying, ‘Have patience with me, and I will repay you!’', pt: 'Então o seu companheiro, caindo-lhe aos pés, rogava-lhe, dizendo: Tem paciência comigo, que te pagarei.' },
      { v: 30, en: 'He would not, but went and cast him into prison, until he should pay back that which was due.', pt: 'Ele, porém, não quis; antes foi encerrá-lo na prisão, até que pagasse a dívida.' },
      { v: 31, en: 'So when his fellow servants saw what was done, they were exceedingly sorry, and came and told their lord all that was done.', pt: 'Vendo, pois, os seus conservos o que acontecera, contristaram-se grandemente, e foram revelar tudo isso ao seu senhor.' },
      { v: 32, en: 'Then his lord called him in, and said to him, ‘You wicked servant! I forgave you all that debt, because you begged me.', pt: 'Então o seu senhor, chamando-o á sua presença, disse-lhe: Servo malvado, perdoei-te toda aquela dívida, porque me suplicaste;' },
      { v: 33, en: 'Shouldn’t you also have had mercy on your fellow servant, even as I had mercy on you?’', pt: 'não devias tu também ter compaixão do teu companheiro, assim como eu tive compaixão de ti?' },
      { v: 34, en: 'His lord was angry, and delivered him to the tormentors, until he should pay all that was due to him.', pt: 'E, indignado, o seu senhor o entregou aos verdugos, até que pagasse tudo o que lhe devia.' },
      { v: 35, en: 'So my heavenly Father will also do to you, if you don’t each forgive your brother from your hearts for his misdeeds.”', pt: 'Assim vos fará meu Pai celestial, se de coração não perdoardes, cada um a seu irmão.' },
    ],
    19: [
      { v: 1, en: 'When Jesus had finished these words, he departed from Galilee, and came into the borders of Judea beyond the Jordan.', pt: 'Tendo Jesus concluído estas palavras, partiu da Galiléia, e foi para os confins da Judéia, além do Jordão;' },
      { v: 2, en: 'Great multitudes followed him, and he healed them there.', pt: 'e seguiram-no grandes multidões, e curou-os ali.' },
      { v: 3, en: 'Pharisees came to him, testing him, and saying, “Is it lawful for a man to divorce his wife for any reason?”', pt: 'Aproximaram-se dele alguns fariseus que o experimentavam, dizendo: É lícito ao homem repudiar sua mulher por qualquer motivo?' },
      { v: 4, en: 'He answered, “Haven’t you read that he who made them from the beginning made them male and female,', pt: 'Respondeu-lhe Jesus: Não tendes lido que o Criador os fez desde o princípio homem e mulher,' },
      { v: 5, en: 'and said, ‘For this cause a man shall leave his father and mother, and shall be joined to his wife; and the two shall become one flesh?’', pt: 'e que ordenou: Por isso deixará o homem pai e mãe, e unir-se-á a sua mulher; e serão os dois uma só carne?' },
      { v: 6, en: 'So that they are no more two, but one flesh. What therefore God has joined together, don’t let man tear apart.”', pt: 'Assim já não são mais dois, mas um só carne. Portanto o que Deus ajuntou, não o separe o homem.' },
      { v: 7, en: 'They asked him, “Why then did Moses command us to give her a bill of divorce, and divorce her?”', pt: 'Responderam-lhe: Então por que mandou Moisés dar-lhe carta de divórcio e repudiá-la?' },
      { v: 8, en: 'He said to them, “Moses, because of the hardness of your hearts, allowed you to divorce your wives, but from the beginning it has not been so.', pt: 'Disse-lhes ele: Pela dureza de vossos corações Moisés vos permitiu repudiar vossas mulheres; mas não foi assim desde o princípio.' },
      { v: 9, en: 'I tell you that whoever divorces his wife, except for sexual immorality, and marries another, commits adultery; and he who marries her when she is divorced commits adultery.”', pt: 'Eu vos digo porém, que qualquer que repudiar sua mulher, a não ser por causa de infidelidade, e casar com outra, comete adultério; [e o que casar com a repudiada também comete adultério.]' },
      { v: 10, en: 'His disciples said to him, “If this is the case of the man with his wife, it is not expedient to marry.”', pt: 'Disseram-lhe os discípulos: Se tal é a condição do homem relativamente à mulher, não convém casar.' },
      { v: 11, en: 'But he said to them, “Not all men can receive this saying, but those to whom it is given.', pt: 'Ele, porém, lhes disse: Nem todos podem aceitar esta palavra, mas somente aqueles a quem é dado.' },
      { v: 12, en: 'For there are eunuchs who were born that way from their mother’s womb, and there are eunuchs who were made eunuchs by men; and there are eunuchs who made themselves eunuchs for the Kingdom of Heaven’s sake. He who is able to receive it, let him receive it.”', pt: 'Porque há eunucos que nasceram assim; e há eunucos que pelos homens foram feitos tais; e outros há que a si mesmos se fizeram eunucos por causa do reino dos céus. Quem pode aceitar isso, aceite-o.' },
      { v: 13, en: 'Then little children were brought to him, that he should lay his hands on them and pray; and the disciples rebuked them.', pt: 'Então lhe trouxeram algumas crianças para que lhes impusesse as mãos, e orasse; mas os discípulos os repreenderam.' },
      { v: 14, en: 'But Jesus said, “Allow the little children, and don’t forbid them to come to me; for the Kingdom of Heaven belongs to ones like these.”', pt: 'Jesus, porém, disse: Deixai as crianças e não as impeçais de virem a mim, porque de tais é o reino dos céus.' },
      { v: 15, en: 'He laid his hands on them, and departed from there.', pt: 'E, depois de lhes impor as mãos, partiu dali.' },
      { v: 16, en: 'Behold, one came to him and said, “Good teacher, what good thing shall I do, that I may have eternal life?”', pt: 'E eis que se aproximou dele um jovem, e lhe disse: Mestre, que bem farei para conseguir a vida eterna?' },
      { v: 17, en: 'He said to him, “Why do you call me good? No one is good but one, that is, God. But if you want to enter into life, keep the commandments.”', pt: 'Respondeu-lhe ele: Por que me perguntas sobre o que é bom? Um só é bom; mas se é que queres entrar na vida, guarda os mandamentos.' },
      { v: 18, en: 'He said to him, “Which ones?” Jesus said, “‘You shall not murder.’ ‘You shall not commit adultery.’ ‘You shall not steal.’ ‘You shall not offer false testimony.’', pt: 'Perguntou-lhe ele: Quais? Respondeu Jesus: Não matarás; não adulterarás; não furtarás; não dirás falso testemunho;' },
      { v: 19, en: '‘Honor your father and your mother.’ And, ‘You shall love your neighbor as yourself.’”', pt: 'honra a teu pai e a tua mãe; e amarás o teu próximo como a ti mesmo.' },
      { v: 20, en: 'The young man said to him, “All these things I have observed from my youth. What do I still lack?”', pt: 'Disse-lhe o jovem: Tudo isso tenho guardado; que me falta ainda?' },
      { v: 21, en: 'Jesus said to him, “If you want to be perfect, go, sell what you have, and give to the poor, and you will have treasure in heaven; and come, follow me.”', pt: 'Disse-lhe Jesus: Se queres ser perfeito, vai, vende tudo o que tens e dá-o aos pobres, e terás um tesouro no céu; e vem, segue- me.' },
      { v: 22, en: 'But when the young man heard the saying, he went away sad, for he was one who had great possessions.', pt: 'Mas o jovem, ouvindo essa palavra, retirou-se triste; porque possuía muitos bens.' },
      { v: 23, en: 'Jesus said to his disciples, “Most certainly I say to you, a rich man will enter into the Kingdom of Heaven with difficulty.', pt: 'Disse então Jesus aos seus discípulos: Em verdade vos digo que um rico dificilmente entrará no reino dos céus.' },
      { v: 24, en: 'Again I tell you, it is easier for a camel to go through a needle’s eye, than for a rich man to enter into God’s Kingdom.”', pt: 'E outra vez vos digo que é mais fácil um camelo passar pelo fundo duma agulha, do que entrar um rico no reino de Deus.' },
      { v: 25, en: 'When the disciples heard it, they were exceedingly astonished, saying, “Who then can be saved?”', pt: 'Quando os seus discípulos ouviram isso, ficaram grandemente maravilhados, e perguntaram: Quem pode, então, ser salvo?' },
      { v: 26, en: 'Looking at them, Jesus said, “With men this is impossible, but with God all things are possible.”', pt: 'Jesus, fixando neles o olhar, respondeu: Aos homens é isso impossível, mas a Deus tudo é possível.' },
      { v: 27, en: 'Then Peter answered, “Behold, we have left everything, and followed you. What then will we have?”', pt: 'Então Pedro, tomando a palavra, disse-lhe: Eis que nós deixamos tudo, e te seguimos; que recompensa, pois, teremos nós?' },
      { v: 28, en: 'Jesus said to them, “Most certainly I tell you that you who have followed me, in the regeneration when the Son of Man will sit on the throne of his glory, you also will sit on twelve thrones, judging the twelve tribes of Israel.', pt: 'Ao que lhe disse Jesus: Em verdade vos digo a vós que me seguistes, que na regeneração, quando o Filho do homem se assentar no trono da sua glória, sentar-vos-eis também vós sobre doze tronos, para julgar as doze tribos de Israel.' },
      { v: 29, en: 'Everyone who has left houses, or brothers, or sisters, or father, or mother, or wife, or children, or lands, for my name’s sake, will receive one hundred times, and will inherit eternal life.', pt: 'E todo o que tiver deixado casas, ou irmãos, ou irmãs, ou pai, ou mãe, ou filhos, ou terras, por amor do meu nome, receberá cem vezes tanto, e herdará a vida eterna.' },
      { v: 30, en: 'But many will be last who are first; and first who are last.', pt: 'Entretanto, muitos que são primeiros serão últimos; e muitos que são últimos serão primeiros.' },
    ],
    20: [
      { v: 1, en: '“For the Kingdom of Heaven is like a man who was the master of a household, who went out early in the morning to hire laborers for his vineyard.', pt: 'Porque o reino dos céus é semelhante a um homem, proprietário, que saiu de madrugada a contratar trabalhadores para a sua vinha.' },
      { v: 2, en: 'When he had agreed with the laborers for a denarius a day, he sent them into his vineyard.', pt: 'Ajustou com os trabalhadores o salário de um denário por dia, e mandou-os para a sua vinha.' },
      { v: 3, en: 'He went out about the third hour, and saw others standing idle in the marketplace.', pt: 'Cerca da hora terceira saiu, e viu que estavam outros, ociosos, na praça,' },
      { v: 4, en: 'He said to them, ‘You also go into the vineyard, and whatever is right I will give you.’ So they went their way.', pt: 'e disse-lhes: Ide também vós para a vinha, e dar-vos-ei o que for justo. E eles foram.' },
      { v: 5, en: 'Again he went out about the sixth and the ninth hour, and did likewise.', pt: 'Outra vez saiu, cerca da hora sexta e da nona, e fez o mesmo.' },
      { v: 6, en: 'About the eleventh hour he went out, and found others standing idle. He said to them, ‘Why do you stand here all day idle?’', pt: 'Igualmente, cerca da hora undécima, saiu e achou outros que lá estavam, e perguntou-lhes: Por que estais aqui ociosos o dia todo?' },
      { v: 7, en: '“They said to him, ‘Because no one has hired us.’ “He said to them, ‘You also go into the vineyard, and you will receive whatever is right.’', pt: 'Responderam-lhe eles: Porque ninguém nos contratou. Disse- lhes ele: Ide também vós para a vinha.' },
      { v: 8, en: 'When evening had come, the lord of the vineyard said to his manager, ‘Call the laborers and pay them their wages, beginning from the last to the first.’', pt: 'Ao anoitecer, disse o senhor da vinha ao seu mordomo: Chama os trabalhadores, e paga-lhes o salário, começando pelos últimos até os primeiros.' },
      { v: 9, en: '“When those who were hired at about the eleventh hour came, they each received a denarius.', pt: 'Chegando, pois, os que tinham ido cerca da hora undécima, receberam um denário cada um.' },
      { v: 10, en: 'When the first came, they supposed that they would receive more; and they likewise each received a denarius.', pt: 'Vindo, então, os primeiros, pensaram que haviam de receber mais; mas do mesmo modo receberam um denário cada um.' },
      { v: 11, en: 'When they received it, they murmured against the master of the household,', pt: 'E ao recebê-lo, murmuravam contra o proprietário, dizendo:' },
      { v: 12, en: 'saying, ‘These last have spent one hour, and you have made them equal to us, who have borne the burden of the day and the scorching heat!’', pt: 'Estes últimos trabalharam somente uma hora, e os igualastes a nós, que suportamos a fadiga do dia inteiro e o forte calor.' },
      { v: 13, en: '“But he answered one of them, ‘Friend, I am doing you no wrong. Didn’t you agree with me for a denarius?', pt: 'Mas ele, respondendo, disse a um deles: Amigo, não te faço injustiça; não ajustaste comigo um denário?' },
      { v: 14, en: 'Take that which is yours, and go your way. It is my desire to give to this last just as much as to you.', pt: 'Toma o que é teu, e vai-te; eu quero dar a este último tanto como a ti.' },
      { v: 15, en: 'Isn’t it lawful for me to do what I want to with what I own? Or is your eye evil, because I am good?’', pt: 'Não me é lícito fazer o que quero do que é meu? Ou é mau o teu olho porque eu sou bom?' },
      { v: 16, en: 'So the last will be first, and the first last. For many are called, but few are chosen.”', pt: 'Assim os últimos serão primeiros, e os primeiros serão últimos.' },
      { v: 17, en: 'As Jesus was going up to Jerusalem, he took the twelve disciples aside, and on the way he said to them,', pt: 'Estando Jesus para subir a Jerusalém, chamou à parte os doze e no caminho lhes disse:' },
      { v: 18, en: '“Behold, we are going up to Jerusalem, and the Son of Man will be delivered to the chief priests and scribes, and they will condemn him to death,', pt: 'Eis que subimos a Jerusalém, e o Filho do homem será entregue aos principais sacerdotes e aos escribas, e eles o condenarão à morte,' },
      { v: 19, en: 'and will hand him over to the Gentiles to mock, to scourge, and to crucify; and the third day he will be raised up.”', pt: 'e o entregarão aos gentios para que dele escarneçam, e o açoitem e crucifiquem; e ao terceiro dia ressuscitará.' },
      { v: 20, en: 'Then the mother of the sons of Zebedee came to him with her sons, kneeling and asking a certain thing of him.', pt: 'Aproximou-se dele, então, a mãe dos filhos de Zebedeu, com seus filhos, ajoelhando-se e fazendo-lhe um pedido.' },
      { v: 21, en: 'He said to her, “What do you want?” She said to him, “Command that these, my two sons, may sit, one on your right hand, and one on your left hand, in your Kingdom.”', pt: 'Perguntou-lhe Jesus: Que queres? Ela lhe respondeu: Concede que estes meus dois filhos se sentem, um à tua direita e outro à tua esquerda, no teu reino.' },
      { v: 22, en: 'But Jesus answered, “You don’t know what you are asking. Are you able to drink the cup that I am about to drink, and be baptized with the baptism that I am baptized with?” They said to him, “We are able.”', pt: 'Jesus, porém, replicou: Não sabeis o que pedis; podeis beber o cálice que eu estou para beber? Responderam-lhe: Podemos.' },
      { v: 23, en: 'He said to them, “You will indeed drink my cup, and be baptized with the baptism that I am baptized with, but to sit on my right hand and on my left hand is not mine to give; but it is for whom it has been prepared by my Father.”', pt: 'Então lhes disse: O meu cálice certamente haveis de beber; mas o sentar-se à minha direita e à minha esquerda, não me pertence concedê-lo; mas isso é para aqueles para quem está preparado por meu Pai.' },
      { v: 24, en: 'When the ten heard it, they were indignant with the two brothers.', pt: 'E ouvindo isso os dez, indignaram-se contra os dois irmãos.' },
      { v: 25, en: 'But Jesus summoned them, and said, “You know that the rulers of the nations lord it over them, and their great ones exercise authority over them.', pt: 'Jesus, pois, chamou-os para junto de si e lhes disse: Sabeis que os governadores dos gentios os dominam, e os seus grandes exercem autoridades sobre eles.' },
      { v: 26, en: 'It shall not be so among you, but whoever desires to become great among you shall be your servant.', pt: 'Não será assim entre vós; antes, qualquer que entre vós quiser tornar-se grande, será esse o que vos sirva;' },
      { v: 27, en: 'Whoever desires to be first among you shall be your bondservant,', pt: 'e qualquer que entre vós quiser ser o primeiro, será vosso servo;' },
      { v: 28, en: 'even as the Son of Man came not to be served, but to serve, and to give his life as a ransom for many.”', pt: 'assim como o Filho do homem não veio para ser servido, mas para servir, e para dar a sua vida em resgate de muitos.' },
      { v: 29, en: 'As they went out from Jericho, a great multitude followed him.', pt: 'Saindo eles de Jericó, seguiu-o uma grande multidão;' },
      { v: 30, en: 'Behold, two blind men sitting by the road, when they heard that Jesus was passing by, cried out, “Lord, have mercy on us, you son of David!”', pt: 'e eis que dois cegos, sentados junto do caminho, ouvindo que Jesus passava, clamaram, dizendo: Senhor, Filho de Davi, tem compaixão de nós.' },
      { v: 31, en: 'The multitude rebuked them, telling them that they should be quiet, but they cried out even more, “Lord, have mercy on us, you son of David!”', pt: 'E a multidão os repreendeu, para que se calassem; eles, porém, clamaram ainda mais alto, dizendo: Senhor, Filho de Davi, tem compaixão de nós.' },
      { v: 32, en: 'Jesus stood still, and called them, and asked, “What do you want me to do for you?”', pt: 'E Jesus, parando, chamou-os e perguntou: Que quereis que vos faça?' },
      { v: 33, en: 'They told him, “Lord, that our eyes may be opened.”', pt: 'Disseram-lhe eles: Senhor, que se nos abram os olhos.' },
      { v: 34, en: 'Jesus, being moved with compassion, touched their eyes; and immediately their eyes received their sight, and they followed him.', pt: 'E Jesus, movido de compaixão, tocou-lhes os olhos, e imediatamente recuperaram a vista, e o seguiram.' },
    ],
    21: [
      { v: 1, en: 'When they came near to Jerusalem, and came to Bethsphage, to the Mount of Olives, then Jesus sent two disciples,', pt: 'Quando se aproximaram de Jerusalém, e chegaram a Betfagé, ao Monte das Oliveiras, enviou Jesus dois discípulos, dizendo-lhes:' },
      { v: 2, en: 'saying to them, “Go into the village that is opposite you, and immediately you will find a donkey tied, and a colt with her. Untie them, and bring them to me.', pt: 'Ide à aldeia que está defronte de vós, e logo encontrareis uma jumenta presa, e um jumentinho com ela; desprendei-a, e trazei- mos.' },
      { v: 3, en: 'If anyone says anything to you, you shall say, ‘The Lord needs them,’ and immediately he will send them.”', pt: 'E, se alguém vos disser alguma coisa, respondei: O Senhor precisa deles; e logo os enviará.' },
      { v: 4, en: 'All this was done, that it might be fulfilled which was spoken through the prophet, saying,', pt: 'Ora, isso aconteceu para que se cumprisse o que foi dito pelo profeta:' },
      { v: 5, en: '“Tell the daughter of Zion, behold, your King comes to you, humble, and riding on a donkey, on a colt, the foal of a donkey.”', pt: 'Dizei à filha de Sião: Eis que aí te vem o teu Rei, manso e montado em um jumento, em um jumentinho, cria de animal de carga.' },
      { v: 6, en: 'The disciples went, and did just as Jesus commanded them,', pt: 'Indo, pois, os discípulos e fazendo como Jesus lhes ordenara,' },
      { v: 7, en: 'and brought the donkey and the colt, and laid their clothes on them; and he sat on them.', pt: 'trouxeram a jumenta e o jumentinho, e sobre eles puseram os seus mantos, e Jesus montou.' },
      { v: 8, en: 'A very great multitude spread their clothes on the road. Others cut branches from the trees, and spread them on the road.', pt: 'E a maior parte da multidão estendeu os seus mantos pelo caminho; e outros cortavam ramos de árvores, e os espalhavam pelo caminho.' },
      { v: 9, en: 'The multitudes who went in front of him, and those who followed, kept shouting, “Hosanna to the son of David! Blessed is he who comes in the name of the Lord! Hosanna in the highest!”', pt: 'E as multidões, tanto as que o precediam como as que o seguiam, clamavam, dizendo: Hosana ao Filho de Davi! bendito o que vem em nome do Senhor! Hosana nas alturas!' },
      { v: 10, en: 'When he had come into Jerusalem, all the city was stirred up, saying, “Who is this?”', pt: 'Ao entrar ele em Jerusalém, agitou-se a cidade toda e perguntava: Quem é este?' },
      { v: 11, en: 'The multitudes said, “This is the prophet, Jesus, from Nazareth of Galilee.”', pt: 'E as multidões respondiam: Este é o profeta Jesus, de Nazaré da Galiléia.' },
      { v: 12, en: 'Jesus entered into the temple of God, and drove out all of those who sold and bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves.', pt: 'Então Jesus entrou no templo, expulsou todos os que ali vendiam e compravam, e derribou as mesas dos cambistas e as cadeiras dos que vendiam pombas;' },
      { v: 13, en: 'He said to them, “It is written, ‘My house shall be called a house of prayer,’ but you have made it a den of robbers!”', pt: 'e disse-lhes: Está escrito: A minha casa será chamada casa de oração; vós, porém, a fazeis covil de salteadores.' },
      { v: 14, en: 'The blind and the lame came to him in the temple, and he healed them.', pt: 'E chegaram-se a ele no templo cegos e coxos, e ele os curou.' },
      { v: 15, en: 'But when the chief priests and the scribes saw the wonderful things that he did, and the children who were crying in the temple and saying, “Hosanna to the son of David!” they were indignant,', pt: 'Vendo, porém, os principais sacerdotes e os escribas as maravilhas que ele fizera, e os meninos que clamavam no templo: Hosana ao Filho de Davi, indignaram-se,' },
      { v: 16, en: 'and said to him, “Do you hear what these are saying?” Jesus said to them, “Yes. Did you never read, ‘Out of the mouth of babes and nursing babies you have perfected praise?’”', pt: 'e perguntaram-lhe: Ouves o que estes estão dizendo? Respondeu-lhes Jesus: Sim; nunca lestes: Da boca de pequeninos e de criancinhas de peito tiraste perfeito louvor?' },
      { v: 17, en: 'He left them, and went out of the city to Bethany, and camped there.', pt: 'E deixando-os, saiu da cidade para Betânia, e ali passou a noite.' },
      { v: 18, en: 'Now in the morning, as he returned to the city, he was hungry.', pt: 'Ora, de manhã, ao voltar à cidade, teve fome;' },
      { v: 19, en: 'Seeing a fig tree by the road, he came to it, and found nothing on it but leaves. He said to it, “Let there be no fruit from you forever!” Immediately the fig tree withered away.', pt: 'e, avistando uma figueira à beira do caminho, dela se aproximou, e não achou nela senão folhas somente; e disse-lhe: Nunca mais nasça fruto de ti. E a figueira secou imediatamente.' },
      { v: 20, en: 'When the disciples saw it, they marveled, saying, “How did the fig tree immediately wither away?”', pt: 'Quando os discípulos viram isso, perguntaram admirados: Como é que imediatamente secou a figueira?' },
      { v: 21, en: 'Jesus answered them, “Most certainly I tell you, if you have faith, and don’t doubt, you will not only do what was done to the fig tree, but even if you told this mountain, ‘Be taken up and cast into the sea,’ it would be done.', pt: 'Jesus, porém, respondeu-lhes: Em verdade vos digo que, se tiverdes fé e não duvidardes, não só fareis o que foi feito à figueira, mas até, se a este monte disserdes: Ergue-te e lança-te no mar, isso será feito;' },
      { v: 22, en: 'All things, whatever you ask in prayer, believing, you will receive.”', pt: 'e tudo o que pedirdes na oração, crendo, recebereis.' },
      { v: 23, en: 'When he had come into the temple, the chief priests and the elders of the people came to him as he was teaching, and said, “By what authority do you do these things? Who gave you this authority?”', pt: 'Tendo Jesus entrado no templo, e estando a ensinar, aproximaram-se dele os principais sacerdotes e os anciãos do povo, e perguntaram: Com que autoridade fazes tu estas coisas? e quem te deu tal autoridade?' },
      { v: 24, en: 'Jesus answered them, “I also will ask you one question, which if you tell me, I likewise will tell you by what authority I do these things.', pt: 'Respondeu-lhes Jesus: Eu também vos perguntarei uma coisa; se ma disserdes, eu de igual modo vos direi com que autoridade faço estas coisas.' },
      { v: 25, en: 'The baptism of John, where was it from? From heaven or from men?” They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will ask us, ‘Why then did you not believe him?’', pt: 'O batismo de João, donde era? do céu ou dos homens? Ao que eles arrazoavam entre si: Se dissermos: Do céu, ele nos dirá: Então por que não o crestes?' },
      { v: 26, en: 'But if we say, ‘From men,’ we fear the multitude, for all hold John as a prophet.”', pt: 'Mas, se dissermos: Dos homens, tememos o povo; porque todos consideram João como profeta.' },
      { v: 27, en: 'They answered Jesus, and said, “We don’t know.” He also said to them, “Neither will I tell you by what authority I do these things.', pt: 'Responderam, pois, a Jesus: Não sabemos. Disse-lhe ele: Nem eu vos digo com que autoridade faço estas coisas.' },
      { v: 28, en: 'But what do you think? A man had two sons, and he came to the first, and said, ‘Son, go work today in my vineyard.’', pt: 'Mas que vos parece? Um homem tinha dois filhos, e, chegando- se ao primeiro, disse: Filho, vai trabalhar hoje na vinha.' },
      { v: 29, en: 'He answered, ‘I will not,’ but afterward he changed his mind, and went.', pt: 'Ele respondeu: Sim, senhor; mas não foi.' },
      { v: 30, en: 'He came to the second, and said the same thing. He answered, ‘I’ m going, sir,’ but he didn’t go.', pt: 'Chegando-se, então, ao segundo, falou-lhe de igual modo; respondeu-lhe este: Não quero; mas depois, arrependendo-se, foi.' },
      { v: 31, en: 'Which of the two did the will of his father?” They said to him, “The first.” Jesus said to them, “Most certainly I tell you that the tax collectors and the prostitutes are entering into God’s Kingdom before you.', pt: 'Qual dos dois fez a vontade do pai? Disseram eles: O segundo. Disse-lhes Jesus: Em verdade vos digo que os publicanos e as meretrizes entram adiante de vós no reino de Deus.' },
      { v: 32, en: 'For John came to you in the way of righteousness, and you didn’t believe him, but the tax collectors and the prostitutes believed him. When you saw it, you didn’t even repent afterward, that you might believe him.', pt: 'Pois João veio a vós no caminho da justiça, e não lhe deste crédito, mas os publicanos e as meretrizes lho deram; vós, porém, vendo isto, nem depois vos arrependestes para crerdes nele.' },
      { v: 33, en: '“Hear another parable. There was a man who was a master of a household, who planted a vineyard, set a hedge about it, dug a wine press in it, built a tower, leased it out to farmers, and went into another country.', pt: 'Ouvi ainda outra parábola: Havia um homem, proprietário, que plantou uma vinha, cercou-a com uma sebe, cavou nela um lagar, e edificou uma torre; depois arrendou-a a uns lavradores e ausentou-se do país.' },
      { v: 34, en: 'When the season for the fruit came near, he sent his servants to the farmers, to receive his fruit.', pt: 'E quando chegou o tempo dos frutos, enviou os seus servos aos lavradores, para receber os seus frutos.' },
      { v: 35, en: 'The farmers took his servants, beat one, killed another, and stoned another.', pt: 'E os lavradores, apoderando-se dos servos, espancaram um, mataram outro, e a outro apedrejaram.' },
      { v: 36, en: 'Again, he sent other servants more than the first: and they treated them the same way.', pt: 'Depois enviou ainda outros servos, em maior número do que os primeiros; e fizeram-lhes o mesmo.' },
      { v: 37, en: 'But afterward he sent to them his son, saying, ‘They will respect my son.’', pt: 'Por último enviou-lhes seu filho, dizendo: A meu filho terão respeito.' },
      { v: 38, en: 'But the farmers, when they saw the son, said among themselves, ‘This is the heir. Come, let’s kill him, and seize his inheritance.’', pt: 'Mas os lavradores, vendo o filho, disseram entre si: Este é o herdeiro; vinde, matemo-lo, e apoderemo-nos da sua herança.' },
      { v: 39, en: 'So they took him, and threw him out of the vineyard, and killed him.', pt: 'E, agarrando-o, lançaram-no fora da vinha e o mataram.' },
      { v: 40, en: 'When therefore the lord of the vineyard comes, what will he do to those farmers?”', pt: 'Quando, pois, vier o senhor da vinha, que fará àqueles lavradores?' },
      { v: 41, en: 'They told him, “He will miserably destroy those miserable men, and will lease out the vineyard to other farmers, who will give him the fruit in its season.”', pt: 'Responderam-lhe eles: Fará perecer miseravelmente a esses maus, e arrendará a vinha a outros lavradores, que a seu tempo lhe entreguem os frutos.' },
      { v: 42, en: 'Jesus said to them, “Did you never read in the Scriptures, ‘The stone which the builders rejected, the same was made the head of the corner. This was from the Lord. It is marvelous in our eyes?’', pt: 'Disse-lhes Jesus: Nunca lestes nas Escrituras: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular; pelo Senhor foi feito isso, e é maravilhoso aos nossos olhos?' },
      { v: 43, en: '“Therefore I tell you, God’s Kingdom will be taken away from you, and will be given to a nation producing its fruit.', pt: 'Portanto eu vos digo que vos será tirado o reino de Deus, e será dado a um povo que dê os seus frutos.' },
      { v: 44, en: 'He who falls on this stone will be broken to pieces, but on whomever it will fall, it will scatter him as dust.”', pt: 'E quem cair sobre esta pedra será despedaçado; mas aquele sobre quem ela cair será reduzido a pó.' },
      { v: 45, en: 'When the chief priests and the Pharisees heard his parables, they perceived that he spoke about them.', pt: 'Os principais sacerdotes e os fariseus, ouvindo essas parábolas, entenderam que era deles que Jesus falava.' },
      { v: 46, en: 'When they sought to seize him, they feared the multitudes, because they considered him to be a prophet.', pt: 'E procuravam prendê-lo, mas temeram o povo, porquanto este o tinha por profeta.' },
    ],
    22: [
      { v: 1, en: 'Jesus answered and spoke to them again in parables, saying,', pt: 'Então Jesus tornou a falar-lhes por parábolas, dizendo:' },
      { v: 2, en: '“The Kingdom of Heaven is like a certain king, who made a marriage feast for his son,', pt: 'O reino dos céus é semelhante a um rei que celebrou as bodas de seu filho.' },
      { v: 3, en: 'and sent out his servants to call those who were invited to the marriage feast, but they would not come.', pt: 'Enviou os seus servos a chamar os convidados para as bodas, e estes não quiseram vir.' },
      { v: 4, en: 'Again he sent out other servants, saying, ‘Tell those who are invited, “Behold, I have prepared my dinner. My cattle and my fatlings are killed, and all things are ready. Come to the marriage feast!”’', pt: 'Depois enviou outros servos, ordenando: Dizei aos convidados: Eis que tenho o meu jantar preparado; os meus bois e cevados já estão mortos, e tudo está pronto; vinde às bodas.' },
      { v: 5, en: 'But they made light of it, and went their ways, one to his own farm, another to his merchandise,', pt: 'Eles, porém, não fazendo caso, foram, um para o seu campo, outro para o seu negócio;' },
      { v: 6, en: 'and the rest grabbed his servants, and treated them shamefully, and killed them.', pt: 'e os outros, apoderando-se dos servos, os ultrajaram e mataram.' },
      { v: 7, en: 'When the king heard that, he was angry, and sent his armies, destroyed those murderers, and burned their city.', pt: 'Mas o rei encolerizou-se; e enviando os seus exércitos, destruiu aqueles homicidas, e incendiou a sua cidade.' },
      { v: 8, en: '“Then he said to his servants, ‘The wedding is ready, but those who were invited weren’t worthy.', pt: 'Então disse aos seus servos: As bodas, na verdade, estão preparadas, mas os convidados não eram dignos.' },
      { v: 9, en: 'Go therefore to the intersections of the highways, and as many as you may find, invite to the marriage feast.’', pt: 'Ide, pois, pelas encruzilhadas dos caminhos, e a quantos encontrardes, convidai-os para as bodas.' },
      { v: 10, en: 'Those servants went out into the highways, and gathered together as many as they found, both bad and good. The wedding was filled with guests.', pt: 'E saíram aqueles servos pelos caminhos, e ajuntaram todos quantos encontraram, tanto maus como bons; e encheu-se de convivas a sala nupcial.' },
      { v: 11, en: 'But when the king came in to see the guests, he saw there a man who didn’t have on wedding clothing,', pt: 'Mas, quando o rei entrou para ver os convivas, viu ali um homem que não trajava veste nupcial;' },
      { v: 12, en: 'and he said to him, ‘Friend, how did you come in here not wearing wedding clothing?’ He was speechless.', pt: 'e perguntou-lhe: Amigo, como entraste aqui, sem teres veste nupcial? Ele, porém, emudeceu.' },
      { v: 13, en: 'Then the king said to the servants, ‘Bind him hand and foot, take him away, and throw him into the outer darkness. That is where the weeping and grinding of teeth will be.’', pt: 'Ordenou então o rei aos servos: Amarrai-o de pés e mãos, e lançai-o nas trevas exteriores; ali haverá choro e ranger de dentes.' },
      { v: 14, en: 'For many are called, but few chosen.”', pt: 'Porque muitos são chamados, mas poucos escolhidos.' },
      { v: 15, en: 'Then the Pharisees went and took counsel how they might entrap him in his talk.', pt: 'Então os fariseus se retiraram e consultaram entre si como o apanhariam em alguma palavra;' },
      { v: 16, en: 'They sent their disciples to him, along with the Herodians, saying, “Teacher, we know that you are honest, and teach the way of God in truth, no matter whom you teach, for you aren’t partial to anyone.', pt: 'e enviaram-lhe os seus discípulos, juntamente com os herodianos, a dizer; Mestre, sabemos que és verdadeiro, e que ensinas segundo a verdade o caminho de Deus, e de ninguém se te dá, porque não olhas a aparência dos homens.' },
      { v: 17, en: 'Tell us therefore, what do you think? Is it lawful to pay taxes to Caesar, or not?”', pt: 'Dize-nos, pois, que te parece? É lícito pagar tributo a César, ou não?' },
      { v: 18, en: 'But Jesus perceived their wickedness, and said, “Why do you test me, you hypocrites?', pt: 'Jesus, porém, percebendo a sua malícia, respondeu: Por que me experimentais, hipócritas?' },
      { v: 19, en: 'Show me the tax money.” They brought to him a denarius.', pt: 'Mostrai-me a moeda do tributo. E eles lhe apresentaram um denário.' },
      { v: 20, en: 'He asked them, “Whose is this image and inscription?”', pt: 'Perguntou-lhes ele: De quem é esta imagem e inscrição?' },
      { v: 21, en: 'They said to him, “Caesar’s.” Then he said to them, “Give therefore to Caesar the things that are Caesar’s, and to God the things that are God’s.”', pt: 'Responderam: De César. Então lhes disse: Dai, pois, a César o que é de César, e a Deus o que é de Deus.' },
      { v: 22, en: 'When they heard it, they marveled, and left him, and went away.', pt: 'Ao ouvirem isso, ficaram admirados; e, deixando-o, se retiraram.' },
      { v: 23, en: 'On that day Sadducees (those who say that there is no resurrection) came to him. They asked him,', pt: 'No mesmo dia vieram alguns saduceus, que dizem não haver ressurreição, e o interrogaram, dizendo:' },
      { v: 24, en: 'saying, “Teacher, Moses said, ‘If a man dies, having no children, his brother shall marry his wife, and raise up offspring for his brother.’', pt: 'Mestre, Moisés disse: Se morrer alguém, não tendo filhos, seu irmão casará com a mulher dele, e suscitará descendência a seu irmão.' },
      { v: 25, en: 'Now there were with us seven brothers. The first married and died, and having no offspring left his wife to his brother.', pt: 'Ora, havia entre nós sete irmãos: o primeiro, tendo casado, morreu: e, não tendo descendência, deixou sua mulher a seu irmão;' },
      { v: 26, en: 'In the same way, the second also, and the third, to the seventh.', pt: 'da mesma sorte também o segundo, o terceiro, até o sétimo.' },
      { v: 27, en: 'After them all, the woman died.', pt: 'depois de todos, morreu também a mulher.' },
      { v: 28, en: 'In the resurrection therefore, whose wife will she be of the seven? For they all had her.”', pt: 'Portanto, na ressurreição, de qual dos sete será ela esposa, pois todos a tiveram?' },
      { v: 29, en: 'But Jesus answered them, “You are mistaken, not knowing the Scriptures, nor the power of God.', pt: 'Jesus, porém, lhes respondeu: Errais, não compreendendo as Escrituras nem o poder de Deus;' },
      { v: 30, en: 'For in the resurrection they neither marry, nor are given in marriage, but are like God’s angels in heaven.', pt: 'pois na ressurreição nem se casam nem se dão em casamento; mas serão como os anjos no céu.' },
      { v: 31, en: 'But concerning the resurrection of the dead, haven’t you read that which was spoken to you by God, saying,', pt: 'E, quanto à ressurreição dos mortos, não lestes o que foi dito por Deus:' },
      { v: 32, en: '‘I am the God of Abraham, and the God of Isaac, and the God of Jacob?’ God is not the God of the dead, but of the living.”', pt: 'Eu sou o Deus de Abraão, o Deus de Isaque, e o Deus de Jacó? Ora, ele não é Deus de mortos, mas de vivos.' },
      { v: 33, en: 'When the multitudes heard it, they were astonished at his teaching.', pt: 'E as multidões, ouvindo isso, se maravilhavam da sua doutrina.' },
      { v: 34, en: 'But the Pharisees, when they heard that he had silenced the Sadducees, gathered themselves together.', pt: 'Os fariseus, quando souberam, que ele fizera emudecer os saduceus, reuniram-se todos;' },
      { v: 35, en: 'One of them, a lawyer, asked him a question, testing him.', pt: 'e um deles, doutor da lei, para o experimentar, interrogou- o, dizendo:' },
      { v: 36, en: '“Teacher, which is the greatest commandment in the law?”', pt: 'Mestre, qual é o grande mandamento na lei?' },
      { v: 37, en: 'Jesus said to him, “‘You shall love the Lord your God with all your heart, with all your soul, and with all your mind.’', pt: 'Respondeu-lhe Jesus: Amarás ao Senhor teu Deus de todo o teu coração, de toda a tua alma, e de todo o teu entendimento.' },
      { v: 38, en: 'This is the first and great commandment.', pt: 'Este é o grande e primeiro mandamento.' },
      { v: 39, en: 'A second likewise is this, ‘You shall love your neighbor as yourself.’', pt: 'E o segundo, semelhante a este, é: Amarás ao teu próximo como a ti mesmo.' },
      { v: 40, en: 'The whole law and the prophets depend on these two commandments.”', pt: 'Destes dois mandamentos dependem toda a lei e os profetas.' },
      { v: 41, en: 'Now while the Pharisees were gathered together, Jesus asked them a question,', pt: 'Ora, enquanto os fariseus estavam reunidos, interrogou-os Jesus, dizendo:' },
      { v: 42, en: 'saying, “What do you think of the Christ? Whose son is he?” They said to him, “Of David.”', pt: 'Que pensais vós do Cristo? De quem é filho? Responderam-lhe: De Davi.' },
      { v: 43, en: 'He said to them, “How then does David in the Spirit call him Lord, saying,', pt: 'Replicou-lhes ele: Como é então que Davi, no Espírito, lhe chama Senhor, dizendo:' },
      { v: 44, en: '‘The Lord said to my Lord, sit on my right hand, until I make your enemies a footstool for your feet?’', pt: 'Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos de baixo dos teus pés?' },
      { v: 45, en: '“If then David calls him Lord, how is he his son?”', pt: 'Se Davi, pois, lhe chama Senhor, como é ele seu filho?' },
      { v: 46, en: 'No one was able to answer him a word, neither did any man dare ask him any more questions from that day forward.', pt: 'E ninguém podia responder-lhe palavra; nem desde aquele dia jamais ousou alguém interrogá-lo.' },
    ],
    23: [
      { v: 1, en: 'Then Jesus spoke to the multitudes and to his disciples,', pt: 'Então falou Jesus às multidões e aos seus discípulos, dizendo:' },
      { v: 2, en: 'saying, “The scribes and the Pharisees sat on Moses’ seat.', pt: 'Na cadeira de Moisés se assentam os escribas e fariseus.' },
      { v: 3, en: 'All things therefore whatever they tell you to observe, observe and do, but don’t do their works; for they say, and don’t do.', pt: 'Portanto, tudo o que vos disserem, isso fazei e observai; mas não façais conforme as suas obras; porque dizem e não praticam.' },
      { v: 4, en: 'For they bind heavy burdens that are grievous to be borne, and lay them on men’s shoulders; but they themselves will not lift a finger to help them.', pt: 'Pois atam fardos pesados e difíceis de suportar, e os põem aos ombros dos homens; mas eles mesmos nem com o dedo querem movê-los.' },
      { v: 5, en: 'But all their works they do to be seen by men. They make their phylacteries broad, enlarge the fringes of their garments,', pt: 'Todas as suas obras eles fazem a fim de serem vistos pelos homens; pois alargam os seus filactérios, e aumentam as franjas dos seus mantos;' },
      { v: 6, en: 'and love the place of honor at feasts, the best seats in the synagogues,', pt: 'gostam do primeiro lugar nos banquetes, das primeiras cadeiras nas sinagogas,' },
      { v: 7, en: 'the salutations in the marketplaces, and to be called ‘Rabbi, Rabbi’ by men.', pt: 'das saudações nas praças, e de serem chamados pelos homens: Rabi.' },
      { v: 8, en: 'But don’t you be called ‘Rabbi,’ for one is your teacher, the Christ, and all of you are brothers.', pt: 'Vós, porém, não queirais ser chamados Rabi; porque um só é o vosso Mestre, e todos vós sois irmãos.' },
      { v: 9, en: 'Call no man on the earth your father, for one is your Father, he who is in heaven.', pt: 'E a ninguém sobre a terra chameis vosso pai; porque um só é o vosso Pai, aquele que está nos céus.' },
      { v: 10, en: 'Neither be called masters, for one is your master, the Christ.', pt: 'Nem queirais ser chamados guias; porque um só é o vosso Guia, que é o Cristo.' },
      { v: 11, en: 'But he who is greatest among you will be your servant.', pt: 'Mas o maior dentre vós há de ser vosso servo.' },
      { v: 12, en: 'Whoever exalts himself will be humbled, and whoever humbles himself will be exalted.', pt: 'Qualquer, pois, que a si mesmo se exaltar, será humilhado; e qualquer que a si mesmo se humilhar, será exaltado.' },
      { v: 13, en: '“Woe to you, scribes and Pharisees, hypocrites! For you devour widows’ houses, and as a pretense you make long prayers. Therefore you will receive greater condemnation.', pt: 'Mas ai de vós, escribas e fariseus, hipócritas! porque fechais aos homens o reino dos céus; pois nem vós entrais, nem aos que entrariam permitis entrar.' },
      { v: 14, en: '“But woe to you, scribes and Pharisees, hypocrites! Because you shut up the Kingdom of Heaven against men; for you don’t enter in yourselves, neither do you allow those who are entering in to enter.', pt: '[Ai de vós, escribas e fariseus, hipócritas! porque devorais as casas das viúvas e sob pretexto fazeis longas orações; por isso recebereis maior condenação.]' },
      { v: 15, en: 'Woe to you, scribes and Pharisees, hypocrites! For you travel around by sea and land to make one proselyte; and when he becomes one, you make him twice as much a son of Gehenna as yourselves.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque percorreis o mar e a terra para fazer um prosélito; e, depois de o terdes feito, o tornais duas vezes mais filho do inferno do que vós.' },
      { v: 16, en: '“Woe to you, you blind guides, who say, ‘Whoever swears by the temple, it is nothing; but whoever swears by the gold of the temple, he is obligated.’', pt: 'Ai de vós, guias cegos! que dizeis: Quem jurar pelo ouro do santuário, esse fica obrigado ao que jurou.' },
      { v: 17, en: 'You blind fools! For which is greater, the gold, or the temple that sanctifies the gold?', pt: 'Insensatos e cegos! Pois qual é o maior; o ouro, ou o santuário que santifica o ouro?' },
      { v: 18, en: '‘Whoever swears by the altar, it is nothing; but whoever swears by the gift that is on it, he is obligated?’', pt: 'E: Quem jurar pelo altar, isso nada é; mas quem jurar pela oferta que está sobre o altar, esse fica obrigado ao que jurou.' },
      { v: 19, en: 'You blind fools! For which is greater, the gift, or the altar that sanctifies the gift?', pt: 'Cegos! Pois qual é maior: a oferta, ou o altar que santifica a oferta?' },
      { v: 20, en: 'He therefore who swears by the altar, swears by it, and by everything on it.', pt: 'Portanto, quem jurar pelo altar jura por ele e por tudo quanto sobre ele está;' },
      { v: 21, en: 'He who swears by the temple, swears by it, and by him who has been living in it.', pt: 'e quem jurar pelo santuário jura por ele e por aquele que nele habita;' },
      { v: 22, en: 'He who swears by heaven, swears by the throne of God, and by him who sits on it.', pt: 'e quem jurar pelo céu jura pelo trono de Deus e por aquele que nele está assentado.' },
      { v: 23, en: '“Woe to you, scribes and Pharisees, hypocrites! For you tithe mint, dill, and cumin, and have left undone the weightier matters of the law: justice, mercy, and faith. But you ought to have done these, and not to have left the other undone.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque dais o dízimo da hortelã, do endro e do cominho, e tendes omitido o que há de mais importante na lei, a saber, a justiça, a misericórdia e a fé; estas coisas, porém, devíeis fazer, sem omitir aquelas.' },
      { v: 24, en: 'You blind guides, who strain out a gnat, and swallow a camel!', pt: 'Guias cegos! que coais um mosquito, e engulis um camelo.' },
      { v: 25, en: '“Woe to you, scribes and Pharisees, hypocrites! For you clean the outside of the cup and of the platter, but within they are full of extortion and unrighteousness.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque limpais o exterior do copo e do prato, mas por dentro estão cheios de rapina e de intemperança.' },
      { v: 26, en: 'You blind Pharisee, first clean the inside of the cup and of the platter, that its outside may become clean also.', pt: 'Fariseu cego! limpa primeiro o interior do copo, para que também o exterior se torne limpo.' },
      { v: 27, en: '“Woe to you, scribes and Pharisees, hypocrites! For you are like whitened tombs, which outwardly appear beautiful, but inwardly are full of dead men’s bones, and of all uncleanness.', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque sois semelhantes aos sepulcros caiados, que por fora realmente parecem formosos, mas por dentro estão cheios de ossos e de toda imundícia.' },
      { v: 28, en: 'Even so you also outwardly appear righteous to men, but inwardly you are full of hypocrisy and iniquity.', pt: 'Assim também vós exteriormente pareceis justos aos homens, mas por dentro estais cheios de hipocrisia e de iniquidade.' },
      { v: 29, en: '“Woe to you, scribes and Pharisees, hypocrites! For you build the tombs of the prophets, and decorate the tombs of the righteous,', pt: 'Ai de vós, escribas e fariseus, hipócritas! porque edificais os sepulcros dos profetas e adornais os monumentos dos justos,' },
      { v: 30, en: 'and say, ‘If we had lived in the days of our fathers, we wouldn’t have been partakers with them in the blood of the prophets.’', pt: 'e dizeis: Se tivéssemos vivido nos dias de nossos pais, não teríamos sido cúmplices no derramar o sangue dos profetas.' },
      { v: 31, en: 'Therefore you testify to yourselves that you are children of those who killed the prophets.', pt: 'Assim, vós testemunhais contra vós mesmos que sois filhos daqueles que mataram os profetas.' },
      { v: 32, en: 'Fill up, then, the measure of your fathers.', pt: 'Enchei vós, pois, a medida de vossos pais.' },
      { v: 33, en: 'You serpents, you offspring of vipers, how will you escape the judgment of Gehenna?', pt: 'Serpentes, raça de víboras! como escapareis da condenação do inferno?' },
      { v: 34, en: 'Therefore behold, I send to you prophets, wise men, and scribes. Some of them you will kill and crucify; and some of them you will scourge in your synagogues, and persecute from city to city;', pt: 'Portanto, eis que eu vos envio profetas, sábios e escribas: e a uns deles matareis e crucificareis; e a outros os perseguireis de cidade em cidade;' },
      { v: 35, en: 'that on you may come all the righteous blood shed on the earth, from the blood of righteous Abel to the blood of Zachariah son of Barachiah, whom you killed between the sanctuary and the altar.', pt: 'para que sobre vós caia todo o sangue justo, que foi derramado sobre a terra, desde o sangue de Abel, o justo, até o sangue de Zacarias, filho de Baraquias, que mataste entre o santuário e o altar.' },
      { v: 36, en: 'Most certainly I tell you, all these things will come upon this generation.', pt: 'Em verdade vos digo que todas essas coisas hão de vir sobre esta geração.' },
      { v: 37, en: '“Jerusalem, Jerusalem, who kills the prophets, and stones those who are sent to her! How often I would have gathered your children together, even as a hen gathers her chicks under her wings, and you would not!', pt: 'Jerusalém, Jerusalém, que matas os profetas, apedrejas os que a ti são enviados! quantas vezes quis eu ajuntar os teus filhos, como a galinha ajunta os seus pintos debaixo das asas, e não o quiseste!' },
      { v: 38, en: 'Behold, your house is left to you desolate.', pt: 'Eis aí abandonada vos é a vossa casa.' },
      { v: 39, en: 'For I tell you, you will not see me from now on, until you say, ‘Blessed is he who comes in the name of the Lord!’”', pt: 'Pois eu vos declaro que desde agora de modo nenhum me vereis, até que digais: Bendito aquele que vem em nome do Senhor.' },
    ],
    24: [
      { v: 1, en: 'Jesus went out from the temple, and was going on his way. His disciples came to him to show him the buildings of the temple.', pt: 'Ora, Jesus, tendo saído do templo, ia-se retirando, quando se aproximaram dele os seus discípulos, para lhe mostrarem os edifícios do templo.' },
      { v: 2, en: 'But he answered them, “You see all of these things, don’t you? Most certainly I tell you, there will not be left here one stone on another, that will not be thrown down.”', pt: 'Mas ele lhes disse: Não vedes tudo isto? Em verdade vos digo que não se deixará aqui pedra sobre pedra que não seja derribada.' },
      { v: 3, en: 'As he sat on the Mount of Olives, the disciples came to him privately, saying, “Tell us, when will these things be? What is the sign of your coming, and of the end of the age?”', pt: 'E estando ele sentado no Monte das Oliveiras, chegaram-se a ele os seus discípulos em particular, dizendo: Declara-nos quando serão essas coisas, e que sinal haverá da tua vinda e do fim do mundo.' },
      { v: 4, en: 'Jesus answered them, “Be careful that no one leads you astray.', pt: 'Respondeu-lhes Jesus: Acautelai-vos, que ninguém vos engane.' },
      { v: 5, en: 'For many will come in my name, saying, ‘I am the Christ,’ and will lead many astray.', pt: 'Porque muitos virão em meu nome, dizendo: Eu sou o Cristo; a muitos enganarão.' },
      { v: 6, en: 'You will hear of wars and rumors of wars. See that you aren’t troubled, for all this must happen, but the end is not yet.', pt: 'E ouvireis falar de guerras e rumores de guerras; olhai não vos perturbeis; porque forçoso é que assim aconteça; mas ainda não é o fim.' },
      { v: 7, en: 'For nation will rise against nation, and kingdom against kingdom; and there will be famines, plagues, and earthquakes in various places.', pt: 'Porquanto se levantará nação contra nação, e reino contra reino; e haverá fomes e terremotos em vários lugares.' },
      { v: 8, en: 'But all these things are the beginning of birth pains.', pt: 'Mas todas essas coisas são o princípio das dores.' },
      { v: 9, en: 'Then they will deliver you up to oppression, and will kill you. You will be hated by all of the nations for my name’s sake.', pt: 'Então sereis entregues à tortura, e vos matarão; e sereis odiados de todas as nações por causa do meu nome.' },
      { v: 10, en: 'Then many will stumble, and will deliver up one another, and will hate one another.', pt: 'Nesse tempo muitos hão de se escandalizar, e trair-se uns aos outros, e mutuamente se odiarão.' },
      { v: 11, en: 'Many false prophets will arise, and will lead many astray.', pt: 'Igualmente hão de surgir muitos falsos profetas, e enganarão a muitos;' },
      { v: 12, en: 'Because iniquity will be multiplied, the love of many will grow cold.', pt: 'e, por se multiplicar a iniquidade, o amor de muitos esfriará.' },
      { v: 13, en: 'But he who endures to the end, the same will be saved.', pt: 'Mas quem perseverar até o fim, esse será salvo.' },
      { v: 14, en: 'This Good News of the Kingdom will be preached in the whole world for a testimony to all the nations, and then the end will come.', pt: 'E este evangelho do reino será pregado no mundo inteiro, em testemunho a todas as nações, e então virá o fim.' },
      { v: 15, en: '“When, therefore, you see the abomination of desolation, which was spoken of through Daniel the prophet, standing in the holy place (let the reader understand),', pt: 'Quando, pois, virdes estar no lugar santo a abominação de desolação, predita pelo profeta Daniel (quem lê, entenda),' },
      { v: 16, en: 'then let those who are in Judea flee to the mountains.', pt: 'então os que estiverem na Judéia fujam para os montes;' },
      { v: 17, en: 'Let him who is on the housetop not go down to take out the things that are in his house.', pt: 'quem estiver no eirado não desça para tirar as coisas de sua casa,' },
      { v: 18, en: 'Let him who is in the field not return back to get his clothes.', pt: 'e quem estiver no campo não volte atrás para apanhar a sua capa.' },
      { v: 19, en: 'But woe to those who are with child and to nursing mothers in those days!', pt: 'Mas ai das que estiverem grávidas, e das que amamentarem naqueles dias!' },
      { v: 20, en: 'Pray that your flight will not be in the winter, nor on a Sabbath,', pt: 'Orai para que a vossa fuga não suceda no inverno nem no sábado;' },
      { v: 21, en: 'for then there will be great oppression, such as has not been from the beginning of the world until now, no, nor ever will be.', pt: 'porque haverá então uma tribulação tão grande, como nunca houve desde o princípio do mundo até agora, nem jamais haverá.' },
      { v: 22, en: 'Unless those days had been shortened, no flesh would have been saved. But for the sake of the chosen ones, those days will be shortened.', pt: 'E se aqueles dias não fossem abreviados, ninguém se salvaria; mas por causa dos escolhidos serão abreviados aqueles dias.' },
      { v: 23, en: '“Then if any man tells you, ‘Behold, here is the Christ,’ or, ‘There,’ don’t believe it.', pt: 'Se, pois, alguém vos disser: Eis aqui o Cristo! ou: Ei-lo aí! não acrediteis;' },
      { v: 24, en: 'For there will arise false christs, and false prophets, and they will show great signs and wonders, so as to lead astray, if possible, even the chosen ones.', pt: 'porque hão de surgir falsos cristos e falsos profetas, e farão grandes sinais e prodígios; de modo que, se possível fora, enganariam até os escolhidos.' },
      { v: 25, en: '“Behold, I have told you beforehand.', pt: 'Eis que de antemão vo-lo tenho dito.' },
      { v: 26, en: 'If therefore they tell you, ‘Behold, he is in the wilderness,’ don’t go out; ‘Behold, he is in the inner rooms,’ don’t believe it.', pt: 'Portanto, se vos disserem: Eis que ele está no deserto; não saiais; ou: Eis que ele está no interior da casa; não acrediteis.' },
      { v: 27, en: 'For as the lightning flashes from the east, and is seen even to the west, so will be the coming of the Son of Man.', pt: 'Porque, assim como o relâmpago sai do oriente e se mostra até o ocidente, assim será também a vinda do filho do homem.' },
      { v: 28, en: 'For wherever the carcass is, that is where the vultures gather together.', pt: 'Pois onde estiver o cadáver, aí se ajuntarão os abutres.' },
      { v: 29, en: 'But immediately after the oppression of those days, the sun will be darkened, the moon will not give its light, the stars will fall from the sky, and the powers of the heavens will be shaken;', pt: 'Logo depois da tribulação daqueles dias, escurecerá o sol, e a lua não dará a sua luz; as estrelas cairão do céu e os poderes dos céus serão abalados.' },
      { v: 30, en: 'and then the sign of the Son of Man will appear in the sky. Then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of the sky with power and great glory.', pt: 'Então aparecerá no céu o sinal do Filho do homem, e todas as tribos da terra se lamentarão, e verão vir o Filho do homem sobre as nuvens do céu, com poder e grande glória.' },
      { v: 31, en: 'He will send out his angels with a great sound of a trumpet, and they will gather together his chosen ones from the four winds, from one end of the sky to the other.', pt: 'E ele enviará os seus anjos com grande clangor de trombeta, os quais lhe ajuntarão os escolhidos desde os quatro ventos, de uma à outra extremidade dos céus.' },
      { v: 32, en: '“Now from the fig tree learn this parable. When its branch has now become tender, and produces its leaves, you know that the summer is near.', pt: 'Aprendei, pois, da figueira a sua parábola: Quando já o seu ramo se torna tenro e brota folhas, sabeis que está próximo o verão.' },
      { v: 33, en: 'Even so you also, when you see all these things, know that it is near, even at the doors.', pt: 'Igualmente, quando virdes todas essas coisas, sabei que ele está próximo, mesmo às portas.' },
      { v: 34, en: 'Most certainly I tell you, this generation will not pass away, until all these things are accomplished.', pt: 'Em verdade vos digo que não passará esta geração sem que todas essas coisas se cumpram.' },
      { v: 35, en: 'Heaven and earth will pass away, but my words will not pass away.', pt: 'Passará o céu e a terra, mas as minhas palavras jamais passarão.' },
      { v: 36, en: 'But no one knows of that day and hour, not even the angels of heaven, but my Father only.', pt: 'Daquele dia e hora, porém, ninguém sabe, nem os anjos do céu, nem o Filho, senão só o Pai.' },
      { v: 37, en: '“As the days of Noah were, so will be the coming of the Son of Man.', pt: 'Pois como foi dito nos dias de Noé, assim será também a vinda do Filho do homem.' },
      { v: 38, en: 'For as in those days which were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ship,', pt: 'Porquanto, assim como nos dias anteriores ao dilúvio, comiam, bebiam, casavam e davam-se em casamento, até o dia em que Noé entrou na arca,' },
      { v: 39, en: 'and they didn’t know until the flood came, and took them all away, so will be the coming of the Son of Man.', pt: 'e não o perceberam, até que veio o dilúvio, e os levou a todos; assim será também a vinda do Filho do homem.' },
      { v: 40, en: 'Then two men will be in the field: one will be taken and one will be left.', pt: 'Então, estando dois homens no campo, será levado um e deixado outro;' },
      { v: 41, en: 'Two women will be grinding at the mill: one will be taken and one will be left.', pt: 'estando duas mulheres a trabalhar no moinho, será levada uma e deixada a outra.' },
      { v: 42, en: 'Watch therefore, for you don’t know in what hour your Lord comes.', pt: 'Vigiai, pois, porque não sabeis em que dia vem o vosso Senhor;' },
      { v: 43, en: 'But know this, that if the master of the house had known in what watch of the night the thief was coming, he would have watched, and would not have allowed his house to be broken into.', pt: 'sabei, porém, isto: se o dono da casa soubesse a que vigília da noite havia de vir o ladrão, vigiaria e não deixaria minar a sua casa.' },
      { v: 44, en: 'Therefore also be ready, for in an hour that you don’t expect, the Son of Man will come.', pt: 'Por isso ficai também vós apercebidos; porque numa hora em que não penseis, virá o Filho do homem.' },
      { v: 45, en: '“Who then is the faithful and wise servant, whom his lord has set over his household, to give them their food in due season?', pt: 'Quem é, pois, o servo fiel e prudente, que o senhor pôs sobre os seus serviçais, para a tempo dar-lhes o sustento?' },
      { v: 46, en: 'Blessed is that servant whom his lord finds doing so when he comes.', pt: 'Bem-aventurado aquele servo a quem o seu senhor, quando vier, achar assim fazendo.' },
      { v: 47, en: 'Most certainly I tell you that he will set him over all that he has.', pt: 'Em verdade vos digo que o porá sobre todos os seus bens.' },
      { v: 48, en: 'But if that evil servant should say in his heart, ‘My lord is delaying his coming,’', pt: 'Mas se aquele outro, o mau servo, disser no seu coração: Meu senhor tarda em vir,' },
      { v: 49, en: 'and begins to beat his fellow servants, and eat and drink with the drunkards,', pt: 'e começar a espancar os seus conservos, e a comer e beber com os ébrios,' },
      { v: 50, en: 'the lord of that servant will come in a day when he doesn’t expect it, and in an hour when he doesn’t know it,', pt: 'virá o senhor daquele servo, num dia em que não o espera, e numa hora de que não sabe,' },
      { v: 51, en: 'and will cut him in pieces, and appoint his portion with the hypocrites. That is where the weeping and grinding of teeth will be.', pt: 'e cortá-lo-á pelo meio, e lhe dará a sua parte com os hipócritas; ali haverá choro e ranger de dentes.' },
    ],
    25: [
      { v: 1, en: '“Then the Kingdom of Heaven will be like ten virgins, who took their lamps, and went out to meet the bridegroom.', pt: 'Então o reino dos céus será semelhante a dez virgens que, tomando as suas lâmpadas, saíram ao encontro do noivo.' },
      { v: 2, en: 'Five of them were foolish, and five were wise.', pt: 'Cinco delas eram insensatas, e cinco prudentes.' },
      { v: 3, en: 'Those who were foolish, when they took their lamps, took no oil with them,', pt: 'Ora, as insensatas, tomando as lâmpadas, não levaram azeite consigo.' },
      { v: 4, en: 'but the wise took oil in their vessels with their lamps.', pt: 'As prudentes, porém, levaram azeite em suas vasilhas, juntamente com as lâmpadas.' },
      { v: 5, en: 'Now while the bridegroom delayed, they all slumbered and slept.', pt: 'E tardando o noivo, cochilaram todas, e dormiram.' },
      { v: 6, en: 'But at midnight there was a cry, ‘Behold! The bridegroom is coming! Come out to meet him!’', pt: 'Mas à meia-noite ouviu-se um grito: Eis o noivo! saí-lhe ao encontro!' },
      { v: 7, en: 'Then all those virgins arose, and trimmed their lamps.', pt: 'Então todas aquelas virgens se levantaram, e prepararam as suas lâmpadas.' },
      { v: 8, en: 'The foolish said to the wise, ‘Give us some of your oil, for our lamps are going out.’', pt: 'E as insensatas disseram às prudentes: Dai-nos do vosso azeite, porque as nossas lâmpadas estão se apagando.' },
      { v: 9, en: 'But the wise answered, saying, ‘What if there isn’t enough for us and you? You go rather to those who sell, and buy for yourselves.’', pt: 'Mas as prudentes responderam: não; pois de certo não chegaria para nós e para vós; ide antes aos que o vendem, e comprai-o para vós.' },
      { v: 10, en: 'While they went away to buy, the bridegroom came, and those who were ready went in with him to the marriage feast, and the door was shut.', pt: 'E, tendo elas ido comprá-lo, chegou o noivo; e as que estavam preparadas entraram com ele para as bodas, e fechou-se a porta.' },
      { v: 11, en: 'Afterward the other virgins also came, saying, ‘Lord, Lord, open to us.’', pt: 'Depois vieram também as outras virgens, e disseram: Senhor, Senhor, abre-nos a porta.' },
      { v: 12, en: 'But he answered, ‘Most certainly I tell you, I don’t know you.’', pt: 'Ele, porém, respondeu: Em verdade vos digo, não vos conheço.' },
      { v: 13, en: 'Watch therefore, for you don’t know the day nor the hour in which the Son of Man is coming.', pt: 'Vigiai pois, porque não sabeis nem o dia nem a hora.' },
      { v: 14, en: '“For it is like a man, going into another country, who called his own servants, and entrusted his goods to them.', pt: 'Porque é assim como um homem que, ausentando-se do país, chamou os seus servos e lhes entregou os seus bens:' },
      { v: 15, en: 'To one he gave five talents, to another two, to another one; to each according to his own ability. Then he went on his journey.', pt: 'a um deu cinco talentos, a outro dois, e a outro um, a cada um segundo a sua capacidade; e seguiu viagem.' },
      { v: 16, en: 'Immediately he who received the five talents went and traded with them, and made another five talents.', pt: 'O que recebera cinco talentos foi imediatamente negociar com eles, e ganhou outros cinco;' },
      { v: 17, en: 'In the same way, he also who got the two gained another two.', pt: 'da mesma sorte, o que recebera dois ganhou outros dois;' },
      { v: 18, en: 'But he who received the one talent went away and dug in the earth, and hid his lord’s money.', pt: 'mas o que recebera um foi e cavou na terra e escondeu o dinheiro do seu senhor.' },
      { v: 19, en: '“Now after a long time the lord of those servants came, and reconciled accounts with them.', pt: 'Ora, depois de muito tempo veio o senhor daqueles servos, e fez contas com eles.' },
      { v: 20, en: 'He who received the five talents came and brought another five talents, saying, ‘Lord, you delivered to me five talents. Behold, I have gained another five talents besides them.’', pt: 'Então chegando o que recebera cinco talentos, apresentou-lhe outros cinco talentos, dizendo: Senhor, entregaste-me cinco talentos; eis aqui outros cinco que ganhei.' },
      { v: 21, en: '“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’', pt: 'Disse-lhe o seu senhor: Muito bem, servo bom e fiel; sobre o pouco foste fiel, sobre muito te colocarei; entra no gozo do teu senhor.' },
      { v: 22, en: '“He also who got the two talents came and said, ‘Lord, you delivered to me two talents. Behold, I have gained another two talents besides them.’', pt: 'Chegando também o que recebera dois talentos, disse: Senhor, entregaste-me dois talentos; eis aqui outros dois que ganhei.' },
      { v: 23, en: '“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’', pt: 'Disse-lhe o seu senhor: Muito bem, servo bom e fiel; sobre o pouco foste fiel, sobre muito te colocarei; entra no gozo do teu senhor.' },
      { v: 24, en: '“He also who had received the one talent came and said, ‘Lord, I knew you that you are a hard man, reaping where you did not sow, and gathering where you did not scatter.', pt: 'Chegando por fim o que recebera um talento, disse: Senhor, eu te conhecia, que és um homem duro, que ceifas onde não semeaste, e recolhes onde não joeiraste;' },
      { v: 25, en: 'I was afraid, and went away and hid your talent in the earth. Behold, you have what is yours.’', pt: 'e, atemorizado, fui esconder na terra o teu talento; eis aqui tens o que é teu.' },
      { v: 26, en: '“But his lord answered him, ‘You wicked and slothful servant. You knew that I reap where I didn’t sow, and gather where I didn’t scatter.', pt: 'Ao que lhe respondeu o seu senhor: Servo mau e preguiçoso, sabias que ceifo onde não semeei, e recolho onde não joeirei?' },
      { v: 27, en: 'You ought therefore to have deposited my money with the bankers, and at my coming I should have received back my own with interest.', pt: 'Devias então entregar o meu dinheiro aos banqueiros e, vindo eu, tê-lo-ia recebido com juros.' },
      { v: 28, en: 'Take away therefore the talent from him, and give it to him who has the ten talents.', pt: 'Tirai-lhe, pois, o talento e dai ao que tem os dez talentos.' },
      { v: 29, en: 'For to everyone who has will be given, and he will have abundance, but from him who doesn’t have, even that which he has will be taken away.', pt: 'Porque a todo o que tem, dar-se-lhe-á, e terá em abundância; mas ao que não tem, até aquilo que tem ser-lhe-á tirado.' },
      { v: 30, en: 'Throw out the unprofitable servant into the outer darkness, where there will be weeping and gnashing of teeth.’', pt: 'E lançai o servo inútil nas trevas exteriores; ali haverá choro e ranger de dentes.' },
      { v: 31, en: '“But when the Son of Man comes in his glory, and all the holy angels with him, then he will sit on the throne of his glory.', pt: 'Quando, pois vier o Filho do homem na sua glória, e todos os anjos com ele, então se assentará no trono da sua glória;' },
      { v: 32, en: 'Before him all the nations will be gathered, and he will separate them one from another, as a shepherd separates the sheep from the goats.', pt: 'e diante dele serão reunidas todas as nações; e ele separará uns dos outros, como o pastor separa as ovelhas dos cabritos;' },
      { v: 33, en: 'He will set the sheep on his right hand, but the goats on the left.', pt: 'e porá as ovelhas à sua direita, mas os cabritos à esquerda.' },
      { v: 34, en: 'Then the King will tell those on his right hand, ‘Come, blessed of my Father, inherit the Kingdom prepared for you from the foundation of the world;', pt: 'Então dirá o Rei aos que estiverem à sua direita: Vinde, benditos de meu Pai. Possuí por herança o reino que vos está preparado desde a fundação do mundo;' },
      { v: 35, en: 'for I was hungry, and you gave me food to eat. I was thirsty, and you gave me drink. I was a stranger, and you took me in.', pt: 'porque tive fome, e me destes de comer; tive sede, e me destes de beber; era forasteiro, e me acolhestes;' },
      { v: 36, en: 'I was naked, and you clothed me. I was sick, and you visited me. I was in prison, and you came to me.’', pt: 'estava nu, e me vestistes; adoeci, e me visitastes; estava na prisão e fostes ver-me.' },
      { v: 37, en: '“Then the righteous will answer him, saying, ‘Lord, when did we see you hungry, and feed you; or thirsty, and give you a drink?', pt: 'Então os justos lhe perguntarão: Senhor, quando te vimos com fome, e te demos de comer? ou com sede, e te demos de beber?' },
      { v: 38, en: 'When did we see you as a stranger, and take you in; or naked, and clothe you?', pt: 'Quando te vimos forasteiro, e te acolhemos? ou nu, e te vestimos?' },
      { v: 39, en: 'When did we see you sick, or in prison, and come to you?’', pt: 'Quando te vimos enfermo, ou na prisão, e fomos visitar-te?' },
      { v: 40, en: '“The King will answer them, ‘Most certainly I tell you, because you did it to one of the least of these my brothers, you did it to me.’', pt: 'E responder-lhes-á o Rei: Em verdade vos digo que, sempre que o fizestes a um destes meus irmãos, mesmo dos mais pequeninos, a mim o fizestes.' },
      { v: 41, en: 'Then he will say also to those on the left hand, ‘Depart from me, you cursed, into the eternal fire which is prepared for the devil and his angels;', pt: 'Então dirá também aos que estiverem à sua esquerda: Apartai- vos de mim, malditos, para o fogo eterno, preparado para o Diabo e seus anjos;' },
      { v: 42, en: 'for I was hungry, and you didn’t give me food to eat; I was thirsty, and you gave me no drink;', pt: 'porque tive fome, e não me destes de comer; tive sede, e não me destes de beber;' },
      { v: 43, en: 'I was a stranger, and you didn’t take me in; naked, and you didn’t clothe me; sick, and in prison, and you didn’t visit me.’', pt: 'era forasteiro, e não me acolhestes; estava nu, e não me vestistes; enfermo, e na prisão, e não me visitastes.' },
      { v: 44, en: '“Then they will also answer, saying, ‘Lord, when did we see you hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and didn’t help you?’', pt: 'Então também estes perguntarão: Senhor, quando te vimos com fome, ou com sede, ou forasteiro, ou nu, ou enfermo, ou na prisão, e não te servimos?' },
      { v: 45, en: '“Then he will answer them, saying, ‘Most certainly I tell you, because you didn’t do it to one of the least of these, you didn’t do it to me.’', pt: 'Ao que lhes responderá: Em verdade vos digo que, sempre que o deixaste de fazer a um destes mais pequeninos, deixastes de o fazer a mim.' },
      { v: 46, en: 'These will go away into eternal punishment, but the righteous into eternal life.”', pt: 'E irão eles para o castigo eterno, mas os justos para a vida eterna.' },
    ],
    26: [
      { v: 1, en: 'When Jesus had finished all these words, he said to his disciples,', pt: 'E havendo Jesus concluído todas estas palavras, disse aos seus discípulos:' },
      { v: 2, en: '“You know that after two days the Passover is coming, and the Son of Man will be delivered up to be crucified.”', pt: 'Sabeis que daqui a dois dias é a páscoa; e o Filho do homem será entregue para ser crucificado.' },
      { v: 3, en: 'Then the chief priests, the scribes, and the elders of the people were gathered together in the court of the high priest, who was called Caiaphas.', pt: 'Então os principais sacerdotes e os anciãos do povo se reuniram no pátio da casa do sumo sacerdote, o qual se chamava Caifás;' },
      { v: 4, en: 'They took counsel together that they might take Jesus by deceit, and kill him.', pt: 'e deliberaram como prender Jesus a traição, e o matar.' },
      { v: 5, en: 'But they said, “Not during the feast, lest a riot occur among the people.”', pt: 'Mas diziam: Não durante a festa, para que não haja tumulto entre o povo.' },
      { v: 6, en: 'Now when Jesus was in Bethany, in the house of Simon the leper,', pt: 'Estando Jesus em Betânia, em casa de Simão, o leproso,' },
      { v: 7, en: 'a woman came to him having an alabaster jar of very expensive ointment, and she poured it on his head as he sat at the table.', pt: 'aproximou-se dele uma mulher que trazia um vaso de alabastro cheio de bálsamo precioso, e lho derramou sobre a cabeça, estando ele reclinado à mesa.' },
      { v: 8, en: 'But when his disciples saw this, they were indignant, saying, “Why this waste?', pt: 'Quando os discípulos viram isso, indignaram-se, e disseram: Para que este disperdício?' },
      { v: 9, en: 'For this ointment might have been sold for much, and given to the poor.”', pt: 'Pois este bálsamo podia ser vendido por muito dinheiro, que se daria aos pobres.' },
      { v: 10, en: 'However, knowing this, Jesus said to them, “Why do you trouble the woman? She has done a good work for me.', pt: 'Jesus, porém, percebendo isso, disse-lhes: Por que molestais esta mulher? pois praticou uma boa ação para comigo.' },
      { v: 11, en: 'For you always have the poor with you; but you don’t always have me.', pt: 'Porquanto os pobres sempre os tendes convosco; a mim, porém, nem sempre me tendes.' },
      { v: 12, en: 'For in pouring this ointment on my body, she did it to prepare me for burial.', pt: 'Ora, derramando ela este bálsamo sobre o meu corpo, fê-lo a fim de preparar-me para a minha sepultura.' },
      { v: 13, en: 'Most certainly I tell you, wherever this Good News is preached in the whole world, what this woman has done will also be spoken of as a memorial of her.”', pt: 'Em verdade vos digo que onde quer que for pregado em todo o mundo este evangelho, também o que ela fez será contado para memória sua.' },
      { v: 14, en: 'Then one of the twelve, who was called Judas Iscariot, went to the chief priests,', pt: 'Então um dos doze, chamado Judas Iscariotes, foi ter com os principais sacerdotes,' },
      { v: 15, en: 'and said, “What are you willing to give me, that I should deliver him to you?” They weighed out for him thirty pieces of silver.', pt: 'e disse: Que me quereis dar, e eu vo-lo entregarei? E eles lhe pesaram trinta moedas de prata.' },
      { v: 16, en: 'From that time he sought opportunity to betray him.', pt: 'E desde então buscava ele oportunidade para o entregar.' },
      { v: 17, en: 'Now on the first day of unleavened bread, the disciples came to Jesus, saying to him, “Where do you want us to prepare for you to eat the Passover?”', pt: 'Ora, no primeiro dia dos pães ázimos, vieram os discípulos a Jesus, e perguntaram: Onde queres que façamos os preparativos para comeres a páscoa?' },
      { v: 18, en: 'He said, “Go into the city to a certain person, and tell him, ‘The Teacher says, “My time is at hand. I will keep the Passover at your house with my disciples.”’”', pt: 'Respondeu ele: Ide à cidade a um certo homem, e dizei-lhe: O Mestre diz: O meu tempo está próximo; em tua casa celebrarei a páscoa com os meus discípulos.' },
      { v: 19, en: 'The disciples did as Jesus commanded them, and they prepared the Passover.', pt: 'E os discípulos fizeram como Jesus lhes ordenara, e prepararam a páscoa.' },
      { v: 20, en: 'Now when evening had come, he was reclining at the table with the twelve disciples.', pt: 'Ao anoitecer reclinou-se à mesa com os doze discípulos;' },
      { v: 21, en: 'As they were eating, he said, “Most certainly I tell you that one of you will betray me.”', pt: 'e, enquanto comiam, disse: Em verdade vos digo que um de vós me trairá.' },
      { v: 22, en: 'They were exceedingly sorrowful, and each began to ask him, “It isn’t me, is it, Lord?”', pt: 'E eles, profundamente contristados, começaram cada um a perguntar-lhe: Porventura sou eu, Senhor?' },
      { v: 23, en: 'He answered, “He who dipped his hand with me in the dish, the same will betray me.', pt: 'Respondeu ele: O que mete comigo a mão no prato, esse me trairá.' },
      { v: 24, en: 'The Son of Man goes, even as it is written of him, but woe to that man through whom the Son of Man is betrayed! It would be better for that man if he had not been born.”', pt: 'Em verdade o Filho do homem vai, conforme está escrito a seu respeito; mas ai daquele por quem o Filho do homem é traido! bom seria para esse homem se não houvera nascido.' },
      { v: 25, en: 'Judas, who betrayed him, answered, “It isn’t me, is it, Rabbi?” He said to him, “You said it.”', pt: 'Também Judas, que o traía, perguntou: Porventura sou eu, Rabí? Respondeu-lhe Jesus: Tu o disseste.' },
      { v: 26, en: 'As they were eating, Jesus took bread, gave thanks for it, and broke it. He gave to the disciples, and said, “Take, eat; this is my body.”', pt: 'Enquanto comiam, Jesus tomou o pão e, abençoando-o, o partiu e o deu aos discípulos, dizendo: Tomai, comei; isto é o meu corpo.' },
      { v: 27, en: 'He took the cup, gave thanks, and gave to them, saying, “All of you drink it,', pt: 'E tomando um cálice, rendeu graças e deu-lho, dizendo: Bebei dele todos;' },
      { v: 28, en: 'for this is my blood of the new covenant, which is poured out for many for the remission of sins.', pt: 'pois isto é o meu sangue, o sangue do pacto, o qual é derramado por muitos para remissão dos pecados.' },
      { v: 29, en: 'But I tell you that I will not drink of this fruit of the vine from now on, until that day when I drink it anew with you in my Father’s Kingdom.”', pt: 'Mas digo-vos que desde agora não mais beberei deste fruto da videira até aquele dia em que convosco o beba novo, no reino de meu Pai.' },
      { v: 30, en: 'When they had sung a hymn, they went out to the Mount of Olives.', pt: 'E tendo cantado um hino, saíram para o Monte das Oliveiras.' },
      { v: 31, en: 'Then Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep of the flock will be scattered.’', pt: 'Então Jesus lhes disse: Todos vós esta noite vos escandalizareis de mim; pois está escrito: Ferirei o pastor, e as ovelhas do rebanho se dispersarão.' },
      { v: 32, en: 'But after I am raised up, I will go before you into Galilee.”', pt: 'Todavia, depois que eu ressurgir, irei adiante de vós para a Galiléia.' },
      { v: 33, en: 'But Peter answered him, “Even if all will be made to stumble because of you, I will never be made to stumble.”', pt: 'Mas Pedro, respondendo, disse-lhe: Ainda que todos se escandalizem de ti, eu nunca me escandalizarei.' },
      { v: 34, en: 'Jesus said to him, “Most certainly I tell you that tonight, before the rooster crows, you will deny me three times.”', pt: 'Disse-lhe Jesus: Em verdade te digo que esta noite, antes que o galo cante três vezes me negarás.' },
      { v: 35, en: 'Peter said to him, “Even if I must die with you, I will not deny you.” All of the disciples also said likewise.', pt: 'Respondeu-lhe Pedro: Ainda que me seja necessário morrer contigo, de modo algum te negarei. E o mesmo disseram todos os discípulos.' },
      { v: 36, en: 'Then Jesus came with them to a place called Gethsemane, and said to his disciples, “Sit here, while I go there and pray.”', pt: 'Então foi Jesus com eles a um lugar chamado Getsêmane, e disse aos discípulos: Sentai-vos aqui, enquanto eu vou ali orar.' },
      { v: 37, en: 'He took with him Peter and the two sons of Zebedee, and began to be sorrowful and severely troubled.', pt: 'E levando consigo Pedro e os dois filhos de Zebedeu, começou a entristecer-se e a angustiar-se.' },
      { v: 38, en: 'Then he said to them, “My soul is exceedingly sorrowful, even to death. Stay here, and watch with me.”', pt: 'Então lhes disse: A minha alma está triste até a morte; ficai aqui e vigiai comigo.' },
      { v: 39, en: 'He went forward a little, fell on his face, and prayed, saying, “My Father, if it is possible, let this cup pass away from me; nevertheless, not what I desire, but what you desire.”', pt: 'E adiantando-se um pouco, prostrou-se com o rosto em terra e orou, dizendo: Meu Pai, se é possível, passa de mim este cálice; todavia, não seja como eu quero, mas como tu queres.' },
      { v: 40, en: 'He came to the disciples, and found them sleeping, and said to Peter, “What, couldn’t you watch with me for one hour?', pt: 'Voltando para os discípulos, achou-os dormindo; e disse a Pedro: Assim nem uma hora pudestes vigiar comigo?' },
      { v: 41, en: 'Watch and pray, that you don’t enter into temptation. The spirit indeed is willing, but the flesh is weak.”', pt: 'Vigiai e orai, para que não entreis em tentação; o espírito, na verdade, está pronto, mas a carne é fraca.' },
      { v: 42, en: 'Again, a second time he went away, and prayed, saying, “My Father, if this cup can’t pass away from me unless I drink it, your desire be done.”', pt: 'Retirando-se mais uma vez, orou, dizendo: Pai meu, se este cálice não pode passar sem que eu o beba, faça-se a tua vontade.' },
      { v: 43, en: 'He came again and found them sleeping, for their eyes were heavy.', pt: 'E, voltando outra vez, achou-os dormindo, porque seus olhos estavam carregados.' },
      { v: 44, en: 'He left them again, went away, and prayed a third time, saying the same words.', pt: 'Deixando-os novamente, foi orar terceira vez, repetindo as mesmas palavras.' },
      { v: 45, en: 'Then he came to his disciples, and said to them, “Sleep on now, and take your rest. Behold, the hour is at hand, and the Son of Man is betrayed into the hands of sinners.', pt: 'Então voltou para os discípulos e disse-lhes: Dormi agora e descansai. Eis que é chegada a hora, e o Filho do homem está sendo entregue nas mãos dos pecadores.' },
      { v: 46, en: 'Arise, let’s be going. Behold, he who betrays me is at hand.”', pt: 'Levantai-vos, vamo-nos; eis que é chegado aquele que me trai.' },
      { v: 47, en: 'While he was still speaking, behold, Judas, one of the twelve, came, and with him a great multitude with swords and clubs, from the chief priests and elders of the people.', pt: 'E estando ele ainda a falar, eis que veio Judas, um dos doze, e com ele grande multidão com espadas e varapaus, vinda da parte dos principais sacerdotes e dos anciãos do povo.' },
      { v: 48, en: 'Now he who betrayed him gave them a sign, saying, “Whoever I kiss, he is the one. Seize him.”', pt: 'Ora, o que o traía lhes havia dado um sinal, dizendo: Aquele que eu beijar, esse é: prendei-o.' },
      { v: 49, en: 'Immediately he came to Jesus, and said, “Hail, Rabbi!” and kissed him.', pt: 'E logo, aproximando-se de Jesus disse: Salve, Rabi. E o beijou.' },
      { v: 50, en: 'Jesus said to him, “Friend, why are you here?” Then they came and laid hands on Jesus, and took him.', pt: 'Jesus, porém, lhe disse: Amigo, a que vieste? Nisto, aproximando-se eles, lançaram mão de Jesus, e o prenderam.' },
      { v: 51, en: 'Behold, one of those who were with Jesus stretched out his hand, and drew his sword, and struck the servant of the high priest, and struck off his ear.', pt: 'E eis que um dos que estavam com Jesus, estendendo a mão, puxou da espada e, ferindo o servo do sumo sacerdote, cortou-lhe uma orelha.' },
      { v: 52, en: 'Then Jesus said to him, “Put your sword back into its place, for all those who take the sword will die by the sword.', pt: 'Então Jesus lhe disse: Mete a tua espada no seu lugar; porque todos os que lançarem mão da espada, à espada morrerão.' },
      { v: 53, en: 'Or do you think that I couldn’t ask my Father, and he would even now send me more than twelve legions of angels?', pt: 'Ou pensas tu que eu não poderia rogar a meu Pai, e que ele não me mandaria agora mesmo mais de doze legiões de anjos?' },
      { v: 54, en: 'How then would the Scriptures be fulfilled that it must be so?”', pt: 'Como, pois, se cumpririam as Escrituras, que dizem que assim convém que aconteça?' },
      { v: 55, en: 'In that hour Jesus said to the multitudes, “Have you come out as against a robber with swords and clubs to seize me? I sat daily in the temple teaching, and you didn’t arrest me.', pt: 'Disse Jesus à multidão naquela hora: Saístes com espadas e varapaus para me prender, como a um salteador? Todos os dias estava eu sentado no templo ensinando, e não me prendestes.' },
      { v: 56, en: 'But all this has happened, that the Scriptures of the prophets might be fulfilled.” Then all the disciples left him, and fled.', pt: 'Mas tudo isso aconteceu para que se cumprissem as Escrituras dos profetas. Então todos os discípulos, deixando-o fugiram.' },
      { v: 57, en: 'Those who had taken Jesus led him away to Caiaphas the high priest, where the scribes and the elders were gathered together.', pt: 'Aqueles que prenderam a Jesus levaram-no à presença do sumo sacerdote Caifás, onde os escribas e os anciãos estavam reunidos.' },
      { v: 58, en: 'But Peter followed him from a distance, to the court of the high priest, and entered in and sat with the officers, to see the end.', pt: 'E Pedro o seguia de longe até o pátio do sumo sacerdote; e entrando, sentou-se entre os guardas, para ver o fim.' },
      { v: 59, en: 'Now the chief priests, the elders, and the whole council sought false testimony against Jesus, that they might put him to death;', pt: 'Ora, os principais sacerdotes e todo o sinédrio buscavam falso testemunho contra Jesus, para poderem entregá-lo à morte;' },
      { v: 60, en: 'and they found none. Even though many false witnesses came forward, they found none. But at last two false witnesses came forward,', pt: 'e não achavam, apesar de se apresentarem muitas testemunhas falsas. Mas por fim compareceram duas,' },
      { v: 61, en: 'and said, “This man said, ‘I am able to destroy the temple of God, and to build it in three days.’”', pt: 'e disseram: Este disse: Posso destruir o santuário de Deus, e reedificá-lo em três dias.' },
      { v: 62, en: 'The high priest stood up, and said to him, “Have you no answer? What is this that these testify against you?”', pt: 'Levantou-se então o sumo sacerdote e perguntou-lhe: Nada respondes? Que é que estes depõem contra ti?' },
      { v: 63, en: 'But Jesus held his peace. The high priest answered him, “I adjure you by the living God, that you tell us whether you are the Christ, the Son of God.”', pt: 'Jesus, porém, guardava silêncio. E o sumo sacerdote disse- lhe: Conjuro-te pelo Deus vivo que nos digas se tu és o Cristo, o Filho do Deus.' },
      { v: 64, en: 'Jesus said to him, “You have said it. Nevertheless, I tell you, after this you will see the Son of Man sitting at the right hand of Power, and coming on the clouds of the sky.”', pt: 'Repondeu-lhe Jesus: É como disseste; contudo vos digo que vereis em breve o Filho do homem assentado à direita do Poder, e vindo sobre as nuvens do céu.' },
      { v: 65, en: 'Then the high priest tore his clothing, saying, “He has spoken blasphemy! Why do we need any more witnesses? Behold, now you have heard his blasphemy.', pt: 'Então o sumo sacerdote rasgou as suas vestes, dizendo: Blasfemou; para que precisamos ainda de testemunhas? Eis que agora acabais de ouvir a sua blasfêmia.' },
      { v: 66, en: 'What do you think?” They answered, “He is worthy of death!”', pt: 'Que vos parece? Responderam eles: É réu de morte.' },
      { v: 67, en: 'Then they spat in his face and beat him with their fists, and some slapped him,', pt: 'Então uns lhe cuspiram no rosto e lhe deram socos;' },
      { v: 68, en: 'saying, “Prophesy to us, you Christ! Who hit you?”', pt: 'e outros o esbofetearam, dizendo: Profetiza-nos, ó Cristo, quem foi que te bateu?' },
      { v: 69, en: 'Now Peter was sitting outside in the court, and a maid came to him, saying, “You were also with Jesus, the Galilean!”', pt: 'Ora, Pedro estava sentado fora, no pátio; e aproximou-se dele uma criada, que disse: Tu também estavas com Jesus, o galileu.' },
      { v: 70, en: 'But he denied it before them all, saying, “I don’t know what you are talking about.”', pt: 'Mas ele negou diante de todos, dizendo: Não sei o que dizes.' },
      { v: 71, en: 'When he had gone out onto the porch, someone else saw him, and said to those who were there, “This man also was with Jesus of Nazareth.”', pt: 'E saindo ele para o vestíbulo, outra criada o viu, e disse aos que ali estavam: Este também estava com Jesus, o nazareno.' },
      { v: 72, en: 'Again he denied it with an oath, “I don’t know the man.”', pt: 'E ele negou outra vez, e com juramento: Não conheço tal homem.' },
      { v: 73, en: 'After a little while those who stood by came and said to Peter, “Surely you are also one of them, for your speech makes you known.”', pt: 'E daí a pouco, aproximando-se os que ali estavam, disseram a Pedro: Certamente tu também és um deles pois a tua fala te denuncia.' },
      { v: 74, en: 'Then he began to curse and to swear, “I don’t know the man!” Immediately the rooster crowed.', pt: 'Então começou ele a praguejar e a jurar, dizendo: Não conheço esse homem. E imediatamente o galo cantou.' },
      { v: 75, en: 'Peter remembered the word which Jesus had said to him, “Before the rooster crows, you will deny me three times.” He went out and wept bitterly.', pt: 'E Pedro lembrou-se do que dissera Jesus: Antes que o galo cante, três vezes me negarás. E, saindo dali, chorou amargamente.' },
    ],
    27: [
      { v: 1, en: 'Now when morning had come, all the chief priests and the elders of the people took counsel against Jesus to put him to death:', pt: 'Ora, chegada a manhã, todos os principais sacerdotes e os anciãos do povo entraram em conselho contra Jesus, para o matarem;' },
      { v: 2, en: 'and they bound him, and led him away, and delivered him up to Pontius Pilate, the governor.', pt: 'e, maniatando-o, levaram-no e o entregaram a Pilatos, o governador.' },
      { v: 3, en: 'Then Judas, who betrayed him, when he saw that Jesus was condemned, felt remorse, and brought back the thirty pieces of silver to the chief priests and elders,', pt: 'Então Judas, aquele que o traíra, vendo que Jesus fora condenado, devolveu, compungido, as trinta moedas de prata aos anciãos, dizendo:' },
      { v: 4, en: 'saying, “I have sinned in that I betrayed innocent blood.” But they said, “What is that to us? You see to it.”', pt: 'Pequei, traindo o sangue inocente. Responderam eles: Que nos importa? Seja isto lá contigo.' },
      { v: 5, en: 'He threw down the pieces of silver in the sanctuary, and departed. He went away and hanged himself.', pt: 'E tendo ele atirado para dentro do santuário as moedas de prata, retirou-se, e foi enforcar-se.' },
      { v: 6, en: 'The chief priests took the pieces of silver, and said, “It’s not lawful to put them into the treasury, since it is the price of blood.”', pt: 'Os principais sacerdotes, pois, tomaram as moedas de prata, e disseram: Não é lícito metê-las no cofre das ofertas, porque é preço de sangue.' },
      { v: 7, en: 'They took counsel, and bought the potter’s field with them, to bury strangers in.', pt: 'E, tendo deliberado em conselho, compraram com elas o campo do oleiro, para servir de cemitério para os estrangeiros.' },
      { v: 8, en: 'Therefore that field was called “The Field of Blood” to this day.', pt: 'Por isso tem sido chamado aquele campo, até o dia de hoje, Campo de Sangue.' },
      { v: 9, en: 'Then that which was spoken through Jeremiah the prophet was fulfilled, saying, “They took the thirty pieces of silver, the price of him upon whom a price had been set, whom some of the children of Israel priced,', pt: 'Cumpriu-se, então, o que foi dito pelo profeta Jeremias: Tomaram as trinta moedas de prata, preço do que foi avaliado, a quem certos filhos de Israel avaliaram,' },
      { v: 10, en: 'and they gave them for the potter’s field, as the Lord commanded me.”', pt: 'e deram-nas pelo campo do oleiro, assim como me ordenou o Senhor.' },
      { v: 11, en: 'Now Jesus stood before the governor: and the governor asked him, saying, “Are you the King of the Jews?” Jesus said to him, “So you say.”', pt: 'Jesus, pois, ficou em pé diante do governador; e este lhe perguntou: És tu o rei dos judeus? Respondeu-lhe Jesus: É como dizes.' },
      { v: 12, en: 'When he was accused by the chief priests and elders, he answered nothing.', pt: 'Mas ao ser acusado pelos principais sacerdotes e pelos anciãos, nada respondeu.' },
      { v: 13, en: 'Then Pilate said to him, “Don’t you hear how many things they testify against you?”', pt: 'Perguntou-lhe então Pilatos: Não ouves quantas coisas testificam contra ti?' },
      { v: 14, en: 'He gave him no answer, not even one word, so that the governor marveled greatly.', pt: 'E Jesus não lhe respondeu a uma pergunta sequer; de modo que o governador muito se admirava.' },
      { v: 15, en: 'Now at the feast the governor was accustomed to release to the multitude one prisoner, whom they desired.', pt: 'Ora, por ocasião da festa costumava o governador soltar um preso, escolhendo o povo aquele que quisesse.' },
      { v: 16, en: 'They had then a notable prisoner, called Barabbas.', pt: 'Nesse tempo tinham um preso notório, chamado Barrabás.' },
      { v: 17, en: 'When therefore they were gathered together, Pilate said to them, “Whom do you want me to release to you? Barabbas, or Jesus, who is called Christ?”', pt: 'Portanto, estando o povo reunido, perguntou-lhe Pilatos: Qual quereis que vos solte? Barrabás, ou Jesus, chamado o Cristo?' },
      { v: 18, en: 'For he knew that because of envy they had delivered him up.', pt: 'Pois sabia que por inveja o haviam entregado.' },
      { v: 19, en: 'While he was sitting on the judgment seat, his wife sent to him, saying, “Have nothing to do with that righteous man, for I have suffered many things today in a dream because of him.”', pt: 'E estando ele assentado no tribunal, sua mulher mandou dizer-lhe: Não te envolvas na questão desse justo, porque muito sofri hoje em sonho por causa dele.' },
      { v: 20, en: 'Now the chief priests and the elders persuaded the multitudes to ask for Barabbas, and destroy Jesus.', pt: 'Mas os principais sacerdotes e os anciãos persuadiram as multidões a que pedissem Barrabás e fizessem morrer Jesus.' },
      { v: 21, en: 'But the governor answered them, “Which of the two do you want me to release to you?” They said, “Barabbas!”', pt: 'O governador, pois, perguntou-lhes: Qual dos dois quereis que eu vos solte? E disseram: Barrabás.' },
      { v: 22, en: 'Pilate said to them, “What then shall I do to Jesus, who is called Christ?” They all said to him, “Let him be crucified!”', pt: 'Tornou-lhes Pilatos: Que farei então de Jesus, que se chama Cristo? Disseram todos: Seja crucificado.' },
      { v: 23, en: 'But the governor said, “Why? What evil has he done?” But they cried out exceedingly, saying, “Let him be crucified!”', pt: 'Pilatos, porém, disse: Pois que mal fez ele? Mas eles clamavam ainda mais: Seja crucificado.' },
      { v: 24, en: 'So when Pilate saw that nothing was being gained, but rather that a disturbance was starting, he took water, and washed his hands before the multitude, saying, “I am innocent of the blood of this righteous person. You see to it.”', pt: 'Ao ver Pilatos que nada conseguia, mas pelo contrário que o tumulto aumentava, mandando trazer água, lavou as mãos diante da multidão, dizendo: Sou inocente do sangue deste homem; seja isso lá convosco.' },
      { v: 25, en: 'All the people answered, “May his blood be on us, and on our children!”', pt: 'E todo o povo respondeu: O seu sangue caia sobre nós e sobre nossos filhos.' },
      { v: 26, en: 'Then he released to them Barabbas, but Jesus he flogged and delivered to be crucified.', pt: 'Então lhes soltou Barrabás; mas a Jesus mandou açoitar, e o entregou para ser crucificado.' },
      { v: 27, en: 'Then the governor’s soldiers took Jesus into the Praetorium, and gathered the whole garrison together against him.', pt: 'Nisso os soldados do governador levaram Jesus ao pretório, e reuniram em torno dele toda a coorte.' },
      { v: 28, en: 'They stripped him, and put a scarlet robe on him.', pt: 'E, despindo-o, vestiram-lhe um manto escarlate;' },
      { v: 29, en: 'They braided a crown of thorns and put it on his head, and a reed in his right hand; and they kneeled down before him, and mocked him, saying, “Hail, King of the Jews!”', pt: 'e tecendo uma coroa de espinhos, puseram-lha na cabeça, e na mão direita uma cana, e ajoelhando-se diante dele, o escarneciam, dizendo: Salve, rei dos judeus!' },
      { v: 30, en: 'They spat on him, and took the reed and struck him on the head.', pt: 'E, cuspindo nele, tiraram-lhe a cana, e davam-lhe com ela na cabeça.' },
      { v: 31, en: 'When they had mocked him, they took the robe off him, and put his clothes on him, and led him away to crucify him.', pt: 'Depois de o terem escarnecido, despiram-lhe o manto, puseram-lhe as suas vestes, e levaram-no para ser crucificado.' },
      { v: 32, en: 'As they came out, they found a man of Cyrene, Simon by name, and they compelled him to go with them, that he might carry his cross.', pt: 'Ao saírem, encontraram um homem cireneu, chamado Simão, a quem obrigaram a levar a cruz de Jesus.' },
      { v: 33, en: 'When they came to a place called “Golgotha”, that is to say, “The place of a skull,”', pt: 'Quando chegaram ao lugar chamado Gólgota, que quer dizer, lugar da Caveira,' },
      { v: 34, en: 'they gave him sour wine to drink mixed with gall. When he had tasted it, he would not drink.', pt: 'deram-lhe a beber vinho misturado com fel; mas ele, provando-o, não quis beber.' },
      { v: 35, en: 'When they had crucified him, they divided his clothing among them, casting lots,', pt: 'Então, depois de o crucificarem, repartiram as vestes dele, lançando sortes, [para que se cumprisse o que foi dito pelo profeta: Repartiram entre si as minhas vestes, e sobre a minha túnica deitaram sortes.]' },
      { v: 36, en: 'and they sat and watched him there.', pt: 'E, sentados, ali o guardavam.' },
      { v: 37, en: 'They set up over his head the accusation against him written, “THIS IS JESUS, THE KING OF THE JEWS.”', pt: 'Puseram-lhe por cima da cabeça a sua acusação escrita: ESTE É JESUS, O REI DOS JUDEUS.' },
      { v: 38, en: 'Then there were two robbers crucified with him, one on his right hand and one on the left.', pt: 'Então foram crucificados com ele dois salteadores, um à direita, e outro à esquerda.' },
      { v: 39, en: 'Those who passed by blasphemed him, wagging their heads,', pt: 'E os que iam passando blasfemavam dele, meneando a cabeça' },
      { v: 40, en: 'and saying, “You who destroy the temple, and build it in three days, save yourself! If you are the Son of God, come down from the cross!”', pt: 'e dizendo: Tu, que destróis o santuário e em três dias o reedificas, salva-te a ti mesmo; se és Filho de Deus, desce da cruz.' },
      { v: 41, en: 'Likewise the chief priests also mocking, with the scribes, the Pharisees, and the elders, said,', pt: 'De igual modo também os principais sacerdotes, com os escribas e anciãos, escarnecendo, diziam:' },
      { v: 42, en: '“He saved others, but he can’t save himself. If he is the King of Israel, let him come down from the cross now, and we will believe in him.', pt: 'A outros salvou; a si mesmo não pode salvar. Rei de Israel é ele; desça agora da cruz, e creremos nele;' },
      { v: 43, en: 'He trusts in God. Let God deliver him now, if he wants him; for he said, ‘I am the Son of God.’”', pt: 'confiou em Deus, livre-o ele agora, se lhe quer bem; porque disse: Sou Filho de Deus.' },
      { v: 44, en: 'The robbers also who were crucified with him cast on him the same reproach.', pt: 'O mesmo lhe lançaram em rosto também os salteadores que com ele foram crucificados.' },
      { v: 45, en: 'Now from the sixth hour there was darkness over all the land until the ninth hour.', pt: 'E, desde a hora sexta, houve trevas sobre toda a terra, até a hora nona.' },
      { v: 46, en: 'About the ninth hour Jesus cried with a loud voice, saying, “Eli, Eli, lima sabachthani?” That is, “My God, my God, why have you forsaken me?”', pt: 'Cerca da hora nona, bradou Jesus em alta voz, dizendo: Eli, Eli, lamá sabactani; isto é, Deus meu, Deus meu, por que me desamparaste?' },
      { v: 47, en: 'Some of them who stood there, when they heard it, said, “This man is calling Elijah.”', pt: 'Alguns dos que ali estavam, ouvindo isso, diziam: Ele chama por Elias.' },
      { v: 48, en: 'Immediately one of them ran, and took a sponge, and filled it with vinegar, and put it on a reed, and gave him a drink.', pt: 'E logo correu um deles, tomou uma esponja, ensopou-a em vinagre e, pondo-a numa cana, dava-lhe de beber.' },
      { v: 49, en: 'The rest said, “Let him be. Let’s see whether Elijah comes to save him.”', pt: 'Os outros, porém, disseram: Deixa, vejamos se Elias vem salvá-lo.' },
      { v: 50, en: 'Jesus cried again with a loud voice, and yielded up his spirit.', pt: 'De novo bradou Jesus com grande voz, e entregou o espírito.' },
      { v: 51, en: 'Behold, the veil of the temple was torn in two from the top to the bottom. The earth quaked and the rocks were split.', pt: 'E eis que o véu do santuário se rasgou em dois, de alto a baixo; a terra tremeu, as pedras se fenderam,' },
      { v: 52, en: 'The tombs were opened, and many bodies of the saints who had fallen asleep were raised;', pt: 'os sepulcros se abriram, e muitos corpos de santos que tinham dormido foram ressuscitados;' },
      { v: 53, en: 'and coming out of the tombs after his resurrection, they entered into the holy city and appeared to many.', pt: 'e, saindo dos sepulcros, depois da ressurreição dele, entraram na cidade santa, e apareceram a muitos.' },
      { v: 54, en: 'Now the centurion, and those who were with him watching Jesus, when they saw the earthquake, and the things that were done, feared exceedingly, saying, “Truly this was the Son of God.”', pt: 'ora, o centurião e os que com ele guardavam Jesus, vendo o terremoto e as coisas que aconteciam, tiveram grande temor, e disseram: Verdadeiramente este era filho de Deus.' },
      { v: 55, en: 'Many women were there watching from afar, who had followed Jesus from Galilee, serving him.', pt: 'Também estavam ali, olhando de longe, muitas mulheres que tinham seguido Jesus desde a Galiléia para o ouvir;' },
      { v: 56, en: 'Among them were Mary Magdalene, Mary the mother of James and Joses, and the mother of the sons of Zebedee.', pt: 'entre as quais se achavam Maria Madalena, Maria, mãe de Tiago e de José, e a mãe dos filhos de Zebedeu.' },
      { v: 57, en: 'When evening had come, a rich man from Arimathaea, named Joseph, who himself was also Jesus’ disciple came.', pt: 'Ao cair da tarde, veio um homem rico de Arimatéia, chamado José, que também era discípulo de Jesus.' },
      { v: 58, en: 'This man went to Pilate, and asked for Jesus’ body. Then Pilate commanded the body to be given up.', pt: 'Esse foi a Pilatos e pediu o corpo de Jesus. Então Pilatos mandou que lhe fosse entregue.' },
      { v: 59, en: 'Joseph took the body, and wrapped it in a clean linen cloth,', pt: 'E José, tomando o corpo, envolveu-o num pano limpo, de linho,' },
      { v: 60, en: 'and laid it in his own new tomb, which he had cut out in the rock, and he rolled a great stone against the door of the tomb, and departed.', pt: 'e depositou-o no seu sepulcro novo, que havia aberto em rocha; e, rodando uma grande pedra para a porta do sepulcro, retirou- se.' },
      { v: 61, en: 'Mary Magdalene was there, and the other Mary, sitting opposite the tomb.', pt: 'Mas achavam-se ali Maria Madalena e a outra Maria, sentadas defronte do sepulcro.' },
      { v: 62, en: 'Now on the next day, which was the day after the Preparation Day, the chief priests and the Pharisees were gathered together to Pilate,', pt: 'No dia seguinte, isto é, o dia depois da preparação, reuniram-se os principais sacerdotes e os fariseus perante Pilatos,' },
      { v: 63, en: 'saying, “Sir, we remember what that deceiver said while he was still alive: ‘After three days I will rise again.’', pt: 'e disseram: Senhor, lembramo-nos de que aquele embusteiro, quando ainda vivo, afirmou: Depois de três dias ressurgirei.' },
      { v: 64, en: 'Command therefore that the tomb be made secure until the third day, lest perhaps his disciples come at night and steal him away, and tell the people, ‘He is risen from the dead;’ and the last deception will be worse than the first.”', pt: 'Manda, pois, que o sepulcro seja guardado com segurança até o terceiro dia; para não suceder que, vindo os discípulos, o furtem e digam ao povo: Ressurgiu dos mortos; e assim o último embuste será pior do que o primeiro.' },
      { v: 65, en: 'Pilate said to them, “You have a guard. Go, make it as secure as you can.”', pt: 'Disse-lhes Pilatos: Tendes uma guarda; ide, tornai-o seguro, como entendeis.' },
      { v: 66, en: 'So they went with the guard and made the tomb secure, sealing the stone.', pt: 'Foram, pois, e tornaram seguro o sepulcro, selando a pedra, e deixando ali a guarda.' },
    ],
    28: [
      { v: 1, en: 'Now after the Sabbath, as it began to dawn on the first day of the week, Mary Magdalene and the other Mary came to see the tomb.', pt: 'No fim do sábado, quando já despontava o primeiro dia da semana, Maria Madalena e a outra Maria foram ver o sepulcro.' },
      { v: 2, en: 'Behold, there was a great earthquake, for an angel of the Lord descended from the sky, and came and rolled away the stone from the door, and sat on it.', pt: 'E eis que houvera um grande terremoto; pois um anjo do Senhor descera do céu e, chegando-se, removera a pedra e estava sentado sobre ela.' },
      { v: 3, en: 'His appearance was like lightning, and his clothing white as snow.', pt: 'o seu aspecto era como um relâmpago, e as suas vestes brancas como a neve.' },
      { v: 4, en: 'For fear of him, the guards shook, and became like dead men.', pt: 'E de medo dele tremeram os guardas, e ficaram como mortos.' },
      { v: 5, en: 'The angel answered the women, “Don’t be afraid, for I know that you seek Jesus, who has been crucified.', pt: 'Mas o anjo disse às mulheres: Não temais vós; pois eu sei que buscais a Jesus, que foi crucificado.' },
      { v: 6, en: 'He is not here, for he has risen, just like he said. Come, see the place where the Lord was lying.', pt: 'Não está aqui, porque ressurgiu, como ele disse. Vinde, vede o lugar onde jazia;' },
      { v: 7, en: 'Go quickly and tell his disciples, ‘He has risen from the dead, and behold, he goes before you into Galilee; there you will see him.’ Behold, I have told you.”', pt: 'e ide depressa, e dizei aos seus discípulos que ressurgiu dos mortos; e eis que vai adiante de vós para a Galiléia; ali o vereis. Eis que vo-lo tenho dito.' },
      { v: 8, en: 'They departed quickly from the tomb with fear and great joy, and ran to bring his disciples word.', pt: 'E, partindo elas pressurosamente do sepulcro, com temor e grande alegria, correram a anunciá-lo aos discípulos.' },
      { v: 9, en: 'As they went to tell his disciples, behold, Jesus met them, saying, “Rejoice!” They came and took hold of his feet, and worshiped him.', pt: 'E eis que Jesus lhes veio ao encontro, dizendo: Salve. E elas, aproximando-se, abraçaram-lhe os pés, e o adoraram.' },
      { v: 10, en: 'Then Jesus said to them, “Don’t be afraid. Go tell my brothers that they should go into Galilee, and there they will see me.”', pt: 'Então lhes disse Jesus: Não temais; ide dizer a meus irmãos que vão para a Galiléia; ali me verão.' },
      { v: 11, en: 'Now while they were going, behold, some of the guards came into the city, and told the chief priests all the things that had happened.', pt: 'Ora, enquanto elas iam, eis que alguns da guarda foram à cidade, e contaram aos principais sacerdotes tudo quanto havia acontecido.' },
      { v: 12, en: 'When they were assembled with the elders, and had taken counsel, they gave a large amount of silver to the soldiers,', pt: 'E congregados eles com os anciãos e tendo consultado entre si, deram muito dinheiro aos soldados,' },
      { v: 13, en: 'saying, “Say that his disciples came by night, and stole him away while we slept.', pt: 'e ordenaram-lhes que dissessem: Vieram de noite os seus discípulos e, estando nós dormindo, furtaram-no.' },
      { v: 14, en: 'If this comes to the governor’s ears, we will persuade him and make you free of worry.”', pt: 'E, se isto chegar aos ouvidos do governador, nós o persuadiremos, e vos livraremos de cuidado.' },
      { v: 15, en: 'So they took the money and did as they were told. This saying was spread abroad among the Jews, and continues until today.', pt: 'Então eles, tendo recebido o dinheiro, fizeram como foram instruídos. E essa história tem-se divulgado entre os judeus até o dia de hoje.' },
      { v: 16, en: 'But the eleven disciples went into Galilee, to the mountain where Jesus had sent them.', pt: 'Partiram, pois, os onze discípulos para a Galiléia, para o monte onde Jesus lhes designara.' },
      { v: 17, en: 'When they saw him, they bowed down to him, but some doubted.', pt: 'Quando o viram, o adoraram; mas alguns duvidaram.' },
      { v: 18, en: 'Jesus came to them and spoke to them, saying, “All authority has been given to me in heaven and on earth.', pt: 'E, aproximando-se Jesus, falou-lhes, dizendo: Foi-me dada toda a autoridade no céu e na terra.' },
      { v: 19, en: 'Go and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit,', pt: 'Portanto ide, fazei discípulos de todas as nações, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;' },
      { v: 20, en: 'teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen.', pt: 'ensinando-os a observar todas as coisas que eu vos tenho mandado; e eis que eu estou convosco todos os dias, até a consumação dos séculos.' },
    ],
  },
};

export default book;
